use std::env::{self, var};

fn main() {
  // Don't rerun this on changes other than build.rs, as we only depend on
  // the rustc version.
  println!("cargo:rerun-if-changed=build.rs");

  // Check for `--features=tarpaulin`.
  let tarpaulin = var("CARGO_FEATURE_TARPAULIN").is_ok();

  if tarpaulin {
    use_feature("tarpaulin");
  } else {
    // Always rerun if these env vars change.
    println!("cargo:rerun-if-env-changed=CARGO_TARPAULIN");
    println!("cargo:rerun-if-env-changed=CARGO_CFG_TARPAULIN");

    // Detect tarpaulin by environment variable
    if env::var("CARGO_TARPAULIN").is_ok() || env::var("CARGO_CFG_TARPAULIN").is_ok() {
      use_feature("tarpaulin");
    }
  }

  // Rerun this script if any of our features or configuration flags change,
  // or if the toolchain we used for feature detection changes.
  println!("cargo:rerun-if-env-changed=CARGO_FEATURE_TARPAULIN");
}

fn use_feature(feature: &str) {
  println!("cargo:rustc-cfg={}", feature);
}

use super::{
  Cache, CachedTokenOf, CachedTokenRefOf, Checkpoint, GenericArrayDeque, Lexer,
  MaybeRefCachedTokenOf,
};

macro_rules! blackhole {
  ($ty:ty) => {
    impl<'a, L, Lang: ?Sized> Cache<'a, L, Lang> for $ty
    where
      L: Lexer<'a> + 'a,
    {
      type Options = ();

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn new() -> Self {
        Default::default()
      }

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn with_options(_: Self::Options) -> Self
      where
        Self: Sized,
      {
        Default::default()
      }

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn len(&self) -> usize {
        0
      }

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn remaining(&self) -> usize {
        0
      }

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn rewind(&mut self, _: &Checkpoint<'a, '_, L>) {}

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn push_front(
        &mut self,
        tok: CachedTokenOf<'a, L>,
      ) -> Result<CachedTokenRefOf<'_, 'a, L>, CachedTokenOf<'a, L>> {
        Err(tok)
      }

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn push_back(
        &mut self,
        tok: CachedTokenOf<'a, L>,
      ) -> Result<CachedTokenRefOf<'_, 'a, L>, CachedTokenOf<'a, L>> {
        Err(tok)
      }

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn pop_front(&mut self) -> Option<CachedTokenOf<'a, L>> {
        None
      }

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn pop_back(&mut self) -> Option<CachedTokenOf<'a, L>> {
        None
      }

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn clear(&mut self) {}

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn peek<'p, W>(
        &'p self,
        _: &mut GenericArrayDeque<MaybeRefCachedTokenOf<'p, 'a, L>, W::CAPACITY>,
      ) where
        W: crate::Window,
      {
      }

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn front(&self) -> Option<CachedTokenRefOf<'_, 'a, L>> {
        None
      }

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn back(&self) -> Option<CachedTokenRefOf<'_, 'a, L>> {
        None
      }
    }
  };
}

