use mayber::Maybe;

use crate::lexer::Lexer;

use super::{
  Cache, CachedToken, CachedTokenOf, CachedTokenRefOf, Checkpoint, MaybeRefCachedTokenOf, Span,
};

use generic_arraydeque::{ArrayLength, GenericArrayDeque};

impl<'a, L, Lang: ?Sized, N> Cache<'a, L, Lang>
  for GenericArrayDeque<CachedToken<L::Token, L::State, L::Span>, N>
where
  L: Lexer<'a>,
  N: ArrayLength,
{
  type Options = ();

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn new() -> Self {
    Self::new()
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn with_options(_options: ()) -> Self {
    Self::new()
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn len(&self) -> usize {
    self.len()
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn remaining(&self) -> usize {
    self.remaining_capacity()
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn rewind(&mut self, ckp: &Checkpoint<'a, '_, L>)
  where
    Self: Sized,
  {
    if self.is_empty() {
      return;
    }

    let cursor = ckp.cursor();
    // if the rewind position is before the start of the cache, clear the cache
    if let Some(span) = self.front().map(|tok| tok.token().span()) {
      if cursor.as_inner() < span.start_ref() {
        self.clear();
        return;
      }

      // If the rewind position is exactly at the start of the cache, do nothing
      if cursor.as_inner() == span.start_ref() {
        return;
      }
    }

    // if the rewind position is after the end of the cache, clear the cache
    if let Some(span) = self.back().map(|tok| tok.token().span()) {
      if cursor.as_inner() >= span.end_ref() {
        self.clear();
        return;
      }
    }

    let off = cursor.as_inner();
    match self.binary_search_by_key(off, |tok| tok.token().span_ref().start()) {
      Ok(_) => {
        self.retain(|tok| tok.token().span_ref().start().ge(off));
      }
      Err(_) => {
        self.clear();
      }
    }
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn push_front(
    &mut self,
    tok: CachedTokenOf<'a, L>,
  ) -> Result<CachedTokenRefOf<'_, 'a, L>, CachedTokenOf<'a, L>> {
    match self.push_front_mut(tok) {
      Ok(tok) => Ok(tok.as_ref()),
      Err(tok) => Err(tok),
    }
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn push_back(
    &mut self,
    tok: CachedTokenOf<'a, L>,
  ) -> Result<CachedTokenRefOf<'_, 'a, L>, CachedTokenOf<'a, L>> {
    match self.push_back_mut(tok) {
      Ok(tok) => Ok(tok.as_ref()),
      Err(tok) => Err(tok),
    }
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn pop_front(&mut self) -> Option<CachedTokenOf<'a, L>> {
    self.pop_front()
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn pop_back(&mut self) -> Option<CachedTokenOf<'a, L>> {
    self.pop_back()
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn pop_front_if<F>(&mut self, predicate: F) -> Option<CachedTokenOf<'a, L>>
  where
    F: FnOnce(CachedTokenRefOf<'_, 'a, L>) -> bool,
    L: Lexer<'a>,
  {
    self.pop_front_if(|tok| predicate(tok.as_ref()))
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn clear(&mut self) {
    self.clear();
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn peek<'p, W>(
    &'p self,
    buf: &mut GenericArrayDeque<MaybeRefCachedTokenOf<'p, 'a, L>, W::CAPACITY>,
  ) where
    W: crate::Window,
  {
    let fill = buf.remaining_capacity().min(self.len());
    for tok in self.iter().take(fill) {
      buf.push_back(Maybe::Ref(tok.as_ref()));
    }
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn front(&self) -> Option<CachedTokenRefOf<'_, 'a, L>> {
    self.front().map(|tok| tok.as_ref())
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn back(&self) -> Option<CachedTokenRefOf<'_, 'a, L>> {
    self.back().map(|tok| tok.as_ref())
  }
}

#[cfg(test)]
mod tests {
  use super::*;
  use crate::lexer::{DummyLexer, DummyToken};
  use crate::span::{SimpleSpan, Spanned};
  use generic_arraydeque::typenum::U3;

  type DequeCache = GenericArrayDeque<CachedToken<DummyToken, (), SimpleSpan>, U3>;

  fn make_token(start: usize, end: usize) -> CachedToken<DummyToken, (), SimpleSpan> {
    CachedToken::new(Spanned::new(SimpleSpan::new(start, end), DummyToken), ())
  }

  #[test]
  fn deque_cache_new_is_empty() {
    let cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::len(&cache), 0);
    assert!(<DequeCache as Cache<'_, DummyLexer>>::is_empty(&cache));
  }

  #[test]
  fn deque_cache_with_options_is_empty() {
    let cache = <DequeCache as Cache<'_, DummyLexer>>::with_options(());
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::len(&cache), 0);
  }

  #[test]
  fn deque_cache_push_back_and_len() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let tok = make_token(0, 5);
    let result = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, tok);
    assert!(result.is_ok());
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::len(&cache), 1);
    assert!(!<DequeCache as Cache<'_, DummyLexer>>::is_empty(&cache));
  }

  #[test]
  fn deque_cache_push_back_multiple() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 10));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(10, 15));
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::len(&cache), 3);
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::remaining(&cache), 0);
  }

  #[test]
  fn deque_cache_push_back_when_full_returns_err() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 10));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(10, 15));
    let result = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(15, 20));
    assert!(result.is_err());
  }

  #[test]
  fn deque_cache_push_front_and_len() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let tok = make_token(0, 5);
    let result = <DequeCache as Cache<'_, DummyLexer>>::push_front(&mut cache, tok);
    assert!(result.is_ok());
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::len(&cache), 1);
  }

  #[test]
  fn deque_cache_pop_front() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    assert!(<DequeCache as Cache<'_, DummyLexer>>::pop_front(&mut cache).is_none());
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 10));
    let popped = <DequeCache as Cache<'_, DummyLexer>>::pop_front(&mut cache);
    assert!(popped.is_some());
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::len(&cache), 1);
  }

  #[test]
  fn deque_cache_pop_back() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    assert!(<DequeCache as Cache<'_, DummyLexer>>::pop_back(&mut cache).is_none());
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let popped = <DequeCache as Cache<'_, DummyLexer>>::pop_back(&mut cache);
    assert!(popped.is_some());
    assert!(<DequeCache as Cache<'_, DummyLexer>>::is_empty(&cache));
  }

  #[test]
  fn deque_cache_pop_front_if_match() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let popped = <DequeCache as Cache<'_, DummyLexer>>::pop_front_if(&mut cache, |_| true);
    assert!(popped.is_some());
    assert!(<DequeCache as Cache<'_, DummyLexer>>::is_empty(&cache));
  }

  #[test]
  fn deque_cache_pop_front_if_no_match() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let popped = <DequeCache as Cache<'_, DummyLexer>>::pop_front_if(&mut cache, |_| false);
    assert!(popped.is_none());
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::len(&cache), 1);
  }

  #[test]
  fn deque_cache_clear() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 10));
    <DequeCache as Cache<'_, DummyLexer>>::clear(&mut cache);
    assert!(<DequeCache as Cache<'_, DummyLexer>>::is_empty(&cache));
  }

  #[test]
  fn deque_cache_front_and_back() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    assert!(<DequeCache as Cache<'_, DummyLexer>>::front(&cache).is_none());
    assert!(<DequeCache as Cache<'_, DummyLexer>>::back(&cache).is_none());
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 10));
    let front = <DequeCache as Cache<'_, DummyLexer>>::front(&cache);
    let back = <DequeCache as Cache<'_, DummyLexer>>::back(&cache);
    assert!(front.is_some());
    assert!(back.is_some());
  }

  #[test]
  fn deque_cache_remaining() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::remaining(&cache), 3);
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::remaining(&cache), 2);
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 10));
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::remaining(&cache), 1);
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(10, 15));
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::remaining(&cache), 0);
  }

  #[test]
  fn deque_cache_peek_empty() {
    use generic_arraydeque::typenum::U2;
    let cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let mut buf = GenericArrayDeque::new();
    <DequeCache as Cache<'_, DummyLexer>>::peek::<U2>(&cache, &mut buf);
    assert!(buf.is_empty());
  }

  #[test]
  fn deque_cache_peek_with_tokens() {
    use generic_arraydeque::typenum::U2;
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 10));
    let mut buf = GenericArrayDeque::new();
    <DequeCache as Cache<'_, DummyLexer>>::peek::<U2>(&cache, &mut buf);
    assert_eq!(buf.len(), 2);
  }

  #[test]
  fn deque_cache_peek_capped_by_buffer() {
    use generic_arraydeque::typenum::U1;
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 10));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(10, 15));
    let mut buf = GenericArrayDeque::new();
    // Buffer capacity is 1, should only get 1 token even though cache has 3
    <DequeCache as Cache<'_, DummyLexer>>::peek::<U1>(&cache, &mut buf);
    assert_eq!(buf.len(), 1);
  }

  #[test]
  fn deque_cache_push_front_when_full_returns_err() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 10));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(10, 15));
    let result = <DequeCache as Cache<'_, DummyLexer>>::push_front(&mut cache, make_token(15, 20));
    assert!(result.is_err());
  }
}

use ::generic_arraydeque::{GenericArrayDeque, typenum::U1};
use mayber::Maybe;

use crate::{
  Window,
  input::Checkpoint,
  lexer::Lexer,
  span::{Span, Spanned},
};

mod blackhole;
mod generic_arraydeque;
mod option;

/// A peeked buffer of tokens from the lexer.
pub type Peeked<'p, 'inp, L, W> = ::generic_arraydeque::GenericArrayDeque<
  MaybeRefCachedTokenOf<'p, 'inp, L>,
  <W as Window>::CAPACITY,
>;

/// A peeked buffer of tokens from the lexer.
pub type PeekedToken<'p, 'inp, L, W> = ::generic_arraydeque::GenericArrayDeque<
  MaybeRefCachedTokenOf<'p, 'inp, L, <L as Lexer<'inp>>::Token, <L as Lexer<'inp>>::Span>,
  <W as Window>::CAPACITY,
>;

/// The default cache type used by the lexer.
pub type DefaultCache<'a, L> =
  ::generic_arraydeque::GenericArrayDeque<CachedTokenOf<'a, L>, ::generic_arraydeque::typenum::U3>;

/// A trait for caching lookahead tokens in the tokenizer.
///
/// `Cache` provides a buffer for tokens that have been lexed but not yet consumed,
/// enabling efficient lookahead and backtracking operations. The cache acts as a
/// queue (FIFO - First In, First Out) between the lexer and the parser.
///
/// # Purpose
///
/// The cache serves several critical functions:
/// - **Lookahead**: Allows peeking at future tokens without consuming them
/// - **Backtracking**: Supports parser backtracking via checkpoint/rewind operations
/// - **Efficiency**: Avoids re-lexing tokens that have already been processed
/// - **State Management**: Preserves lexer state (extras) alongside each token
///
/// # Design Patterns
///
/// Different implementations support different use cases:
/// - **Fixed-size arrays**: Bounded lookahead with known maximum (e.g., `[CachedToken; 4]`)
/// - **Dynamic buffers**: Unlimited lookahead using `Vec` or `VecDeque`
/// - **BlackHole**: No caching at all, for streaming-only scenarios without backtracking
///
/// Note: Tokens cannot be overwritten until explicitly consumed, as they must remain
/// available for backtracking operations. This means the cache can become full and
/// refuse new tokens if capacity is reached.
///
/// # Cache Operations
///
/// The cache supports standard queue operations:
/// - `push_back`: Add newly lexed tokens to the end (fails if cache is full)
/// - `pop_front`: Remove and return the oldest token
/// - `peek`: View tokens without removing them
/// - `rewind`: Restore to a previous state (for backtracking)
///
/// # Safety
///
/// The `peek` method is marked unsafe because it requires implementations to guarantee
/// that returned slices only contain properly initialized tokens. This is enforced by
/// the trait's contract.
///
/// # Example
///
/// ```ignore
/// // A simple fixed-size cache using a VecDeque-like structure
/// struct BoundedCache<'a, T: Token<'a>> {
///     tokens: VecDeque<CachedToken<'a, T>>,
///     capacity: usize,
/// }
///
/// impl<'a, T: Token<'a>> Cache<'a, T> for BoundedCache<'a, T> {
///     fn len(&self) -> usize {
///         self.tokens.len()
///     }
///
///     fn remaining(&self) -> usize {
///         self.capacity - self.tokens.len()
///     }
///
///     fn push_back(&mut self, tok: CachedToken<'a, T>) -> Result<&CachedToken<'a, T>, CachedToken<'a, T>> {
///         if self.tokens.len() < self.capacity {
///             self.tokens.push_back(tok);
///             Ok(self.tokens.back().unwrap())
///         } else {
///             Err(tok) // Cache full, cannot overwrite!
///         }
///     }
///     // ... other methods
/// }
/// ```
pub trait Cache<'a, L, Lang: ?Sized = ()>: 'a {
  /// The options for creating a new cache.
  type Options;

  /// Creates a new, empty cache.
  fn new() -> Self
  where
    Self: Sized;

  /// Creates a new, empty cache with the specified capacity.
  fn with_options(options: Self::Options) -> Self
  where
    Self: Sized;

  /// Returns `true` if the cache contains no tokens.
  ///
  /// This is a convenience method that checks if `len() == 0`.
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn is_empty(&self) -> bool {
    self.len() == 0
  }

  /// Returns the number of tokens currently stored in the cache.
  ///
  /// This count includes all cached tokens from front to back.
  fn len(&self) -> usize;

  /// Returns the number of additional tokens that can be cached.
  ///
  /// For unbounded caches (like `Vec`), this might return a large number.
  /// For fixed-size caches, this returns the number of free slots.
  /// For black hole caches, this always returns 0.
  fn remaining(&self) -> usize;

  /// Rewinds the cache to a previously saved checkpoint.
  ///
  /// This operation restores the cache state to match the checkpoint, typically
  /// by clearing any tokens that were added after the checkpoint was created.
  /// This is used for parser backtracking.
  fn rewind(&mut self, checkpoint: &Checkpoint<'a, '_, L>)
  where
    Self: Sized,
    L: Lexer<'a>;

  /// Attempts to add a token to the front of the cache.
  ///
  /// If successful, returns `Ok` with a reference to the cached token.
  /// If the cache is full, returns `Err` with the token so the caller can handle it
  /// (e.g., by processing it immediately without caching).
  ///
  /// # Example
  ///
  /// ```ignore
  /// match cache.push_front(token) {
  ///     Ok(cached_ref) => {
  ///         // Token was cached successfully
  ///     }
  ///     Err(token) => {
  ///         // Cache is full, handle token directly
  ///     }
  /// }
  /// ```
  fn push_front(
    &mut self,
    tok: CachedTokenOf<'a, L>,
  ) -> Result<CachedTokenRefOf<'_, 'a, L>, CachedTokenOf<'a, L>>
  where
    L: Lexer<'a>;

  /// Attempts to add a token to the back of the cache.
  ///
  /// If successful, returns `Ok` with a reference to the cached token.
  /// If the cache is full, returns `Err` with the token so the caller can handle it
  /// (e.g., by processing it immediately without caching).
  ///
  /// # Example
  ///
  /// ```ignore
  /// match cache.push_back(token) {
  ///     Ok(cached_ref) => {
  ///         // Token was cached successfully
  ///     }
  ///     Err(token) => {
  ///         // Cache is full, handle token directly
  ///     }
  /// }
  /// ```
  fn push_back(
    &mut self,
    tok: CachedTokenOf<'a, L>,
  ) -> Result<CachedTokenRefOf<'_, 'a, L>, CachedTokenOf<'a, L>>
  where
    L: Lexer<'a>;

  /// Removes and returns the token at the front of the cache.
  ///
  /// Returns `None` if the cache is empty. This is the primary way to consume
  /// cached tokens.
  #[allow(clippy::type_complexity)]
  fn pop_front(&mut self) -> Option<CachedTokenOf<'a, L>>
  where
    L: Lexer<'a>;

  /// Removes and returns the token at the back of the cache.
  ///
  /// Returns `None` if the cache is empty. This is less commonly used than
  /// `pop_front` but can be useful for certain cache management operations.
  #[allow(clippy::type_complexity)]
  fn pop_back(&mut self) -> Option<CachedTokenOf<'a, L>>
  where
    L: Lexer<'a>;

  /// Removes all tokens from the cache.
  ///
  /// After calling this method, `len()` returns 0 and `is_empty()` returns `true`.
  fn clear(&mut self);

  // /// Retains only the tokens in the cache, removing all errors
  // fn retain_tokens<E, Lang>(&mut self, emitter: &mut E) -> Result<(), E::Error>
  // where
  //   E: super::Emitter<'a, L, Lang>,
  //   Lang: ?Sized,
  // {
  //   self.retain(
  //     |t| {
  //       match t.token().data()
  //     },
  //     emitter,
  //   )
  // }

  // /// Retains only the elements specified by the predicate.
  // ///
  // /// In other words, remove all elements e for which f(&e) returns false. This method operates in place, visiting each element exactly once in the original order, and preserves the order of the retained elements.
  // fn retain<E, F, Lang>(&mut self, f: F, emitter: &mut E) -> Result<(), E::Error>
  // where
  //   F: FnMut(CachedTokenRefOf<'_, 'a, L>) -> bool,
  //   E: super::Emitter<'a, L, Lang>,
  //   Lang: ?Sized;

  /// Conditionally removes and returns the front token if it matches a predicate.
  ///
  /// Peeks at the first token in the cache and checks if it satisfies the predicate.
  /// If it does, removes and returns it. Otherwise, returns `None` without modifying
  /// the cache.
  ///
  /// # Example
  ///
  /// ```ignore
  /// // Pop token only if it's a specific type
  /// if let Some(token) = cache.pop_front_if(|t| matches!(t.token().data, Lexed::Token(_))) {
  ///     // Process valid token
  /// }
  /// ```
  #[allow(clippy::type_complexity)]
  fn pop_front_if<F>(&mut self, predicate: F) -> Option<CachedTokenOf<'a, L>>
  where
    F: FnOnce(CachedTokenRefOf<'_, 'a, L>) -> bool,
    L: Lexer<'a>,
  {
    if let Some(peeked) = self.front() {
      if predicate(peeked) {
        return self.pop_front();
      }
    }
    None
  }

  /// Conditionally removes and returns the front token if it matches a validation predicate.
  ///
  /// Peeks at the first token in the cache and checks if it satisfies the predicate.
  /// If it does, removes and returns it. Otherwise, returns `None` without modifying
  /// the cache.
  #[allow(clippy::type_complexity)]
  fn try_pop_front_if<E, F>(&mut self, predicate: F) -> Option<Result<CachedTokenOf<'a, L>, E>>
  where
    F: FnOnce(CachedTokenRefOf<'_, 'a, L>) -> Result<(), E>,
    L: Lexer<'a>,
  {
    if let Some(peeked) = self.front() {
      return match predicate(peeked) {
        Ok(()) => self.pop_front().map(Ok),
        Err(e) => Some(Err(e)),
      };
    }
    None
  }

  /// Peeks at the first cached token without removing it.
  ///
  /// Returns `Some(MaybeRef)` with either a reference to the cached token or
  /// an owned token (if cache implementation requires). Returns `None` if the
  /// cache is empty.
  ///
  /// This is a convenience wrapper around `peek` for looking at just one token.
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn peek_one<'c>(&self) -> Option<MaybeRefCachedTokenOf<'_, 'a, L>>
  where
    'a: 'c,
    L: Lexer<'a>,
  {
    let mut buf = GenericArrayDeque::new();
    self.peek::<U1>(&mut buf);
    buf.pop_front()
  }

  /// Peeks at multiple cached tokens without removing them.
  ///
  /// Fills the provided buffer with references to cached tokens (or owned tokens if
  /// necessary). The returned slice contains only the successfully initialized tokens,
  /// which may be fewer than requested if the cache doesn't have enough tokens.
  ///
  /// # Parameters
  ///
  /// - `buf`: A buffer of uninitialized `MaybeRef` entries to fill with peeked tokens
  ///
  /// # Returns
  ///
  /// A mutable slice containing initialized token references. The slice length indicates
  /// how many tokens were actually available.
  ///
  /// # Safety
  ///
  /// Implementations must guarantee that:
  /// - The returned slice contains only properly initialized tokens
  /// - All cached tokens are filled into the buffer if the buffer is large enough
  /// - The slice bounds are correct and don't include uninitialized memory
  ///
  /// Callers must ensure the returned slice is not used beyond its lifetime.
  #[allow(clippy::mut_from_ref)]
  fn peek<'p, W>(
    &'p self,
    buf: &mut GenericArrayDeque<MaybeRefCachedTokenOf<'p, 'a, L>, W::CAPACITY>,
  ) where
    W: Window,
    L: Lexer<'a>;

  /// Pushes multiple tokens into the cache at once.
  ///
  /// Attempts to cache all tokens from the iterator. If the cache becomes full,
  /// returns an iterator over the tokens that could not be cached.
  ///
  /// # Example
  ///
  /// ```ignore
  /// let overflow = cache.push_many(token_iter);
  /// for token in overflow {
  ///     // Handle tokens that didn't fit in cache
  /// }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn push_many<'p>(
    &'p mut self,
    toks: impl Iterator<Item = CachedTokenOf<'a, L>> + 'p,
  ) -> impl Iterator<Item = CachedTokenOf<'a, L>> + 'p
  where
    L: Lexer<'a>,
  {
    toks.filter_map(move |tok| self.push_back(tok).err())
  }

  /// Returns a reference to the front (oldest) cached token.
  ///
  /// Returns `None` if the cache is empty. This does not remove the token.
  fn front(&self) -> Option<CachedTokenRefOf<'_, 'a, L>>
  where
    L: Lexer<'a>;

  /// Returns a reference to the back (newest) cached token.
  ///
  /// Returns `None` if the cache is empty. This does not remove the token.
  fn back(&self) -> Option<CachedTokenRefOf<'_, 'a, L>>
  where
    L: Lexer<'a>;

  /// Returns the combined span covering all cached tokens.
  ///
  /// If the cache has tokens, returns a span from the start of the first token
  /// to the end of the last token. Returns `None` if the cache is empty.
  ///
  /// This is useful for error reporting or understanding the range of lookahead.
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn span(&self) -> Option<L::Span>
  where
    L: Lexer<'a>,
  {
    match (self.front(), self.back()) {
      (Some(first), Some(last)) => Some(L::Span::new(
        first.token().span_ref().start(),
        last.token().span_ref().end(),
      )),
      _ => None,
    }
  }

  /// Returns the span of the first cached token.
  ///
  /// Returns `None` if the cache is empty. This is often used to determine
  /// where the next consumed token will come from.
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn front_span<'s>(&'s self) -> Option<&'s L::Span>
  where
    'a: 's,
    L: Lexer<'a>,
  {
    self.front().map(move |t| *t.token().span())
  }

  /// Returns the span of the last cached token.
  ///
  /// Returns `None` if the cache is empty. This can be used to determine
  /// where the cache's lookahead ends.
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn back_span<'s>(&'s self) -> Option<&'s L::Span>
  where
    'a: 's,
    L: Lexer<'a>,
  {
    self.back().map(move |t| *t.token().span())
  }
}

/// A cached token with its associated state for a specific lexer.
pub type CachedTokenOf<'a, L, T = <L as Lexer<'a>>::Token, Span = <L as Lexer<'a>>::Span> =
  CachedToken<T, <L as Lexer<'a>>::State, Span>;
/// A cached token with its associated state for a specific lexer.
pub type CachedTokenRefOf<'r, 'a, L, T = <L as Lexer<'a>>::Token, Span = <L as Lexer<'a>>::Span> =
  CachedToken<&'r T, &'r <L as Lexer<'a>>::State, &'r Span>;
/// A maybe reference to a cached token with its associated state for a specific lexer.
pub type MaybeRefCachedTokenOf<
  'r,
  'a,
  L,
  T = <L as Lexer<'a>>::Token,
  Span = <L as Lexer<'a>>::Span,
> = Maybe<CachedTokenRefOf<'r, 'a, L, T, Span>, CachedTokenOf<'a, L, T, Span>>;

/// A cached token with its associated state.
pub struct CachedToken<T, State, Span> {
  pub(crate) token: Spanned<T, Span>,
  pub(crate) state: State,
}

impl<T, State, Span> Clone for CachedToken<T, State, Span>
where
  State: Clone,
  Span: Clone,
  T: Clone,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn clone(&self) -> Self {
    Self {
      token: self.token.clone(),
      state: self.state.clone(),
    }
  }
}

// impl<'a, L: Lexer<'a>> TryFrom<> for CachedToken<T, State, Span> {
//   #[cfg_attr(not(tarpaulin), inline(always))]
//   pub(super) fn try_into_token(
//     self,
//   ) -> Result<CachedToken<T, State, Span>, <T as Token<>>::Error> {
//     match self.token.data {
//       Lexed::Token(token) => Ok(CachedToken::new(Spanned::new(self.token.span, token), self.state)),
//       Lexed::Error(e) => Err(e),
//     }
//   }
// }

impl<T, State, Span> CachedToken<T, State, Span> {
  /// Creates a new cached token.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub(crate) const fn new(token: Spanned<T, Span>, state: State) -> Self {
    Self { token, state }
  }

  /// Returns a reference to the token.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn token(&self) -> Spanned<&T, &Span> {
    self.token.as_ref()
  }

  /// Consumes the cached token and returns the lexed token.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn into_token(self) -> Spanned<T, Span> {
    self.token
  }

  /// Returns a reference to the cached token.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn as_ref(&self) -> CachedToken<&T, &State, &Span> {
    CachedToken {
      token: self.token.as_ref(),
      state: &self.state,
    }
  }

  /// Maps the token to a new type using the provided function.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn map_token<U, F>(self, f: F) -> CachedToken<U, State, Span>
  where
    F: FnOnce(T) -> U,
  {
    CachedToken {
      token: self.token.map_data(f),
      state: self.state,
    }
  }

  /// Returns a reference to the state.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn state(&self) -> &State {
    &self.state
  }

  /// Consumes the cached token and returns the extras.
  #[cfg_attr(not(tarpaulin), inline(always))]
  #[allow(clippy::type_complexity)]
  pub fn into_components(self) -> (Spanned<T, Span>, State) {
    (self.token, self.state)
  }
}

#[cfg(test)]
#[allow(warnings)]
#[cfg(feature = "std")]
mod tests {
  use super::*;
  use crate::span::Spanned;

  #[test]
  fn cached_token_new_and_accessors() {
    let spanned = Spanned::new(10..20, "hello");
    let ct = CachedToken::new(spanned, 42u32);
    assert_eq!(ct.state(), &42);
    let tok = ct.token();
    assert_eq!(*tok.data(), &"hello");
  }

  #[test]
  fn cached_token_into_token() {
    let spanned = Spanned::new(10..20, "hello");
    let ct = CachedToken::new(spanned, 42u32);
    let tok = ct.into_token();
    assert_eq!(*tok.data(), "hello");
  }

  #[test]
  fn cached_token_as_ref() {
    let spanned = Spanned::new(10..20, 99u32);
    let ct = CachedToken::new(spanned, 42u32);
    let ct_ref = ct.as_ref();
    // as_ref returns CachedToken<&T, &State, &Span>, so state is &&u32
    assert_eq!(**ct_ref.state(), 42);
  }

  #[test]
  fn cached_token_map_token() {
    let spanned = Spanned::new(10..20, 5u32);
    let ct = CachedToken::new(spanned, "state");
    let ct2 = ct.map_token(|x| x * 2);
    assert_eq!(*ct2.token().data(), &10);
    assert_eq!(ct2.state(), &"state");
  }

  #[test]
  fn cached_token_into_components() {
    let spanned = Spanned::new(10..20, "hello");
    let ct = CachedToken::new(spanned, 42u32);
    let (tok, state) = ct.into_components();
    assert_eq!(*tok.data(), "hello");
    assert_eq!(state, 42);
  }

  #[test]
  fn cached_token_clone() {
    let spanned = Spanned::new(10..20, "hello");
    let ct = CachedToken::new(spanned, 42u32);
    let ct2 = ct.clone();
    assert_eq!(ct2.state(), &42);
  }

  #[test]
  fn cached_token_new_various_types() {
    let ct = CachedToken::new(Spanned::new(0..1, 100u64), "state_str");
    assert_eq!(ct.state(), &"state_str");
    assert_eq!(*ct.token().data(), &100u64);
  }

  #[test]
  fn cached_token_map_preserves_span() {
    let spanned = Spanned::new(5..15, 10i32);
    let ct = CachedToken::new(spanned, ());
    let ct2 = ct.map_token(|x| x.to_string());
    assert_eq!(*ct2.token().data(), &"10".to_string());
  }
}

#[cfg(test)]
#[allow(warnings)]
#[cfg(feature = "std")]
mod cache_trait_tests {
  use super::*;
  use crate::lexer::{DummyLexer, DummyToken};
  use crate::span::{SimpleSpan, Span, Spanned};
  use ::generic_arraydeque::typenum::U3;

  type DequeCache = GenericArrayDeque<CachedToken<DummyToken, (), SimpleSpan>, U3>;
  type OptionCache = Option<CachedToken<DummyToken, (), SimpleSpan>>;

  fn make_token(start: usize, end: usize) -> CachedToken<DummyToken, (), SimpleSpan> {
    CachedToken::new(Spanned::new(SimpleSpan::new(start, end), DummyToken), ())
  }

  // ── Cache::span ─────────────────────────────────────────────────────────

  #[test]
  fn deque_cache_span_empty() {
    let cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    assert!(<DequeCache as Cache<'_, DummyLexer>>::span(&cache).is_none());
  }

  #[test]
  fn deque_cache_span_single() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 10));
    let span = <DequeCache as Cache<'_, DummyLexer>>::span(&cache).unwrap();
    assert_eq!(span.start(), 5);
    assert_eq!(span.end(), 10);
  }

  #[test]
  fn deque_cache_span_multiple() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 10));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(10, 20));
    let span = <DequeCache as Cache<'_, DummyLexer>>::span(&cache).unwrap();
    assert_eq!(span.start(), 5);
    assert_eq!(span.end(), 20);
  }

  #[test]
  fn option_cache_span_empty() {
    let cache = <OptionCache as Cache<'_, DummyLexer>>::new();
    assert!(<OptionCache as Cache<'_, DummyLexer>>::span(&cache).is_none());
  }

  #[test]
  fn option_cache_span_with_token() {
    let mut cache = <OptionCache as Cache<'_, DummyLexer>>::new();
    let _ = <OptionCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(3, 7));
    let span = <OptionCache as Cache<'_, DummyLexer>>::span(&cache).unwrap();
    assert_eq!(span.start(), 3);
    assert_eq!(span.end(), 7);
  }

  // ── Cache::front_span / back_span ────────────────────────────────────────

  #[test]
  fn deque_cache_front_span_and_back_span() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    assert!(<DequeCache as Cache<'_, DummyLexer>>::front_span(&cache).is_none());
    assert!(<DequeCache as Cache<'_, DummyLexer>>::back_span(&cache).is_none());
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(5, 15));
    let front = <DequeCache as Cache<'_, DummyLexer>>::front_span(&cache).unwrap();
    let back = <DequeCache as Cache<'_, DummyLexer>>::back_span(&cache).unwrap();
    assert_eq!(front.start(), 0);
    assert_eq!(front.end(), 5);
    assert_eq!(back.start(), 5);
    assert_eq!(back.end(), 15);
  }

  #[test]
  fn option_cache_front_span_and_back_span() {
    let mut cache = <OptionCache as Cache<'_, DummyLexer>>::new();
    assert!(<OptionCache as Cache<'_, DummyLexer>>::front_span(&cache).is_none());
    assert!(<OptionCache as Cache<'_, DummyLexer>>::back_span(&cache).is_none());
    let _ = <OptionCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(2, 8));
    let front = <OptionCache as Cache<'_, DummyLexer>>::front_span(&cache).unwrap();
    let back = <OptionCache as Cache<'_, DummyLexer>>::back_span(&cache).unwrap();
    assert_eq!(front.start(), 2);
    assert_eq!(back.start(), 2);
  }

  // ── Cache::peek_one ──────────────────────────────────────────────────────

  #[test]
  fn deque_cache_peek_one_empty() {
    let cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    assert!(<DequeCache as Cache<'_, DummyLexer>>::peek_one(&cache).is_none());
  }

  #[test]
  fn deque_cache_peek_one_with_token() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    assert!(<DequeCache as Cache<'_, DummyLexer>>::peek_one(&cache).is_some());
    // peek_one does not consume
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::len(&cache), 1);
  }

  #[test]
  fn option_cache_peek_one_empty() {
    let cache = <OptionCache as Cache<'_, DummyLexer>>::new();
    assert!(<OptionCache as Cache<'_, DummyLexer>>::peek_one(&cache).is_none());
  }

  #[test]
  fn option_cache_peek_one_with_token() {
    let mut cache = <OptionCache as Cache<'_, DummyLexer>>::new();
    let _ = <OptionCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    assert!(<OptionCache as Cache<'_, DummyLexer>>::peek_one(&cache).is_some());
  }

  // ── Cache::try_pop_front_if ──────────────────────────────────────────────

  #[test]
  fn deque_cache_try_pop_front_if_ok() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let result =
      <DequeCache as Cache<'_, DummyLexer>>::try_pop_front_if::<(), _>(&mut cache, |_| Ok(()));
    assert!(matches!(result, Some(Ok(_))));
    assert!(<DequeCache as Cache<'_, DummyLexer>>::is_empty(&cache));
  }

  #[test]
  fn deque_cache_try_pop_front_if_err() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let _ = <DequeCache as Cache<'_, DummyLexer>>::push_back(&mut cache, make_token(0, 5));
    let result =
      <DequeCache as Cache<'_, DummyLexer>>::try_pop_front_if(&mut cache, |_| Err("fail"));
    assert!(matches!(result, Some(Err("fail"))));
    // Token is NOT consumed on error
    assert_eq!(<DequeCache as Cache<'_, DummyLexer>>::len(&cache), 1);
  }

  #[test]
  fn deque_cache_try_pop_front_if_empty() {
    let mut cache = <DequeCache as Cache<'_, DummyLexer>>::new();
    let result =
