    assert!(Container::<i32>::last(&c).is_none());
    assert_eq!(Container::<i32>::max_capacity(&c), usize::MAX);
  }
}

use super::{CstNode, CstNodeChildren, Language, SyntaxNode};

/// Returns the first child of a specific typed node type.
///
/// Searches through the children of the parent node and returns the first child
/// that can be successfully cast to the specified node type `N`.
#[inline]
pub fn child<N: CstNode<Lang>, Lang: Language>(parent: &SyntaxNode<Lang>) -> Option<N> {
  parent.children().find_map(|t| N::try_cast_node(t).ok())
}

/// Returns an iterator over all children of a specific typed node type.
///
/// Iterates through all children of the parent node, yielding only those that
/// can be successfully cast to the specified node type `N`.
#[inline]
pub fn children<N: CstNode<Lang>, Lang: Language>(
  parent: &SyntaxNode<Lang>,
) -> CstNodeChildren<N, Lang> {
  CstNodeChildren::new(parent)
}

/// Returns the first token child with the specified syntax kind.
///
/// Searches through all tokens (not nodes) that are direct children of the parent
/// and returns the first one matching the specified kind.
#[inline]
pub fn token<L: Language>(parent: &SyntaxNode<L>, kind: &L::Kind) -> Option<rowan::SyntaxToken<L>> {
  parent
    .children_with_tokens()
    .filter_map(|child| {
      child
        .into_token()
        .and_then(|t| t.kind().eq(kind).then_some(t))
    })
    .next()
}

#[cfg(test)]
#[allow(warnings)]
mod tests {
  use super::*;
  use rowan::{GreenNodeBuilder, Language as _, SyntaxKind};

  #[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
  enum TK {
    Root,
    Ident,
    Plus,
  }

  #[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
  enum TLang {}

  impl Language for TLang {
    type Kind = TK;

    fn kind_from_raw(raw: SyntaxKind) -> TK {
      match raw.0 {
        0 => TK::Root,
        1 => TK::Ident,
        2 => TK::Plus,
        _ => panic!("unknown"),
      }
    }

    fn kind_to_raw(kind: TK) -> SyntaxKind {
      match kind {
        TK::Root => SyntaxKind(0),
        TK::Ident => SyntaxKind(1),
        TK::Plus => SyntaxKind(2),
      }
    }
  }

  fn make_tree() -> SyntaxNode<TLang> {
    let mut builder = GreenNodeBuilder::new();
    builder.start_node(TLang::kind_to_raw(TK::Root));
    builder.token(TLang::kind_to_raw(TK::Ident), "x");
    builder.token(TLang::kind_to_raw(TK::Plus), "+");
    builder.finish_node();
    SyntaxNode::new_root(builder.finish())
  }

  #[test]
  fn token_finds_by_kind() {
    let root = make_tree();
    let plus = token(&root, &TK::Plus);
    assert!(plus.is_some());
    assert_eq!(plus.unwrap().text(), "+");
  }

  #[test]
  fn token_finds_ident() {
    let root = make_tree();
    let ident = token(&root, &TK::Ident);
    assert!(ident.is_some());
    assert_eq!(ident.unwrap().text(), "x");
  }

  #[test]
  fn token_returns_none_when_not_found() {
    let mut builder = GreenNodeBuilder::new();
    builder.start_node(TLang::kind_to_raw(TK::Root));
    builder.token(TLang::kind_to_raw(TK::Ident), "x");
    builder.finish_node();
    let root = SyntaxNode::<TLang>::new_root(builder.finish());
    let plus = token(&root, &TK::Plus);
    assert!(plus.is_none());
  }
}

use super::super::{CstElement, Language};
use derive_more::{From, Into};
use rowan::SyntaxNode;

/// An error indicating a mismatch between expected and actual syntax node kinds.
///
/// This error occurs when attempting to cast a [`SyntaxNode`] to a typed [`CstNode`](crate::cst::CstNode)
/// type, but the node's kind doesn't match the expected kind for that type.
#[derive(Debug, Clone, PartialEq, Eq, Hash, From, Into)]
pub struct CstNodeMismatch<N, Lang: Language> {
  found: SyntaxNode<Lang>,
  _m: core::marker::PhantomData<N>,
}

impl<N: CstElement<Lang>, Lang: Language> core::fmt::Display for CstNodeMismatch<N, Lang>
where
  Lang::Kind: core::fmt::Display,
{
  #[inline]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
    write!(
      f,
      "syntax node mismatch: expected syntax node of kind {}, but found syntax node of kind {}",
      N::KIND,
      self.found.kind()
    )
  }
}

impl<N: CstElement<Lang>, Lang: Language> core::error::Error for CstNodeMismatch<N, Lang>
where
  N: CstElement<Lang> + core::fmt::Debug,
  Lang::Kind: core::fmt::Display,
{
}

impl<N, Lang: Language> CstNodeMismatch<N, Lang> {
  /// Creates a new syntax node mismatch error.
  /// ```
  #[inline]
  pub const fn new(found: SyntaxNode<Lang>) -> Self {
    Self {
      found,
      _m: core::marker::PhantomData,
    }
  }

  /// Returns the expected syntax node kind.
  #[inline]
  pub const fn expected(&self) -> Lang::Kind
  where
    N: CstElement<Lang>,
  {
    N::KIND
  }

  /// Returns a reference to the syntax node that was found.
  #[inline]
  pub const fn found(&self) -> &SyntaxNode<Lang> {
    &self.found
  }

  /// Consumes the error and returns the expected kind and found node.
  ///
  /// This is useful for recovering the original syntax node after a failed cast,
  /// allowing you to try casting to a different type.
  #[inline]
  pub fn into_components(self) -> (Lang::Kind, SyntaxNode<Lang>)
  where
    N: CstElement<Lang>,
  {
    (N::KIND, self.found)
  }
}

