#[cfg(test)]
mod tests {
  use super::*;
  use rowan::{Language, SyntaxKind};

  #[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
  enum TestKind {
    Root,
    Ident,
    Plus,
  }

  #[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
  enum TestLang {}

  impl Language for TestLang {
    type Kind = TestKind;

    fn kind_from_raw(raw: SyntaxKind) -> TestKind {
      match raw.0 {
        0 => TestKind::Root,
        1 => TestKind::Ident,
        2 => TestKind::Plus,
        _ => panic!("unknown kind"),
      }
    }

    fn kind_to_raw(kind: TestKind) -> SyntaxKind {
      match kind {
        TestKind::Root => SyntaxKind(0),
        TestKind::Ident => SyntaxKind(1),
        TestKind::Plus => SyntaxKind(2),
      }
    }
  }

  #[test]
  fn builder_new_and_default() {
    let b1 = SyntaxTreeBuilder::<TestLang>::new();
    let b2 = SyntaxTreeBuilder::<TestLang>::default();
    // Just verify they can be created
    let _ = format!("{:?}", b1);
    let _ = format!("{:?}", b2);
  }

  #[test]
  fn builder_simple_tree() {
    let builder = SyntaxTreeBuilder::<TestLang>::new();
    builder.start_node(TestKind::Root);
    builder.token(TestKind::Ident, "hello");
    builder.finish_node();
    let green = builder.finish();

    let root = rowan::SyntaxNode::<TestLang>::new_root(green);
    assert_eq!(root.kind(), TestKind::Root);
    assert_eq!(root.to_string(), "hello");
  }

  #[test]
  fn builder_with_checkpoint() {
    let builder = SyntaxTreeBuilder::<TestLang>::new();
    builder.start_node(TestKind::Root);

    let checkpoint = builder.checkpoint();
    builder.token(TestKind::Ident, "foo");

    // Wrap the identifier in a new node retroactively
    builder.start_node_at(checkpoint, TestKind::Root);
    builder.finish_node();

    builder.finish_node();
    let green = builder.finish();
    let root = rowan::SyntaxNode::<TestLang>::new_root(green);
    assert_eq!(root.to_string(), "foo");
  }

  #[test]
  fn builder_multiple_tokens() {
    let builder = SyntaxTreeBuilder::<TestLang>::new();
    builder.start_node(TestKind::Root);
    builder.token(TestKind::Ident, "a");
    builder.token(TestKind::Plus, "+");
    builder.token(TestKind::Ident, "b");
    builder.finish_node();
    let green = builder.finish();

    let root = rowan::SyntaxNode::<TestLang>::new_root(green);
    assert_eq!(root.to_string(), "a+b");
  }

  #[test]
  fn cst_node_children_clone() {
    let builder = SyntaxTreeBuilder::<TestLang>::new();
    builder.start_node(TestKind::Root);
    builder.token(TestKind::Ident, "hello");
    builder.finish_node();
    let green = builder.finish();
    let root = rowan::SyntaxNode::<TestLang>::new_root(green);

    let children: CstNodeChildren<rowan::SyntaxNode<TestLang>, TestLang> =
      CstNodeChildren::new(&root);
    let _cloned = children.clone();
  }

  #[test]
  fn cst_node_children_by_kind() {
    let builder = SyntaxTreeBuilder::<TestLang>::new();
    builder.start_node(TestKind::Root);
    builder.start_node(TestKind::Root);
    builder.token(TestKind::Ident, "inner");
    builder.finish_node();
    builder.finish_node();
    let green = builder.finish();
    let root = rowan::SyntaxNode::<TestLang>::new_root(green);

    let children: CstNodeChildren<rowan::SyntaxNode<TestLang>, TestLang> =
      CstNodeChildren::new(&root);
    let matching: Vec<_> = children.by_kind(|k| k == TestKind::Root).collect();
    assert_eq!(matching.len(), 1);
  }
}

use crate::{Lexer, Token, error::token::UnexpectedToken, punct::*, span::Spanned, utils::CowStr};

/// A trait for any delimiter consisting of an opening and a closing punctuator.
pub trait Delimiter<'inp, L, Lang: ?Sized = ()> {
  /// The opening punctuator.
  type Open: Punctuator<'inp, L, Lang>;
  /// The closing punctuator.
  type Close: Punctuator<'inp, L, Lang>;

  /// The name of the delimiter.
  fn name() -> CowStr;

  /// Checks if the given token kind is the opening delimiter.
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn is_open(knd: &<L::Token as Token<'inp>>::Kind) -> bool
  where
    L: Lexer<'inp>,
  {
    <Self::Open as Punctuator<'inp, L, Lang>>::eval(knd)
  }

  /// Checks if the given token kind is the closing delimiter.
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn is_close(knd: &<L::Token as Token<'inp>>::Kind) -> bool
  where
    L: Lexer<'inp>,
  {
    <Self::Close as Punctuator<'inp, L, Lang>>::eval(knd)
  }

  /// Creates an `UnexpectedToken` error for an unexpected opening token.
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn unexpected_open_token(
    tok: Spanned<L::Token, L::Span>,
  ) -> UnexpectedToken<'inp, L::Token, <L::Token as Token<'inp>>::Kind, L::Span, Lang>
  where
    L: Lexer<'inp>,
  {
    <Self::Open as Punctuator<'inp, L, Lang>>::unexpected_token(tok)
  }

  /// Creates an `UnexpectedToken` error for an unexpected closing token.
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn unexpected_close_token(
    tok: Spanned<L::Token, L::Span>,
  ) -> UnexpectedToken<'inp, L::Token, <L::Token as Token<'inp>>::Kind, L::Span, Lang>
  where
    L: Lexer<'inp>,
  {
    <Self::Close as Punctuator<'inp, L, Lang>>::unexpected_token(tok)
  }
}

macro_rules! impl_builtin_delimiter {
  ($($name:ident { description: $description:literal, open: $open:ident, close: $close:ident $(,)? }),+$(,)?) => {
    $(
      impl<'inp, S, C, L, Lang: ?Sized> Delimiter<'inp, L, Lang> for $name<S, C, Lang>
      where
        L: Lexer<'inp>,
        $open<S, C, Lang>: Punctuator<'inp, L, Lang>,
        $close<S, C, Lang>: Punctuator<'inp, L, Lang>,
      {
        type Open = $open<S, C, Lang>;

        type Close = $close<S, C, Lang>;

        #[cfg_attr(not(tarpaulin), inline(always))]
        fn name() -> CowStr {
          CowStr::from_static($description)
        }
      }
    )*
  };
}

impl_builtin_delimiter! {
  Paren { description: "()", open: OpenParen, close: CloseParen },
  Angle { description: "<>", open: OpenAngle, close: CloseAngle },
  Bracket { description: "[]", open: OpenBracket, close: CloseBracket },
  Brace { description: "{}", open: OpenBrace, close: CloseBrace },
}

macro_rules! impl_deref {
  (@impl<$ty:ty>) => {
    type Open = <$ty>::Open;
    type Close = <$ty>::Close;

    #[cfg_attr(not(tarpaulin), inline(always))]
    fn name() -> CowStr {
      <$ty>::name()
    }

    #[cfg_attr(not(tarpaulin), inline(always))]
    fn is_open(knd: &<<L>::Token as Token<'inp>>::Kind) -> bool
    where
      L: Lexer<'inp>,
    {
      <$ty>::is_open(knd)
    }

    #[cfg_attr(not(tarpaulin), inline(always))]
    fn is_close(knd: &<<L>::Token as Token<'inp>>::Kind) -> bool
    where
      L: Lexer<'inp>,
    {
      <$ty>::is_close(knd)
    }

    #[cfg_attr(not(tarpaulin), inline(always))]
    fn unexpected_open_token(
      tok: Spanned<L::Token, L::Span>,
    ) -> UnexpectedToken<'inp, L::Token, <L::Token as Token<'inp>>::Kind, L::Span, Lang>
    where
      L: Lexer<'inp>,
    {
      <$ty>::unexpected_open_token(tok)
    }

    #[cfg_attr(not(tarpaulin), inline(always))]
    fn unexpected_close_token(
      tok: Spanned<L::Token, L::Span>,
    ) -> UnexpectedToken<'inp, L::Token, <L::Token as Token<'inp>>::Kind, L::Span, Lang>
    where
      L: Lexer<'inp>,
    {
      <$ty>::unexpected_close_token(tok)
    }
  };
}

