  // ── IncompleteHexEscape ────────────────────────────────────────────

  #[test]
  fn incomplete_new_and_span() {
    let err = IncompleteHexEscape::new(SimpleSpan::new(10, 13));
    assert_eq!(err.span(), SimpleSpan::new(10, 13));
  }

  #[test]
