//! Syntax definition and incomplete syntax error types.
//!
//! This module provides types for representing syntax elements with a known number
//! of components, and errors for tracking missing components during parsing.
//!
//! Two implementations are provided:
//! - **Const-generic** (default): Uses `const COMPONENTS: usize` for component count
//! - **Type-level** (with `generic-array` feature): Uses `typenum` for type-level component count
//!
//! The implementation is chosen at compile time based on feature flags.
//!
//! # Feature Flags
//!
//! - Without `generic-array`: Uses const-generic implementation
//! - With `generic-array`: Uses type-level implementation with `generic_arraydeque::ArrayLength`
//!
//! # Design Philosophy
//!
//! When parsing syntax elements that require multiple components (like variable declarations,
//! function definitions, etc.), it's valuable to track *all* missing components rather than
//! failing on the first missing one. This enables:
//!
//! - Better error messages showing all missing parts
//! - Faster development iteration (see all errors at once)
//! - More helpful IDE diagnostics
//!
//! # Examples
//!
//! ```rust
//! # {
//! use tokit::{
//!     utils::{typenum::U3, GenericArrayDeque},
//!     syntax::{Syntax, Language},
//!     error::IncompleteSyntax
//! };
//! use core::fmt;
//!
//! #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
//! struct MyLanguage;
//!
//! #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
//! enum MySyntaxKind {
//!     WhileLoop,
//! }
//!
//! impl Language for MyLanguage {
//!     type SyntaxKind = MySyntaxKind;
//! }
//!
//! #[derive(Debug, Clone, PartialEq, Eq, Hash)]
//! enum WhileComponent {
//!     WhileKeyword,
//!     Condition,
//!     Body,
//! }
//!
//! impl fmt::Display for WhileComponent {
//!     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
//!         match self {
//!             Self::WhileKeyword => write!(f, "'while' keyword"),
//!             Self::Condition => write!(f, "condition"),
//!             Self::Body => write!(f, "body"),
//!         }
//!     }
//! }
//!
//! struct WhileLoop;
//!
//! impl Syntax for WhileLoop {
//!     type Component = WhileComponent;
//!     type COMPONENTS = U3;
//!     type REQUIRED = U3;
//!     type Lang = MyLanguage;
//!     const KIND: MySyntaxKind = MySyntaxKind::WhileLoop;
//!
//!     fn possible_components() -> &'static GenericArrayDeque<Self::Component, U3> {
//!         const COMPONENTS: &GenericArrayDeque<WhileComponent, U3> = &GenericArrayDeque::from_array([
//!             WhileComponent::WhileKeyword,
//!             WhileComponent::Condition,
//!             WhileComponent::Body,
//!         ]);
//!         COMPONENTS
//!     }
//!
//!     fn required_components() -> &'static GenericArrayDeque<Self::Component, U3> {
//!         const REQUIRED: &GenericArrayDeque<WhileComponent, U3> = &GenericArrayDeque::from_array([
//!             WhileComponent::WhileKeyword,
//!             WhileComponent::Condition,
//!             WhileComponent::Body,
//!         ]);
//!         REQUIRED
//!     }
//! }
//!
//! let mut error = IncompleteSyntax::<WhileLoop>::new(
//!     tokit::SimpleSpan::new(10, 15),
//!     WhileComponent::Condition
//! );
//! assert_eq!(error.len(), 1);
//! # }
//! ```

use crate::{
  span::{SimpleSpan, Span},
  syntax::Syntax,
};
use generic_arraydeque::{GenericArrayDeque, typenum::Unsigned};

use core::{
  fmt::{Debug, Display},
  hash::Hash,
};

/// Represents an incomplete syntax with missing components.
///
/// This error type is used to track which components are missing from a syntax
/// construct during parsing. It stores components as a set (no duplicates) and
/// always contains at least one missing component.
///
/// # Design Philosophy
///
/// When parsing fails, it's valuable to report *all* missing components rather
/// than just the first one encountered. This type accumulates missing components
/// up to the syntax's maximum component count.
///
/// # Examples
///
/// ## Basic Usage
///
/// ```rust
/// # {
/// use tokit::{utils::{typenum, GenericArrayDeque}, syntax::{Language, Syntax}, error::IncompleteSyntax};
/// use typenum::U3;
/// use core::fmt;
///
/// #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
/// struct MyLanguage;
///
/// #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
/// enum MySyntaxKind {
///     IfStatement,
/// }
///
/// impl Language for MyLanguage {
///     type SyntaxKind = MySyntaxKind;
/// }
///
/// #[derive(Debug, Clone, PartialEq, Eq, Hash)]
/// enum IfStatementComponent {
///     IfKeyword,
///     Condition,
///     ThenBlock,
/// }
///
/// impl fmt::Display for IfStatementComponent {
///     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
///         match self {
///             Self::IfKeyword => write!(f, "'if' keyword"),
///             Self::Condition => write!(f, "condition"),
///             Self::ThenBlock => write!(f, "then block"),
///         }
///     }
/// }
///
/// struct IfStatement;
///
/// impl Syntax for IfStatement {
///     type Lang = MyLanguage;
///     type Component = IfStatementComponent;
///     type COMPONENTS = U3;
///     type REQUIRED = U3;
///     const KIND: MySyntaxKind = MySyntaxKind::IfStatement;
///
///     fn possible_components() -> &'static GenericArrayDeque<Self::Component, U3> {
///         const COMPONENTS: &GenericArrayDeque<IfStatementComponent, U3> = &GenericArrayDeque::from_array([
///            IfStatementComponent::IfKeyword,
///            IfStatementComponent::Condition,
///            IfStatementComponent::ThenBlock,
///         ]);
///         COMPONENTS
///     }
///
///     fn required_components() -> &'static GenericArrayDeque<Self::Component, U3> {
///         const REQUIRED: &GenericArrayDeque<IfStatementComponent, U3> = &GenericArrayDeque::from_array([
///             IfStatementComponent::IfKeyword,
///             IfStatementComponent::Condition,
///             IfStatementComponent::ThenBlock,
///         ]);
///         REQUIRED
///     }
/// }
///
/// // Report a missing component at a specific location
/// let error = IncompleteSyntax::<IfStatement>::new(
///     tokit::SimpleSpan::new(10, 15),
///     IfStatementComponent::Condition
/// );
/// assert_eq!(error.len(), 1);
///
/// // Add more missing components
/// let mut error = error;
/// error.push(IfStatementComponent::ThenBlock);
/// assert_eq!(error.len(), 2);
/// # }
/// ```
///
/// ## Error Message Formatting
///
/// ```rust
/// # {
/// # use tokit::{utils::{typenum, GenericArrayDeque}, syntax::Syntax, error::IncompleteSyntax};
/// # use typenum::U2;
/// # use core::fmt;
/// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
/// # enum Component { A, B }
/// # impl fmt::Display for Component {
/// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
/// #         match self { Self::A => write!(f, "A"), Self::B => write!(f, "B") }
/// #     }
/// # }
/// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
/// # struct MyLang;
/// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
/// # enum MySyntaxKind { Syntax }
/// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
/// # struct MySyntax;
/// # impl Syntax for MySyntax {
/// #     type Component = Component;
/// #     type COMPONENTS = U2;
/// #     type REQUIRED = U2;
/// #     type Lang = MyLang;
/// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
/// #     fn possible_components() -> &'static GenericArrayDeque<Component, U2> {
/// #         const COMPONENTS: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
/// #         COMPONENTS
/// #     }
/// #     fn required_components() -> &'static GenericArrayDeque<Component, U2> {
/// #         const REQUIRED: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
/// #         REQUIRED
/// #     }
/// # }
/// let mut error = IncompleteSyntax::<MySyntax>::new(
///     tokit::SimpleSpan::new(10, 15),
///     Component::A
/// );
/// assert_eq!(format!("{}", error), "incomplete syntax: component A is missing");
///
/// error.push(Component::B);
/// assert_eq!(format!("{}", error), "incomplete syntax: components A, B are missing");
/// # }
/// ```
#[derive(Debug, Clone)]
pub struct IncompleteSyntax<S: Syntax, Sp = SimpleSpan> {
  span: Sp,
  components: GenericArrayDeque<S::Component, S::COMPONENTS>,
}

impl<S, Sp> PartialEq for IncompleteSyntax<S, Sp>
where
  S: Syntax,
  Sp: PartialEq,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn eq(&self, other: &Self) -> bool {
    self.span == other.span && self.components == other.components
  }
}

impl<S, Sp> Eq for IncompleteSyntax<S, Sp>
where
  S: Syntax,
  Sp: Eq,
{
}

impl<S, Sp> Hash for IncompleteSyntax<S, Sp>
where
  S: Syntax,
  Sp: Hash,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn hash<H: core::hash::Hasher>(&self, state: &mut H) {
    self.span.hash(state);
    self.components.hash(state);
  }
}

impl<S, Sp> AsRef<[S::Component]> for IncompleteSyntax<S, Sp>
where
  S: Syntax,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn as_ref(&self) -> &[S::Component] {
    self.as_slice()
  }
}

impl<S, Sp> AsMut<[S::Component]> for IncompleteSyntax<S, Sp>
where
  S: Syntax,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn as_mut(&mut self) -> &mut [S::Component] {
    self.as_mut_slice()
  }
}

impl<S, Sp> IncompleteSyntax<S, Sp>
where
  S: Syntax,
{
  /// Creates a new incomplete syntax error with the specified span and missing component.
  ///
  /// The error always starts with at least one missing component.
  ///
  /// # Panics
  ///
  /// Panics if `S::COMPONENTS::USIZE` is 0 (which would be a malformed Syntax implementation).
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{SimpleSpan, syntax::Syntax, error::IncompleteSyntax, utils::{typenum, GenericArrayDeque}};
  /// # use typenum::U1;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result { write!(f, "A") }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U1;
  /// #     type REQUIRED = U1;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U1> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U1> = &GenericArrayDeque::from_array([Component::A]);
  /// #         COMPONENTS
  /// #     }
  /// #
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U1> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U1> = &GenericArrayDeque::from_array([Component::A]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let error = IncompleteSyntax::<MySyntax>::new(SimpleSpan::new(10, 15), Component::A);
  /// assert_eq!(error.len(), 1);
  /// assert_eq!(error.span(), SimpleSpan::new(10, 15));
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn new(span: Sp, component: S::Component) -> Self {
    if S::COMPONENTS::USIZE == 0 {
      panic!("IncompleteSyntax requires S::COMPONENTS to be non-zero");
    }
    let mut components = GenericArrayDeque::new();
    components.push_back(component);
    Self { span, components }
  }

  /// Tries to create an incomplete syntax error from a span and an iterator of components.
  ///
  /// Returns `None` if:
  /// - The iterator yields no components
  /// - The iterator yields more unique components than the buffer can hold
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{SimpleSpan, syntax::Syntax, error::IncompleteSyntax, utils::{typenum, GenericArrayDeque}};
  /// # use typenum::U2;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A, B }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
  /// #         match self { Self::A => write!(f, "A"), Self::B => write!(f, "B") }
  /// #     }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U2;
  /// #     type REQUIRED = U2;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         &COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let components = vec![Component::A, Component::B];
  /// let error = IncompleteSyntax::<MySyntax>::from_iter(SimpleSpan::new(10, 15), components).unwrap();
  /// assert_eq!(error.len(), 2);
  /// assert_eq!(error.span(), SimpleSpan::new(10, 15));
  ///
  /// // Empty iterator returns None
  /// let error = IncompleteSyntax::<MySyntax>::from_iter(SimpleSpan::new(10, 15), std::iter::empty());
  /// assert!(error.is_none());
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  #[allow(clippy::should_implement_trait)]
  pub fn from_iter(span: Sp, iter: impl IntoIterator<Item = S::Component>) -> Option<Self> {
    let mut components = GenericArrayDeque::new();
    for component in iter {
      Self::try_push_impl(&mut components, component);
    }
    (!components.is_empty()).then_some(Self { span, components })
  }

  /// Helper function that tries to push a component with deduplication logic.
  ///
  /// Returns `None` if the component was added or already exists (success),
  /// `Some(component)` if the buffer is full (failure).
  #[inline(always)]
  fn try_push_impl(
    components: &mut GenericArrayDeque<S::Component, S::COMPONENTS>,
    component: S::Component,
  ) -> Option<S::Component> {
    if components.contains(&component) {
      None
    } else {
      components.push_back(component)
    }
  }

  /// Helper function that tries to push a component with deduplication logic.
  ///
  /// Returns `None` if the component was added or already exists (success),
  /// `Some(component)` if the buffer is full (failure).
  #[inline(always)]
  fn try_push_front_impl(
    components: &mut GenericArrayDeque<S::Component, S::COMPONENTS>,
    component: S::Component,
  ) -> Option<S::Component> {
    if components.contains(&component) {
      None
    } else {
      components.push_front(component)
    }
  }

  /// Returns the number of missing components.
  ///
  /// The length is always at least 1.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{utils::{typenum, GenericArrayDeque}, syntax::Syntax, error::IncompleteSyntax};
  /// # use typenum::U2;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A, B }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
  /// #         match self { Self::A => write!(f, "A"), Self::B => write!(f, "B") }
  /// #     }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U2;
  /// #     type REQUIRED = U2;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let mut error = IncompleteSyntax::<MySyntax>::new(
  ///     tokit::SimpleSpan::new(10, 15),
  ///     Component::A
  /// );
  /// assert_eq!(error.len(), 1);
  /// error.push(Component::B);
  /// assert_eq!(error.len(), 2);
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  #[allow(clippy::len_without_is_empty)]
  pub fn len(&self) -> usize {
    self.components.len()
  }

  /// Returns the maximum number of components this error can hold.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{utils::{typenum, GenericArrayDeque}, syntax::Syntax, error::IncompleteSyntax};
  /// # use typenum::U3;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A, B, C }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result { write!(f, "X") }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U3;
  /// #     type REQUIRED = U3;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U3> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U3> = &GenericArrayDeque::from_array([Component::A, Component::B, Component::C]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U3> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U3> = &GenericArrayDeque::from_array([Component::A, Component::B, Component::C]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let error = IncompleteSyntax::<MySyntax>::new(
  ///     tokit::SimpleSpan::new(10, 15),
  ///     Component::A
  /// );
  /// assert_eq!(error.capacity(), 3);
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn capacity(&self) -> usize {
    self.components.capacity()
  }

  /// Returns `true` if the error is at full capacity.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{utils::{typenum, GenericArrayDeque}, syntax::Syntax, error::IncompleteSyntax};
  /// # use typenum::U2;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A, B }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
  /// #         match self { Self::A => write!(f, "A"), Self::B => write!(f, "B") }
  /// #     }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U2;
  /// #     type REQUIRED = U2;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let mut error = IncompleteSyntax::<MySyntax>::new(
  ///     tokit::SimpleSpan::new(10, 15),
  ///     Component::A
  /// );
  /// assert!(!error.is_full());
  /// error.push(Component::B);
  /// assert!(error.is_full());
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn is_full(&self) -> bool {
    self.components.is_full()
  }

  /// Pushes a new missing component into the error.
  ///
  /// If the component already exists in the error, this is a no-op (silently succeeds).
  /// This maintains the set semantics where each component appears at most once.
  ///
  /// # Panics
  ///
  /// Panics if the error is already full and the component is not already present.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{utils::{typenum, GenericArrayDeque}, syntax::Syntax, error::IncompleteSyntax};
  /// # use typenum::U2;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A, B }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
  /// #         match self { Self::A => write!(f, "A"), Self::B => write!(f, "B") }
  /// #     }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U2;
  /// #     type REQUIRED = U2;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let mut error = IncompleteSyntax::<MySyntax>::new(
  ///     tokit::SimpleSpan::new(10, 15),
  ///     Component::A
  /// );
  /// error.push(Component::B);
  /// // Pushing the same component again is a no-op
  /// error.push(Component::A);
  /// assert_eq!(error.len(), 2);
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn push(&mut self, component: S::Component) {
    if self.try_push(component).is_some() {
      panic!("IncompleteSyntax buffer overflow: cannot push more components")
    }
  }

  /// Pushes a new missing component into the error from the front.
  ///
  /// If the component already exists in the error, this is a no-op (silently succeeds).
  /// This maintains the set semantics where each component appears at most once.
  ///
  /// # Panics
  ///
  /// Panics if the error is already full and the component is not already present.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{utils::{typenum, GenericArrayDeque}, syntax::Syntax, error::IncompleteSyntax};
  /// # use typenum::U2;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A, B }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
  /// #         match self { Self::A => write!(f, "A"), Self::B => write!(f, "B") }
  /// #     }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U2;
  /// #     type REQUIRED = U2;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let mut error = IncompleteSyntax::<MySyntax>::new(
  ///     tokit::SimpleSpan::new(10, 15),
  ///     Component::A
  /// );
  /// error.push_front(Component::B);
  /// // Pushing the same component again is a no-op
  /// error.push_front(Component::A);
  /// assert_eq!(error.len(), 2);
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn push_front(&mut self, component: S::Component) {
    if self.try_push_front(component).is_some() {
      panic!("IncompleteSyntax buffer overflow: cannot push more components")
    }
  }

  /// Tries to push a new missing component into the error.
  ///
  /// Returns:
  /// - `None` if the component was added or already exists (success)
  /// - `Some(component)` if the buffer is full and the component is not present (failure)
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{utils::{typenum, GenericArrayDeque}, syntax::Syntax, error::IncompleteSyntax};
  /// # use typenum::U2;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A, B, C }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result { write!(f, "X") }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U2;
  /// #     type REQUIRED = U2;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let mut error = IncompleteSyntax::<MySyntax>::new(
  ///     tokit::SimpleSpan::new(10, 15),
  ///     Component::A
  /// );
  /// assert!(error.try_push(Component::B).is_none()); // Success
  /// assert_eq!(error.try_push(Component::C), Some(Component::C)); // Full!
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn try_push(&mut self, component: S::Component) -> Option<S::Component> {
    Self::try_push_impl(&mut self.components, component)
  }

  /// Tries to push a new missing component into the error from the front.
  ///
  /// Returns:
  /// - `None` if the component was added or already exists (success)
  /// - `Some(component)` if the buffer is full and the component is not present (failure)
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{utils::{typenum, GenericArrayDeque}, syntax::Syntax, error::IncompleteSyntax};
  /// # use typenum::U2;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A, B, C }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result { write!(f, "X") }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U2;
  /// #     type REQUIRED = U2;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let mut error = IncompleteSyntax::<MySyntax>::new(
  ///     tokit::SimpleSpan::new(10, 15),
  ///     Component::A
  /// );
  /// assert!(error.try_push_front(Component::B).is_none()); // Success
  /// assert_eq!(error.try_push_front(Component::C), Some(Component::C)); // Full!
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn try_push_front(&mut self, component: S::Component) -> Option<S::Component> {
    Self::try_push_front_impl(&mut self.components, component)
  }

  /// Returns a slice of the missing components.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{utils::{typenum, GenericArrayDeque}, syntax::Syntax, error::IncompleteSyntax};
  /// # use typenum::U2;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A, B }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
  /// #         match self { Self::A => write!(f, "A"), Self::B => write!(f, "B") }
  /// #     }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U2;
  /// #     type REQUIRED = U2;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let mut error = IncompleteSyntax::<MySyntax>::new(
  ///     tokit::SimpleSpan::new(10, 15),
  ///     Component::A
  /// );
  /// error.push(Component::B);
  /// assert_eq!(error.as_slice(), &[Component::A, Component::B]);
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn as_slice(&self) -> &[S::Component] {
    self.components.as_slices().0
  }

  /// Returns a mutable slice of the missing components.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{utils::{typenum, GenericArrayDeque}, syntax::Syntax, error::IncompleteSyntax};
  /// # use typenum::U2;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A, B }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
  /// #         match self { Self::A => write!(f, "A"), Self::B => write!(f, "B") }
  /// #     }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     type Component = Component;
  /// #     type COMPONENTS = U2;
  /// #     type REQUIRED = U2;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let mut error = IncompleteSyntax::<MySyntax>::new(
  ///     tokit::SimpleSpan::new(10, 15),
  ///     Component::A
  /// );
  /// error.as_mut_slice()[0] = Component::B;
  /// assert_eq!(error.as_slice()[0], Component::B);
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn as_mut_slice(&mut self) -> &mut [S::Component] {
    self.components.as_mut_slices().0
  }

  /// Returns an iterator over the missing components.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{SimpleSpan, syntax::Syntax, error::IncompleteSyntax, utils::{typenum, GenericArrayDeque}};
  /// # use typenum::U2;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A, B }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
  /// #         match self { Self::A => write!(f, "A"), Self::B => write!(f, "B") }
  /// #     }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U2;
  /// #     type REQUIRED = U2;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U2> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U2> = &GenericArrayDeque::from_array([Component::A, Component::B]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let mut error = IncompleteSyntax::<MySyntax>::new(SimpleSpan::new(10, 15), Component::A);
  /// error.push(Component::B);
  /// let collected: Vec<_> = error.iter().collect();
  /// assert_eq!(collected, vec![&Component::A, &Component::B]);
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn iter(&self) -> generic_arraydeque::Iter<'_, S::Component> {
    self.components.iter()
  }

  /// Returns the span of the incomplete syntax.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{SimpleSpan, syntax::Syntax, error::IncompleteSyntax, utils::{typenum, GenericArrayDeque}};
  /// # use typenum::U1;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result { write!(f, "A") }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U1;
  /// #     type REQUIRED = U1;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U1> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U1> = &GenericArrayDeque::from_array([Component::A]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U1> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U1> = &GenericArrayDeque::from_array([Component::A]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let error = IncompleteSyntax::<MySyntax>::new(SimpleSpan::new(10, 15), Component::A);
  /// assert_eq!(error.span(), SimpleSpan::new(10, 15));
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span(&self) -> Sp
  where
    Sp: Copy,
  {
    self.span
  }

  /// Returns a reference to the span of the incomplete syntax.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span_ref(&self) -> &Sp {
    &self.span
  }

  /// Returns a mutable reference to the span of the incomplete syntax.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span_mut(&mut self) -> &mut Sp {
    &mut self.span
  }

  /// Bumps the span by the given offset.
  ///
  /// This is useful when adjusting error positions after processing or
  /// when combining errors from different parsing contexts.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # {
  /// # use tokit::{SimpleSpan, syntax::Syntax, error::IncompleteSyntax, utils::{typenum, GenericArrayDeque}};
  /// # use typenum::U1;
  /// # use core::fmt;
  /// # #[derive(Debug, Clone, PartialEq, Eq, Hash)]
  /// # enum Component { A }
  /// # impl fmt::Display for Component {
  /// #     fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result { write!(f, "A") }
  /// # }
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # struct MyLang;
  /// # #[derive(Debug, Copy, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
  /// # enum MySyntaxKind { Syntax }
  /// # impl tokit::syntax::Language for MyLang { type SyntaxKind = MySyntaxKind; }
  /// # struct MySyntax;
  /// # impl Syntax for MySyntax {
  /// #     type Component = Component;
  /// #     type COMPONENTS = U1;
  /// #     type REQUIRED = U1;
  /// #     type Lang = MyLang;
  /// #     const KIND: MySyntaxKind = MySyntaxKind::Syntax;
  /// #     fn possible_components() -> &'static GenericArrayDeque<Component, U1> {
  /// #         const COMPONENTS: &GenericArrayDeque<Component, U1> = &GenericArrayDeque::from_array([Component::A]);
  /// #         COMPONENTS
  /// #     }
  /// #     fn required_components() -> &'static GenericArrayDeque<Component, U1> {
  /// #         const REQUIRED: &GenericArrayDeque<Component, U1> = &GenericArrayDeque::from_array([Component::A]);
  /// #         REQUIRED
  /// #     }
  /// # }
  /// let mut error = IncompleteSyntax::<MySyntax>::new(SimpleSpan::new(10, 15), Component::A);
  /// error.bump(&5);
  /// assert_eq!(error.span(), SimpleSpan::new(15, 20));
  /// # }
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn bump(&mut self, offset: &Sp::Offset) -> &mut Self
  where
    Sp: Span,
  {
    self.span.bump(offset);
    self
  }
}

impl<S, Sp> Display for IncompleteSyntax<S, Sp>
where
  S: Syntax,
{
  #[inline]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
    let components = self.as_slice();

    if components.len() == 1 {
      write!(
        f,
        "incomplete syntax: component {} is missing",
        components[0]
      )
    } else {
      write!(f, "incomplete syntax: components ")?;
      for (i, component) in components.iter().enumerate() {
        if i > 0 {
          write!(f, ", ")?;
        }
        write!(f, "{}", component)?;
      }
      write!(f, " are missing")
    }
  }
}

impl<S, Sp> core::error::Error for IncompleteSyntax<S, Sp>
where
  S: Syntax + Debug,
  Sp: Debug,
{
}

use crate::{
  span::{SimpleSpan, Span},
  utils::human_display::DisplayHuman,
};

/// An incomplete token
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct IncompleteToken<Knowledge, S = SimpleSpan> {
  span: S,
  knowledge: Option<Knowledge>,
}

impl<Knowledge> core::fmt::Display for IncompleteToken<Knowledge>
where
  Knowledge: DisplayHuman,
{
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
    match &self.knowledge {
      Some(knowledge) => write!(
        f,
        "incomplete {} token at {}",
        knowledge.display(),
        self.span
      ),
      None => write!(f, "incomplete token at {}", self.span),
    }
  }
}

impl<Knowledge> core::error::Error for IncompleteToken<Knowledge> where
  Knowledge: DisplayHuman + core::fmt::Debug
{
}

impl<Knowledge, S> IncompleteToken<Knowledge, S> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  const fn new_in(span: S, knowledge: Option<Knowledge>) -> Self {
    Self { span, knowledge }
  }

  /// Create a new `IncompleteToken` without any knowledge.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn new(span: S) -> Self {
    Self::new_in(span, None)
  }

  /// Create a new `IncompleteToken` with knowledge.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn with_knowledge(span: S, knowledge: Knowledge) -> Self {
    Self::new_in(span, Some(knowledge))
  }

  /// Get the span of the incomplete token.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span(&self) -> S
  where
    S: Copy,
  {
    self.span
  }

  /// Get the knowledge for the incomplete token, if any.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn knowledge(&self) -> Option<&Knowledge> {
    self.knowledge.as_ref()
  }

  /// Decompose the `IncompleteToken` into its components.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn into_components(self) -> (S, Option<Knowledge>) {
    (self.span, self.knowledge)
  }

  /// Bumps both the start and end positions of the span by the given offset.
  ///
  /// This is useful when adjusting error positions after processing or
  /// when combining spans from different contexts.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn bump(&mut self, offset: &S::Offset)
  where
    S: Span,
  {
    self.span.bump(offset);
  }
}

#[cfg(test)]
#[allow(warnings)]
#[cfg(feature = "std")]
mod tests {
  use super::*;
  use core::hash::Hash;

  #[test]
  fn new_without_knowledge() {
    let e: IncompleteToken<()> = IncompleteToken::new(SimpleSpan::new(0, 5));
    assert_eq!(e.span(), SimpleSpan::new(0, 5));
    assert_eq!(e.knowledge(), None);
  }

  #[test]
  fn with_knowledge_test() {
    let e: IncompleteToken<&str> = IncompleteToken::with_knowledge(SimpleSpan::new(0, 5), "int");
    assert_eq!(e.span(), SimpleSpan::new(0, 5));
    assert_eq!(e.knowledge(), Some(&"int"));
  }

  #[test]
  fn into_components_no_knowledge() {
    let e: IncompleteToken<()> = IncompleteToken::new(SimpleSpan::new(2, 8));
    let (span, knowledge) = e.into_components();
    assert_eq!(span, SimpleSpan::new(2, 8));
    assert_eq!(knowledge, None);
  }

  #[test]
  fn into_components_with_knowledge() {
    let e: IncompleteToken<&str> = IncompleteToken::with_knowledge(SimpleSpan::new(2, 8), "float");
    let (span, knowledge) = e.into_components();
    assert_eq!(span, SimpleSpan::new(2, 8));
    assert_eq!(knowledge, Some("float"));
  }

  #[test]
  fn bump_adjusts_span() {
    let mut e: IncompleteToken<()> = IncompleteToken::new(SimpleSpan::new(0, 5));
    e.bump(&10);
    assert_eq!(e.span(), SimpleSpan::new(10, 15));
  }

  #[test]
  fn display_no_knowledge() {
    extern crate alloc;
    let e: IncompleteToken<()> = IncompleteToken::new(SimpleSpan::new(3, 7));
    let s = alloc::format!("{e}");
    assert!(s.contains("incomplete token at"));
  }

  #[test]
  fn display_with_knowledge() {
    extern crate alloc;
    use crate::utils::knowledge::IntLiteral;
    let e: IncompleteToken<IntLiteral> =
      IncompleteToken::with_knowledge(SimpleSpan::new(3, 7), IntLiteral(()));
    let s = alloc::format!("{e}");
    assert!(s.contains("incomplete"));
    assert!(s.contains("token at"));
  }

  #[test]
  fn clone_and_eq() {
    let e: IncompleteToken<()> = IncompleteToken::new(SimpleSpan::new(0, 5));
    assert_eq!(e, e.clone());
  }

  #[test]
  fn debug_impl() {
    extern crate alloc;
    let e: IncompleteToken<()> = IncompleteToken::new(SimpleSpan::new(0, 5));
    let s = alloc::format!("{e:?}");
    assert!(s.contains("IncompleteToken"));
  }

  #[test]
  fn hash_impl() {
    let e: IncompleteToken<()> = IncompleteToken::new(SimpleSpan::new(0, 5));
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    e.hash(&mut hasher);
  }
}

//! Invalid value error type for tracking semantically incorrect values.
//!
//! This module provides the [`Invalid`] type for representing errors where a value
//! is syntactically correct but semantically invalid in the given context.
//!
//! # Design Philosophy
//!
//! "Invalid" indicates that a value is **not valid** in the current context, even though
//! its syntax is correct. The form/structure is fine, but the value itself doesn't make
//! sense. This is different from [`Malformed`] which indicates incorrect syntax.
//!
//! # Malformed vs Invalid
//!
//! - **`Malformed`**: Syntax/structure is wrong (badly formed)
//!   - Examples: `123abc` (mixed digits and letters), `0x` (missing hex digits),
//!     `"unterminated string`, `12.34.56` (malformed float)
//!   - The **form** is incorrect
//!   - Parser recognized what it *tried* to be, but it's syntactically broken
//!
//! - **`Invalid`**: Value/semantics is wrong (not valid)
//!   - Examples: `999` for a month value, `0777` in strict octal mode,
//!     `256` for a byte value, `-1` for an unsigned type
//!   - The **value** is incorrect
//!   - Syntax is correct, but the value doesn't make sense in context
//!
//! # Type Parameter
//!
//! - `Knowledge`: Provides context about what kind of value was invalid (typically
//!   a knowledge marker type like `IntLiteral`, `StringLiteral`, etc.)
//!
//! # Type Aliases
//!
//! This module provides convenient type aliases for common literal types:
//!
//! - [`InvalidStringLiteral`] - String values that are semantically invalid
//! - [`InvalidIntLiteral`] - Integer values out of range or context-inappropriate
//! - [`InvalidFloatLiteral`] - Float values that are semantically invalid
//! - [`InvalidHexLiteral`] - Hexadecimal values invalid in context
//! - [`InvalidBinaryLiteral`] - Binary values invalid in context
//! - [`InvalidOctalLiteral`] - Octal values invalid in context
//! - And more...
//!
//! # Examples
//!
//! ## Invalid Range Values
//!
//! ```rust
//! use tokit::{error::Invalid, SimpleSpan, utils::{knowledge::IntLiteral}};
//!
//! // Found "256" when parsing a byte (range 0-255)
//! let error = Invalid::int(SimpleSpan::new(10, 13));
//! assert_eq!(error.to_string(), "invalid at 10..13, did you mean int literal?");
//! ```
//!
//! ## Invalid Context Values
//!
//! ```rust
//! use tokit::{error::Invalid, SimpleSpan, utils::{knowledge::OctalLiteral}};
//!
//! // Found "0777" in strict mode where leading zeros aren't allowed
//! let error = Invalid::octal(SimpleSpan::new(5, 9));
//! assert_eq!(error.span(), SimpleSpan::new(5, 9));
//! ```
//!
//! ## Generic Invalid Value
//!
//! ```rust
//! use tokit::{error::Invalid, SimpleSpan};
//!
//! // Invalid with no specific knowledge
//! let error: Invalid<()> = Invalid::new(SimpleSpan::new(20, 25));
//! assert_eq!(error.to_string(), "invalid at 20..25");
//! ```
//!
//! ## With Custom Knowledge
//!
//! ```rust
//! use tokit::{error::Invalid, SimpleSpan, utils::{knowledge::HexLiteral}};
//!
//! // Found valid hex syntax but value out of range
//! let error = Invalid::with_knowledge(SimpleSpan::new(15, 20), HexLiteral::default());
//! assert_eq!(error.knowledge().is_some(), true);
//! ```

use crate::{
  span::{SimpleSpan, Span},
  utils::{human_display::DisplayHuman, knowledge::*},
};

/// An invalid string literal value.
///
/// Used when a string is syntactically correct but semantically invalid in context.
pub type InvalidStringLiteral = Invalid<StringLiteral>;

/// An invalid boolean literal value.
///
/// Used when a boolean value is correctly parsed but invalid in the given context.
pub type InvalidBooleanLiteral = Invalid<BooleanLiteral>;

/// An invalid null literal value.
///
/// Used when a null value appears in a context where it's not allowed.
pub type InvalidNullLiteral = Invalid<NullLiteral>;

/// An invalid enum literal value.
///
/// Used when an enum type is correctly formed but invalid in context.
pub type InvalidEnumLiteral = Invalid<EnumLiteral>;

/// An invalid enum value literal.
///
/// Used when an enum value is correctly formed but doesn't match any variant.
pub type InvalidEnumValueLiteral = Invalid<EnumValueLiteral>;

/// An invalid octal literal value.
///
/// Used when an octal number is syntactically correct but invalid (e.g., out of range).
pub type InvalidOctalLiteral = Invalid<OctalLiteral>;

/// An invalid decimal literal value.
///
/// Used when a decimal number is correctly formed but out of range or invalid in context.
pub type InvalidDecimalLiteral = Invalid<DecimalLiteral>;

/// An invalid hexadecimal literal value.
///
/// Used when a hex number is correctly formed but out of range or invalid in context.
pub type InvalidHexLiteral = Invalid<HexLiteral>;

/// An invalid integer literal value.
///
/// Used when an integer is correctly formed but out of range (e.g., `256` for a u8).
pub type InvalidIntLiteral = Invalid<IntLiteral>;

/// An invalid binary literal value.
///
/// Used when a binary number is correctly formed but invalid in context.
pub type InvalidBinaryLiteral = Invalid<BinaryLiteral>;

/// An invalid floating-point literal value.
///
/// Used when a float is correctly formed but invalid (e.g., `Infinity`, `NaN` in strict mode).
pub type InvalidFloatLiteral = Invalid<FloatLiteral>;

/// An invalid hexadecimal floating-point literal value.
///
/// Used when a hex float is correctly formed but invalid in context.
pub type InvalidHexFloatLiteral = Invalid<HexFloatLiteral>;

/// A zero-copy error type representing an invalid value.
///
/// This type tracks the position of a semantically invalid value, along with
/// optional knowledge about what kind of value was expected.
///
/// # Type Parameter
///
/// - `Knowledge`: Provides context about what was being validated (typically a knowledge
///   marker type like `IntLiteral`, `StringLiteral`, etc.). Must implement `DisplayHuman`
///   for error messages.
///
/// # Common Use Cases
///
/// - **Out of range values**: `256` for u8, `-1` for unsigned types, `999` for months
/// - **Context-inappropriate values**: `0777` in strict mode, `null` where not allowed
/// - **Semantically invalid**: Values that parse correctly but violate domain constraints
///
/// # Design
///
/// The `knowledge` field is optional, allowing this type to be used both with and
/// without specific context about what was being validated. When knowledge is present,
/// error messages can include "did you mean X?" suggestions.
///
/// # Examples
///
/// ## Basic Usage
///
/// ```rust
/// use tokit::{error::Invalid, SimpleSpan};
///
/// // Invalid value at position 10-13
/// let error: Invalid<()> = Invalid::new(SimpleSpan::new(10, 13));
/// assert_eq!(error.span(), SimpleSpan::new(10, 13));
/// assert_eq!(error.to_string(), "invalid at 10..13");
/// ```
///
/// ## With Knowledge Context
///
/// ```rust
/// use tokit::{error::Invalid, SimpleSpan, utils::{knowledge::IntLiteral}};
///
/// // Found "256" when expecting u8 (0-255)
/// let error = Invalid::int(SimpleSpan::new(5, 8));
/// assert_eq!(error.to_string(), "invalid at 5..8, did you mean int literal?");
/// ```
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct Invalid<Knowledge, S = SimpleSpan> {
  span: S,
  knowledge: Option<Knowledge>,
}

impl<Knowledge, S> core::fmt::Display for Invalid<Knowledge, S>
where
  Knowledge: DisplayHuman,
  S: core::fmt::Display,
{
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
    match &self.knowledge {
      Some(knowledge) => write!(
        f,
        "invalid at {}, did you mean {}?",
        self.span,
        knowledge.display()
      ),
      None => write!(f, "invalid at {}", self.span),
    }
  }
}

impl<Knowledge, S> core::error::Error for Invalid<Knowledge, S>
where
  Knowledge: DisplayHuman + core::fmt::Debug,
  S: core::fmt::Debug + core::fmt::Display,
{
}

