  }

  /// Consumes the error and returns its components.
  ///
  /// # Examples
  ///
  /// ```rust
  /// use tokit::{error::Undelimited, utils::CowStr, SimpleSpan};
  ///
  /// let error = Undelimited::<char>::new(SimpleSpan::new(10, 15), "\"".into());
  /// let (span, delimiter) = error.into_components();
