  }

  /// Consumes self and returns only the hint.
  ///
  /// # Example
  ///
  /// ```rust
  /// use tokit::{error::UnexpectedLexeme, utils::PositionedChar};
  ///
  /// let error = UnexpectedLexeme::from_positioned_char(
  ///     PositionedChar::with_position('!', 10),
  ///     "identifier"
  /// );
  ///
  /// let hint = error.into_hint();
  /// assert_eq!(hint, "identifier");
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn into_hint(self) -> Hint {
    self.hint
  }

  /// Returns the byte span covered by this lexeme using a custom length function.
  ///
  /// This delegates to [`Lexeme::span_with`].
  ///
  /// # Example
  ///
  /// ```rust
  /// use tokit::{error::UnexpectedLexeme, utils::PositionedChar};
  ///
  /// let error = UnexpectedLexeme::from_positioned_char(
  ///     PositionedChar::with_position('€', 5),
  ///     "ASCII character"
  /// );
  ///
  /// let span = error.span_with(|c: &char| c.len_utf8());
  /// assert_eq!(span.start(), 5);
  /// assert_eq!(span.end(), 8); // '€' is 3 bytes
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn span_with(&self, len_of: impl FnOnce(&Char) -> usize) -> SimpleSpan<O>
  where
    O: Clone + Ord,
    for<'a> &'a O: Add<usize, Output = O>,
  {
    self.lexeme.span_with(len_of)
  }

  /// Returns the byte span covered by this lexeme.
  ///
  /// This delegates to [`Lexeme::span`].
  ///
  /// # Example
  ///
  /// ```rust
  /// use tokit::{error::UnexpectedLexeme, SimpleSpan, utils::{PositionedChar}};
  ///
  /// let error = UnexpectedLexeme::from_positioned_char(
  ///     PositionedChar::with_position('x', 10),
  ///     "digit"
  /// );
  ///
  /// assert_eq!(error.span(), SimpleSpan::new(10, 11));
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn span(&self) -> SimpleSpan<O>
  where
    Char: CharLen,
    O: Clone + Ord,
    for<'a> &'a O: Add<usize, Output = O>,
  {
    self.lexeme.span()
  }

  /// Maps the character type to another type, preserving the hint.
  ///
  /// # Example
  ///
  /// ```rust
  /// use tokit::{error::UnexpectedLexeme, utils::PositionedChar};
  ///
  /// let error = UnexpectedLexeme::from_positioned_char(
  ///     PositionedChar::with_position('a', 5),
  ///     "digit"
  /// );
  ///
  /// let upper = error.map_char(|c| c.to_ascii_uppercase());
  /// assert_eq!(upper.unwrap_char().char(), 'A');
  /// assert_eq!(*upper.hint(), "digit");
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn map_char<F, NewChar>(self, f: F) -> UnexpectedLexeme<NewChar, Hint, O>
  where
    F: FnMut(Char) -> NewChar,
  {
    UnexpectedLexeme {
      lexeme: self.lexeme.map(f),
      hint: self.hint,
    }
  }

  /// Maps the hint type to another type, preserving the lexeme.
  ///
  /// # Example
  ///
  /// ```rust
  /// use tokit::{error::UnexpectedLexeme, utils::PositionedChar};
  ///
  /// let error = UnexpectedLexeme::from_positioned_char(
  ///     PositionedChar::with_position('!', 5),
  ///     "digit"
  /// );
  ///
  /// let detailed = error.map_hint(|h| format!("expected {}", h));
  /// assert_eq!(detailed.hint(), "expected digit");
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn map_hint<F, NewHint>(self, f: F) -> UnexpectedLexeme<Char, NewHint, O>
  where
    F: FnOnce(Hint) -> NewHint,
  {
    UnexpectedLexeme {
      lexeme: self.lexeme,
      hint: f(self.hint),
    }
  }

  /// Maps both the character and hint types to other types.
  ///
  /// # Example
  ///
  /// ```rust
  /// use tokit::{error::UnexpectedLexeme, utils::PositionedChar};
  ///
  /// let error = UnexpectedLexeme::from_positioned_char(
  ///     PositionedChar::with_position('a', 5),
  ///     "number"
  /// );
  ///
  /// let transformed = error.map(
  ///     |c| c.to_ascii_uppercase(),
  ///     |h| format!("expected {}", h)
  /// );
  ///
  /// assert_eq!(transformed.unwrap_char().char(), 'A');
  /// assert_eq!(transformed.hint(), "expected number");
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn map<F, NewChar, G, NewHint>(self, f: F, g: G) -> UnexpectedLexeme<NewChar, NewHint, O>
  where
    F: FnMut(Char) -> NewChar,
    G: FnOnce(Hint) -> NewHint,
  {
    UnexpectedLexeme {
      lexeme: self.lexeme.map(f),
      hint: g(self.hint),
    }
  }

  /// Adjusts the lexeme's position/span by adding `n` bytes.
  ///
  /// Returns a mutable reference to self for method chaining.
  ///
  /// # Example
  ///
  /// ```rust
  /// use tokit::{error::UnexpectedLexeme, utils::PositionedChar};
  ///
  /// let mut error = UnexpectedLexeme::from_positioned_char(
  ///     PositionedChar::with_position('x', 5),
  ///     "digit"
  /// );
  ///
  /// error.bump(&10);
  /// assert_eq!(error.unwrap_char().position(), 15);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn bump(&mut self, n: &O) -> &mut Self
  where
    O: for<'a> AddAssign<&'a O> + Clone,
  {
    self.lexeme.bump(n);
    self
  }
}

use core::ops::{Add, AddAssign};

use crate::{
  span::SimpleSpan,
  utils::{CharLen, Lexeme, PositionedChar, human_display::DisplayHuman},
};

/// An error indicating that an unexpected prefix was found after a valid token.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct UnexpectedPrefix<Char, Knowledge, O = usize> {
  token: SimpleSpan<O>,
  prefix: Lexeme<Char, O>,
  knowledge: Option<Knowledge>,
}

impl<Char, Knowledge, O> UnexpectedPrefix<Char, Knowledge, O> {
  /// Create a new `UnexpectedPrefix` error indicating a leading zero was found.
  ///
  /// ## Panics
  /// - If the prefix overlaps the token span (i.e., if it ends after the token span starts).
  ///
  /// ## Examples
  ///
  /// ```rust
  /// use tokit::{SimpleSpan, utils::{knowledge::IntLiteral}, error::UnexpectedPrefix};
  ///
  /// let error: UnexpectedPrefix<char, IntLiteral> = UnexpectedPrefix::leading_zero(
  ///   SimpleSpan::new(1, 5),
  ///   0,
  ///   '0'
  /// );
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn leading_zero(token: SimpleSpan<O>, pos: O, ch: Char) -> Self
  where
    Knowledge: DenyLeadingZero,
    Char: CharLen,
    O: Clone + Ord,
    for<'a> &'a O: Add<usize, Output = O>,
  {
    Self::from_char(token, pos, ch).with_knowledge(Knowledge::INIT)
  }

  /// Create a new `UnexpectedPrefix` error from the given token span and the prefix span
  ///
  /// ## Panics
  /// - If the prefix span ends after the token span starts.
  ///
  /// ## Examples
  ///
  /// ```rust
  /// use tokit::{SimpleSpan, utils::{knowledge::IntLiteral}, error::UnexpectedPrefix};
  ///
  /// let error: UnexpectedPrefix<char, IntLiteral> = UnexpectedPrefix::leading_zeros(
  ///   SimpleSpan::new(6, 10),
  ///   SimpleSpan::new(0, 6)
  /// );
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn leading_zeros(token: SimpleSpan<O>, span: SimpleSpan<O>) -> Self
  where
    Knowledge: DenyLeadingZero,
    Char: CharLen,
    O: Clone + Ord,
    for<'a> &'a O: Add<usize, Output = O>,
  {
    Self::from_prefix(token, span).with_knowledge(Knowledge::INIT)
  }
}

impl<Char, Knowledge, O> UnexpectedPrefix<Char, Knowledge, O> {
  /// Creates a new `UnexpectedPrefix` error with the span of the valid token and the unexpected prefix.
  ///
  /// ## Panics
  /// - If the prefix span ends after the token span starts.
  ///
  /// ## Examples
  ///
  /// ```rust
  /// use tokit::{SimpleSpan, utils::{Lexeme, PositionedChar}, error::UnexpectedPrefix};
  ///
  /// let error: UnexpectedPrefix<char, ()> = UnexpectedPrefix::new(
  ///     SimpleSpan::new(1, 5),
  ///     Lexeme::Char(PositionedChar::with_position('x', 0))
  /// );
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn new(token: SimpleSpan<O>, prefix: Lexeme<Char, O>) -> Self
  where
    Char: CharLen,
    O: Clone + Ord,
    for<'a> &'a O: Add<usize, Output = O>,
  {
    assert!(
      prefix.end().le(token.start_ref()),
      "prefix ends after token starts"
    );

    Self {
      token,
      prefix,
      knowledge: None,
    }
  }

  /// Create a new `UnexpectedPrefix` error from the given token span and character with position.
  ///
  /// ## Panics
  /// - If the prefix overlaps the token span (i.e., if it ends after the token span starts).
  ///
  /// ## Examples
  ///
  /// ```rust
  /// use tokit::{SimpleSpan, utils::{PositionedChar}, error::UnexpectedPrefix};
  ///
  /// let error: UnexpectedPrefix<char, ()> = UnexpectedPrefix::from_char(
  ///    SimpleSpan::new(1, 5),
  ///    0,
  ///   'x'
  /// );
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn from_char(token: SimpleSpan<O>, pos: O, ch: Char) -> Self
  where
    Char: CharLen,
    O: Clone + Ord,
    for<'a> &'a O: Add<usize, Output = O>,
  {
    Self::from_positioned_char(token, PositionedChar::with_position(ch, pos))
  }

  /// Create a new `UnexpectedPrefix` error from the given token span and character with position.
  ///
  /// ## Panics
  /// - If the prefix overlaps the token span (i.e., if it ends after the token span starts).
  ///
  /// ## Examples
  ///
  /// ```rust
  /// use tokit::{SimpleSpan, utils::{PositionedChar}, error::UnexpectedPrefix};
  ///
  /// let error: UnexpectedPrefix<char, ()> = UnexpectedPrefix::from_positioned_char(
  ///    SimpleSpan::new(1, 5),
  ///    PositionedChar::with_position('x', 0)
  /// );
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn from_positioned_char(token: SimpleSpan<O>, ch: PositionedChar<Char, O>) -> Self
  where
    Char: CharLen,
    O: Clone + Ord,
    for<'a> &'a O: Add<usize, Output = O>,
  {
    Self::new(token, Lexeme::Char(ch))
  }

  /// Adds knowledge to the `UnexpectedPrefix` error.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn with_knowledge_const(mut self, knowledge: Knowledge) -> Self
  where
    Knowledge: Copy,
  {
    self.knowledge = Some(knowledge);
    self
  }

  /// Adds knowledge to the `UnexpectedPrefix` error.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn with_knowledge(mut self, knowledge: Knowledge) -> Self {
    self.knowledge = Some(knowledge);
    self
  }

  /// Create a new `UnexpectedPrefix` error from the given token span and the prefix span
  ///
  /// ## Panics
  /// - If the prefix span ends after the token span starts.
  ///
  /// ## Examples
  ///
  /// ```rust
  /// use tokit::{SimpleSpan, utils::{Lexeme}, error::UnexpectedPrefix};
  ///
  /// let error: UnexpectedPrefix<char, ()> = UnexpectedPrefix::from_prefix(
  ///   SimpleSpan::new(6, 10),
  ///   SimpleSpan::new(0, 6)
  /// );
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn from_prefix(token: SimpleSpan<O>, span: SimpleSpan<O>) -> Self
  where
    Char: CharLen,
    O: Clone + Ord,
    for<'a> &'a O: Add<usize, Output = O>,
  {
    Self::new(token, Lexeme::Range(span))
  }

  /// Returns the full span since the start of the unexpected prefix to the end of the valid token.
  ///
  /// ## Examples
  ///
  /// ```rust
  /// use tokit::{SimpleSpan, utils::{Lexeme, PositionedChar}, error::UnexpectedPrefix};
  ///
  /// let error: UnexpectedPrefix<char, ()> = UnexpectedPrefix::new(
  ///   SimpleSpan::new(1, 5),
  ///   Lexeme::Char(PositionedChar::with_position('x', 0))
  /// );
  /// assert_eq!(error.span(), SimpleSpan::new(0, 5));
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn span(&self) -> SimpleSpan<O>
  where
    Char: CharLen,
    O: Clone + Ord,
  {
    let end = self.token.end_ref();
    let start = match &self.prefix {
      Lexeme::Char(positioned_char) => positioned_char.position_ref().clone(),
      Lexeme::Range(span) => span.start_ref().clone(),
    };
    SimpleSpan::new(start, end.clone())
  }

  /// Returns the span of the valid token before the unexpected prefix.
  ///
  /// ## Examples
  ///
  /// ```rust
  /// use tokit::{SimpleSpan, utils::{Lexeme, PositionedChar}, error::UnexpectedPrefix};
  ///
  /// let error: UnexpectedPrefix<char, ()> = UnexpectedPrefix::new(
  ///     SimpleSpan::new(1, 5),
  ///     Lexeme::Char(PositionedChar::with_position('x', 0))
  /// );
  /// assert_eq!(error.token(), SimpleSpan::new(1, 5));
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn token(&self) -> SimpleSpan<O>
  where
    O: Copy,
  {
    self.token
  }

  /// Returns the unexpected prefix found before the valid token.
  ///
  /// ## Examples
  ///
  /// ```rust
  /// use tokit::{SimpleSpan, utils::{Lexeme, PositionedChar}, error::UnexpectedPrefix};
  ///
  /// let error: UnexpectedPrefix<char, ()> = UnexpectedPrefix::new(
  ///    SimpleSpan::new(1, 5),
  ///   Lexeme::Char(PositionedChar::with_position('x', 0))
  /// );
  ///
  /// assert_eq!(
  ///   error.prefix(),
  ///   &Lexeme::Char(PositionedChar::with_position('x', 0))
  /// );
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn prefix(&self) -> &Lexeme<Char, O> {
    &self.prefix
  }

  /// Consumes the error and returns the unexpected prefix.
  ///
  /// ## Examples
  ///
  /// ```rust
  /// use tokit::{SimpleSpan, utils::{Lexeme, PositionedChar}, error::UnexpectedPrefix};
  ///
  /// let error: UnexpectedPrefix<char, ()> = UnexpectedPrefix::new(
  ///   SimpleSpan::new(1, 5),
  ///   Lexeme::Char(PositionedChar::with_position('x', 0))
  /// );
  /// let (token, prefix) = error.into_components();
  /// assert_eq!(token, SimpleSpan::new(1, 5));
  /// assert_eq!(
  ///   prefix,
  ///   Lexeme::Char(PositionedChar::with_position('x', 0))
  /// );
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn into_components(self) -> (SimpleSpan<O>, Lexeme<Char, O>) {
    (self.token, self.prefix)
  }

  /// Bumps both the start and end positions of the token span by the given offset.
  ///
  /// This is useful when adjusting error positions after processing or
  /// when combining spans from different contexts.
  ///
  /// ## Examples
  ///
  /// ```rust
  /// use tokit::{SimpleSpan, utils::{Lexeme, PositionedChar}, error::UnexpectedPrefix};
  ///
  /// let mut error: UnexpectedPrefix<char, ()> = UnexpectedPrefix::new(
  ///   SimpleSpan::new(1, 5),
  ///   Lexeme::Char(PositionedChar::with_position('x', 0))
  /// );
  /// error.bump(&10);
  /// assert_eq!(error.token(), SimpleSpan::new(11, 15));
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn bump(&mut self, offset: &O) -> &mut Self
  where
    O: for<'a> AddAssign<&'a O> + Clone,
  {
    self.token.bump(offset);
    self
  }
}

impl<Char, Knowledge> core::fmt::Display for UnexpectedPrefix<Char, Knowledge>
where
  Char: DisplayHuman,
  Knowledge: DisplayHuman,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
    match &self.prefix {
      Lexeme::Char(positioned_char) => match &self.knowledge {
        None => write!(
          f,
          "unexpected prefix '{}' at position {} found before {}",
          positioned_char.char_ref().display(),
          positioned_char.position(),
          self.token
        ),
        Some(knowledge) => {
          write!(
            f,
            "unexpected prefix '{}' at position {} found before '{}'@({})",
            positioned_char.char_ref().display(),
            positioned_char.position(),
            knowledge.display(),
            self.token
          )
        }
      },
      Lexeme::Range(span) => match &self.knowledge {
        Some(knowledge) => write!(
          f,
          "unexpected prefix at {} found before '{}'@({})",
          span,
          knowledge.display(),
          self.token
        ),
        None => write!(
          f,
          "unexpected prefix at {} found before {}",
          span, self.token
        ),
      },
    }
  }
}

impl<Char, Knowledge> core::error::Error for UnexpectedPrefix<Char, Knowledge>
where
  Char: DisplayHuman + core::fmt::Debug,
  Knowledge: DisplayHuman + core::fmt::Debug,
{
}

#[cfg(test)]
#[allow(warnings)]
#[cfg(feature = "std")]
mod tests {
  use super::*;
  use core::hash::Hash;

  type UpError = UnexpectedPrefix<u8, ()>;

  fn make_char_error() -> UpError {
    UnexpectedPrefix::new(
      SimpleSpan::new(1, 5),
      Lexeme::Char(PositionedChar::with_position(b'x', 0)),
    )
  }

  fn make_range_error() -> UpError {
    UnexpectedPrefix::from_prefix(SimpleSpan::new(6, 10), SimpleSpan::new(0, 6))
  }

  #[test]
  fn new_creates_error() {
    let e = make_char_error();
    assert_eq!(e.token(), SimpleSpan::new(1, 5));
  }

  #[test]
  fn from_char_creates_error() {
    let e: UpError = UnexpectedPrefix::from_char(SimpleSpan::new(1, 5), 0, b'x');
    assert_eq!(e.token(), SimpleSpan::new(1, 5));
  }

  #[test]
  fn from_positioned_char_creates_error() {
    let e: UpError = UnexpectedPrefix::from_positioned_char(
      SimpleSpan::new(1, 5),
      PositionedChar::with_position(b'x', 0),
    );
    assert_eq!(e.token(), SimpleSpan::new(1, 5));
  }

  #[test]
  fn from_prefix_creates_error() {
    let e = make_range_error();
    assert_eq!(e.token(), SimpleSpan::new(6, 10));
  }

  #[test]
  fn with_knowledge_method() {
    let e = make_char_error().with_knowledge(());
    assert_eq!(e.token(), SimpleSpan::new(1, 5));
  }

  #[test]
  fn with_knowledge_const_method() {
    let e = make_char_error().with_knowledge_const(());
    assert_eq!(e.token(), SimpleSpan::new(1, 5));
  }

  #[test]
  fn span_char_variant() {
    let e = make_char_error();
    assert_eq!(e.span(), SimpleSpan::new(0, 5));
  }

  #[test]
  fn span_range_variant() {
    let e = make_range_error();
    assert_eq!(e.span(), SimpleSpan::new(0, 10));
  }

  #[test]
  fn prefix_accessor() {
    let e = make_char_error();
    assert_eq!(
      e.prefix(),
      &Lexeme::Char(PositionedChar::with_position(b'x', 0))
    );
  }

  #[test]
  fn into_components_test() {
    let e = make_char_error();
    let (token, prefix) = e.into_components();
    assert_eq!(token, SimpleSpan::new(1, 5));
    assert_eq!(prefix, Lexeme::Char(PositionedChar::with_position(b'x', 0)));
  }

  #[test]
  fn bump_test() {
    let mut e = make_char_error();
    e.bump(&10);
    assert_eq!(e.token(), SimpleSpan::new(11, 15));
  }

  #[test]
  fn display_char_no_knowledge() {
    extern crate alloc;
    let e = make_char_error();
    let s = alloc::format!("{e}");
    assert!(s.contains("unexpected prefix"));
    assert!(s.contains("position 0"));
  }

  #[test]
  fn display_char_with_knowledge() {
    extern crate alloc;
    let e = make_char_error().with_knowledge(());
    let s = alloc::format!("{e}");
    assert!(s.contains("unexpected prefix"));
  }

  #[test]
  fn display_range_no_knowledge() {
    extern crate alloc;
    let e = make_range_error();
    let s = alloc::format!("{e}");
    assert!(s.contains("unexpected prefix at"));
  }

  #[test]
  fn display_range_with_knowledge() {
    extern crate alloc;
    let e = make_range_error().with_knowledge(());
    let s = alloc::format!("{e}");
    assert!(s.contains("unexpected prefix at"));
  }

  #[test]
  fn clone_and_eq() {
    let e = make_char_error();
    assert_eq!(e, e.clone());
  }

  #[test]
  fn debug_impl() {
    extern crate alloc;
    let e = make_char_error();
    let s = alloc::format!("{e:?}");
    assert!(s.contains("UnexpectedPrefix"));
  }

  #[test]
  fn hash_impl() {
    let e = make_char_error();
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    e.hash(&mut hasher);
  }

  #[test]
  fn leading_zero() {
    use crate::utils::knowledge::IntLiteral;
    let e: UnexpectedPrefix<u8, IntLiteral> =
      UnexpectedPrefix::leading_zero(SimpleSpan::new(1, 5), 0, b'0');
    assert_eq!(e.token(), SimpleSpan::new(1, 5));
  }

  #[test]
  fn leading_zeros() {
    use crate::utils::knowledge::IntLiteral;
    let e: UnexpectedPrefix<u8, IntLiteral> =
      UnexpectedPrefix::leading_zeros(SimpleSpan::new(6, 10), SimpleSpan::new(0, 6));
    assert_eq!(e.token(), SimpleSpan::new(6, 10));
  }
}

