  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn into_components(self) -> (S, Knowledge) {
    (self.span, self.knowledge)
  }
}

use core::marker::PhantomData;

use super::{Cursor, Lexer};

/// A checkpoint that captures the lexer's state for backtracking.
///
/// A `Checkpoint` stores a snapshot of the lexer's position and state
/// at a specific point in time. This allows you to save the current state using
/// [`InputRef::save`](crate::InputRef::save) and later restore it using [`InputRef::restore`](crate::InputRef::restore), enabling
/// efficient backtracking in parsers.
///
/// Checkpoints include:
/// - The cursor position (byte offset in the input)
/// - The lexer's extras state (for stateful lexers)
/// - Cache state (implicitly through the cursor)
///
/// # Example
///
/// ```ignore
/// let checkpoint = tokenizer.save();
/// // Try parsing something that might fail...
/// if should_backtrack {
///     tokenizer.restore(checkpoint); // Restore to saved state
/// }
/// ```
pub struct Checkpoint<'a, 'closure, L: Lexer<'a>> {
  cursor: Cursor<'a, 'closure, L>,
  pub(crate) state: L::State,
  _m: PhantomData<fn(&'closure ()) -> &'closure ()>,
}

impl<'a, 'closure, L: Lexer<'a>> Checkpoint<'a, 'closure, L> {
  /// Creates a new checkpoint.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub(super) const fn new(cursor: Cursor<'a, 'closure, L>, state: L::State) -> Self {
    Self {
      cursor,
      state,
      _m: PhantomData,
    }
  }

  /// Returns the cursor of the checkpoint.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn cursor(&self) -> &Cursor<'a, 'closure, L> {
    &self.cursor
  }

  /// Returns the state of the checkpoint.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn state(&self) -> &L::State {
    &self.state
  }
}

use core::marker::PhantomData;

use super::{Lexer, Span};

/// A cursor representing a position in the input source.
///
/// `Cursor` is a lightweight type that wraps a byte offset into the lexer's
/// input source. It's used by [`Checkpoint`](crate::input::Checkpoint) to track positions and represents
/// the current position in the input stream.
///
/// The cursor position represents:
/// - The byte offset in the input where the tokenizer will continue lexing
/// - If there are cached tokens, it points to the start of the first cached token
/// - Otherwise, it points to the position where the next token will be lexed from
#[repr(transparent)]
pub struct Cursor<'inp, 'closure, L: Lexer<'inp>> {
  pub(crate) span: L::Span,
  _phantom: PhantomData<fn(&'closure ()) -> &'closure ()>,
}

impl<'a, L: Lexer<'a>> core::fmt::Debug for Cursor<'a, '_, L> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
    write!(f, "Cursor({:?})", self.span.end_ref())
  }
}

impl<'a, L: Lexer<'a>> Clone for Cursor<'a, '_, L> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn clone(&self) -> Self {
    Self {
      span: self.span.clone(),
      _phantom: PhantomData,
    }
  }
}

impl<'a, L: Lexer<'a>> Copy for Cursor<'a, '_, L> where L::Span: Copy {}

impl<'a, L: Lexer<'a>> Cursor<'a, '_, L> {
  /// Creates a new cursor.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub(super) const fn new(span: L::Span) -> Self {
    Self {
      span,
      _phantom: PhantomData,
    }
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  pub(super) const fn from_ref(cursor: &L::Span) -> &Self {
    // SAFETY: Cursor is #[repr(transparent)]
    unsafe { &*(cursor as *const L::Span as *const Self) }
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  pub(super) const fn span(&self) -> &L::Span {
    &self.span
  }

  /// Returns a reference to the actual cursor.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn as_inner(&self) -> &L::Offset {
    self.span.end_ref()
  }

  /// Returns the actual cursor.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn into_inner(self) -> L::Offset {
    self.span.into_range().end
  }
}

use super::*;

impl<'inp, L, Ctx, Lang: ?Sized> InputRef<'inp, '_, L, Ctx, Lang>
where
  L: Lexer<'inp>,
  L::State: Clone,
  Ctx: ParseContext<'inp, L, Lang>,
{
  /// Consumes one token from the peeked tokens and returns the consumed token if any, the cursor is advanced.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn consume_cached_one(&mut self) -> Option<Spanned<L::Token, L::Span>> {
    let tok = self.cache_mut().pop_front()?;
    let (tok, extras): (Spanned<L::Token, L::Span>, _) = tok.into_components();
    self.set_span_after_consume(tok.span_ref().into());
    *self.state = extras;
    Some(tok)
  }

  /// Consumes tokens from cache until the predicate returns `true`.
  ///
  /// Advances the cursor to the end of the last consumed token.
  /// Returns the last consumed token.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn consume_cached_to<F>(&mut self, mut f: F) -> Option<Spanned<L::Token, L::Span>>
  where
    F: FnMut(CachedTokenRefOf<'_, 'inp, L>) -> bool,
  {
    let mut last = None;
    // pop from cache if not matching
    while let Some(tok) = self.cache_mut().pop_front_if(|t| !f(t)) {
      self.set_span_after_consume(tok.token().span().into());
      let (tok, state) = tok.into_components();
      *self.state = state;
      last = Some(tok);
    }

    last
  }

  /// Consumes tokens from cache while the predicate returns `true`.
  ///
  /// Advances the cursor to the end of the last consumed token.
  /// Returns the last consumed token.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn consume_cached_while<F>(&mut self, mut f: F) -> Option<Spanned<L::Token, L::Span>>
  where
    F: FnMut(CachedTokenRefOf<'_, 'inp, L>) -> bool,
  {
    self.consume_cached_to(|t| !f(t))
  }

  /// Consumes all cached tokens.
  ///
  /// Advances the cursor to the end of the last cached token.
  /// Returns the last consumed token.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn consume_all_cached(&mut self) -> Option<Spanned<L::Token, L::Span>> {
    let last = self.cache_mut().pop_back()?;
    self.cache_mut().clear();
    let (tok, extras): (Spanned<L::Token, L::Span>, _) = last.into_components();
    self.set_span_after_consume(tok.span_ref().into());
    *self.state = extras;
    Some(tok)
  }
}

#[cfg(all(test, feature = "logos", feature = "std"))]
mod tests {
  use crate::{ParseContext, input::Input, lexer::LogosLexer};

  #[derive(Debug, Clone, PartialEq, crate::logos::Logos)]
  #[logos(crate = crate::logos, skip r"[ \t\r\n]+")]
  enum Tok {
    #[regex(r"[a-z]+")]
    Word,
    #[regex(r"[0-9]+")]
    Num,
  }

  impl core::fmt::Display for Tok {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
      match self {
        Tok::Word => write!(f, "word"),
        Tok::Num => write!(f, "num"),
      }
    }
  }

  #[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
  enum TokKind {
    Word,
    Num,
  }

  impl core::fmt::Display for TokKind {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
      match self {
        TokKind::Word => write!(f, "word"),
        TokKind::Num => write!(f, "num"),
      }
    }
  }

  impl crate::Token<'_> for Tok {
    type Kind = TokKind;
    type Error = ();
    fn kind(&self) -> TokKind {
      match self {
        Tok::Word => TokKind::Word,
        Tok::Num => TokKind::Num,
      }
    }
    fn is_trivia(&self) -> bool {
      false
    }
  }

  type TestLexer<'a> = LogosLexer<'a, Tok>;

  fn parse_with<'inp, F, O>(src: &'inp str, mut f: F) -> Result<O, ()>
  where
    F: for<'c> FnMut(
      &mut crate::input::InputRef<'inp, 'c, TestLexer<'inp>, (), ()>,
    ) -> Result<O, ()>,
  {
    let (mut emitter, cache) =
      <() as ParseContext<'_, TestLexer<'_>>>::provide(()).into_components();
    let mut input = Input::<TestLexer<'inp>, (), ()>::with_state_and_cache(src, (), cache);
    let mut inp_ref = input.as_ref(&mut emitter);
    f(&mut inp_ref)
  }

  #[test]
  fn consume_cached_one_after_peek() {
    parse_with("abc 123", |inp| {
      use generic_arraydeque::typenum::U2;
      let peeked = inp.peek::<U2>()?;
      drop(peeked);
      let tok = inp.consume_cached_one();
      assert!(tok.is_some());
      let tok = tok.unwrap();
      assert_eq!(tok.data, Tok::Word);
      Ok(())
    })
    .unwrap();
  }

  #[test]
  fn consume_cached_one_empty_cache() {
    parse_with("abc", |inp| {
      let tok = inp.consume_cached_one();
      assert!(tok.is_none());
      Ok(())
    })
    .unwrap();
  }

  #[test]
  fn consume_cached_to_predicate() {
    parse_with("abc 123 def", |inp| {
      use generic_arraydeque::typenum::U3;
      let peeked = inp.peek::<U3>()?;
      drop(peeked);
      let last = inp.consume_cached_to(|t| matches!(t.token().data(), Tok::Num));
      assert!(last.is_some());
      let last = last.unwrap();
      assert_eq!(last.data, Tok::Word);
      Ok(())
    })
    .unwrap();
  }

  #[test]
  fn consume_cached_while_predicate() {
    parse_with("abc 123 def", |inp| {
      use generic_arraydeque::typenum::U3;
      let peeked = inp.peek::<U3>()?;
      drop(peeked);
      let last = inp.consume_cached_while(|t| matches!(t.token().data(), Tok::Word));
      assert!(last.is_some());
      let last = last.unwrap();
      assert_eq!(last.data, Tok::Word);
      Ok(())
    })
    .unwrap();
  }

  #[test]
  fn consume_all_cached() {
    parse_with("abc 123 def", |inp| {
      use generic_arraydeque::typenum::U3;
      let peeked = inp.peek::<U3>()?;
      drop(peeked);
      let last = inp.consume_all_cached();
      assert!(last.is_some());
      let last = last.unwrap();
      assert_eq!(last.data, Tok::Word);
      Ok(())
    })
    .unwrap();
  }

  #[test]
  fn consume_all_cached_empty() {
    parse_with("abc", |inp| {
      let last = inp.consume_all_cached();
      assert!(last.is_none());
      Ok(())
    })
    .unwrap();
  }
}

use generic_arraydeque::typenum::Unsigned;

use super::*;

impl<'inp, L, Ctx, Lang: ?Sized> InputRef<'inp, '_, L, Ctx, Lang>
where
  L: Lexer<'inp>,
  L::State: Clone,
  Ctx: ParseContext<'inp, L, Lang>,
{
  /// Folds over the input tokens using the provided accumulator function.
  pub fn fold<O, Pred, Init, Op>(
    &mut self,
    mut pred: Pred,
    init: Init,
    mut op: Op,
  ) -> Result<O, <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error>
  where
    Init: FnOnce() -> O,
    Op: FnMut(O, Spanned<L::Token, L::Span>) -> O,
    Pred: FnMut(Spanned<&L::Token, &L::Span>) -> bool,
  {
    let mut output = init();

    loop {
      match self.try_expect(&mut pred)? {
        Some(spanned) => {
          output = op(output, spanned);
        }
        None => return Ok(output),
      }
    }
  }

  /// Folds at most n tokens over the input using the provided accumulator function.
  pub fn foldn<O, Init, Op>(
    &mut self,
    init: Init,
    mut op: Op,
    num: usize,
  ) -> Result<O, <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error>
  where
    Init: FnOnce() -> O,
    Op: FnMut(O, Spanned<L::Token, L::Span>) -> O,
  {
    let mut output = init();

    let mut n = 0;

    loop {
      if n >= num {
        return Ok(output);
      }

      match self.next()? {
        Some(spanned) => {
          output = op(output, spanned);
          n += 1;
        }
        None => return Ok(output),
      }
    }
  }

  /// Right-folds over the input tokens using the provided accumulator function.
  ///
  /// The maximum number of tokens folded is determined by the capacity of the specified `W`.
  ///
  /// See also [`foldrn`](Self::foldrn).
  pub fn foldr_within<O, W, Pred, Init, Op>(
    &mut self,
    mut pred: Pred,
    init: Init,
    mut op: Op,
  ) -> Result<O, <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error>
  where
    Init: FnOnce() -> O,
    Op: FnMut(O, Spanned<L::Token, L::Span>) -> O,
    W: Window,
    Pred: FnMut(Spanned<&L::Token, &L::Span>) -> bool,
  {
    let mut output = init();
    let mut buf = GenericArrayDeque::<_, W::CAPACITY>::new();

    loop {
      if buf.len() >= <W::CAPACITY as Unsigned>::USIZE {
        break;
      }

      match self.try_expect(&mut pred)? {
        Some(spanned) => {
          buf.push_back(spanned);
        }
        None => return Ok(output),
      }
    }

    while let Some(spanned) = buf.pop_back() {
      output = op(output, spanned);
    }

    Ok(output)
  }

  /// Right-folds over the input tokens using the provided accumulator function.
  ///
  /// This method folds up to `num` tokens, and this will lead to implicit allocation.
  ///
  /// See also [`foldr_within`](Self::foldr_within).
  #[cfg(any(feature = "std", feature = "alloc"))]
  #[cfg_attr(docsrs, doc(cfg(any(feature = "std", feature = "alloc"))))]
  pub fn foldrn<O, Init, Op>(
    &mut self,
    init: Init,
    mut op: Op,
    num: usize,
  ) -> Result<O, <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error>
  where
    Init: FnOnce() -> O,
    Op: FnMut(O, Spanned<L::Token, L::Span>) -> O,
  {
    let mut output = init();
    let mut buf = std::vec::Vec::with_capacity(num);

    let mut n = 0;
    loop {
      if n >= num {
        break;
      }

      match self.next()? {
        Some(spanned) => {
          buf.push(spanned);
          n += 1;
        }
        None => break,
      }
    }

    while let Some(spanned) = buf.pop() {
      output = op(output, spanned);
    }

    Ok(output)
  }
}

