    }
  }
}

impl<'inp, L, Ctx, Lang: ?Sized>
  ParseInput<'inp, L, Sliced<L::Token, <L::Source as Source<L::Offset>>::Slice<'inp>>, Ctx, Lang>
  for With<Any<L, Ctx, Lang>, PhantomSliced>
where
