/// A reference wrapper.
#[repr(transparent)]
pub struct ByRef<T: ?Sized>(T);

impl<T: ?Sized> core::ops::Deref for ByRef<T> {
  type Target = T;

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn deref(&self) -> &Self::Target {
    self.inner()
  }
}

impl<T: ?Sized> core::ops::DerefMut for ByRef<T> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn deref_mut(&mut self) -> &mut Self::Target {
    self.inner_mut()
  }
}

impl<'a, T: ?Sized> ByRef<T> {
  /// Create a new reference check wrapper.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub(crate) const fn from_ref(target: &'a T) -> &'a Self {
    // SAFETY: This is safe because `ByRef` is `repr(transparent)` over `T`.
    unsafe { &*(target as *const T as *const Self) }
  }

  /// Create a new mutable reference check wrapper.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub(crate) const fn from_ref_mut(target: &'a mut T) -> &'a mut Self {
    // SAFETY: This is safe because `ByRef` is `repr(transparent)` over `T`.
    unsafe { &mut *(target as *mut T as *mut Self) }
  }

  /// Returns the inner reference.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn inner(&self) -> &T {
    &self.0
  }

  /// Returns the inner mutable reference.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn inner_mut(&mut self) -> &mut T {
    &mut self.0
  }
}

use core::marker::PhantomData;

/// A parser that collects results into a container.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub struct Collect<P, Container, Ctx, Lang: ?Sized = ()> {
  pub(crate) parser: P,
  pub(crate) container: Container,
  pub(crate) _ctx: PhantomData<Ctx>,
  pub(crate) _lang: PhantomData<Lang>,
}

impl<P, Container, Ctx, Lang: ?Sized> Collect<P, Container, Ctx, Lang> {
  /// Creates a new `Collect` combinator.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn new(parser: P, container: Container) -> Self {
    Self {
      parser,
      container,
      _ctx: PhantomData,
      _lang: PhantomData,
    }
  }

  /// Creates a mutable reference version of this `Collect` combinator.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn as_mut(&mut self) -> Collect<&mut P, &mut Container, Ctx, Lang> {
    Collect {
      parser: &mut self.parser,
      container: &mut self.container,
      _ctx: PhantomData,
      _lang: PhantomData,
    }
  }

  /// Maps the inner parser to a new parser.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn map_parser<F, P2>(self, f: F) -> Collect<P2, Container, Ctx, Lang>
  where
    F: FnOnce(P) -> P2,
  {
    Collect {
      parser: f(self.parser),
      container: self.container,
      _ctx: PhantomData,
      _lang: PhantomData,
    }
  }

  /// Returns mutable references to the inner parser and container.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn parts_mut(&mut self) -> (&mut P, &mut Container) {
    (&mut self.parser, &mut self.container)
  }

  /// Maps the inner container to a new container.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn map_container<F, C2>(self, f: F) -> Collect<P, C2, Ctx, Lang>
  where
    F: FnOnce(Container) -> C2,
  {
    Collect {
      parser: self.parser,
      container: f(self.container),
      _ctx: PhantomData,
      _lang: PhantomData,
    }
  }
}

use super::*;

/// A parser that always succeeds without consuming input, returning `()`.
///
/// This parser is the identity element for parser sequencing - it does nothing,
/// consumes nothing, and always succeeds immediately. It's useful for:
/// - **Default values**: Optional parsers that default to doing nothing
/// - **Conditional logic**: Placeholder in choice combinators
/// - **Testing**: Minimal parser for test scaffolding
///
/// # Examples
///
/// ## Placeholder in Choices
///
/// ```ignore
/// // Parse statement: either a let-binding or nothing
/// let parser = peek_then_choice((
///     parse_let_stmt(),
///     empty().map(|_| Statement::Empty),
/// ));
/// ```
///
/// ## Default Behavior
///
/// ```ignore
/// // Conditional parsing
/// let parser = if needs_prefix {
///     parse_prefix().map(Some)
/// } else {
///     empty().map(|_| None)
/// };
/// ```
///
/// ## Testing
///
/// ```ignore
/// // Minimal parser for testing combinators
/// #[test]
/// fn test_map_combinator() {
///     let parser = empty().map(|_| 42);
///     assert_eq!(parser.parse(""), Ok(42));
/// }
/// ```
///
/// # When to Use
///
/// - **Defaults**: When an optional parser should default to no-op
/// - **Type matching**: When you need a parser that returns `()` for sequencing
/// - **Placeholders**: In development before implementing the real parser
///
/// **Don't use** when you actually want to fail - use a parser that returns an error instead.
///
/// # Performance
///
/// - **Memory**: Zero-sized type
/// - **Runtime**: O(1) - instant success, no input consumption
///
/// # See Also
///
/// - [`Todo`] - Placeholder that panics (for unimplemented parsers)
/// - [`map`](crate::parser::ParseInput::map) - Transform `()` to other types
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, Hash)]
pub struct Empty(());

impl Empty {
  /// Creates a parser that always succeeds without consuming any input.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn new() -> Self {
    Self(())
  }
}

impl<'inp, L, Ctx, Lang> ParseInput<'inp, L, (), Ctx, Lang> for Empty
where
  L: Lexer<'inp>,
  Ctx: ParseContext<'inp, L, Lang>,
  Lang: ?Sized,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn parse_input(
    &mut self,
    _inp: &mut InputRef<'inp, '_, L, Ctx, Lang>,
  ) -> Result<(), <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error>
  where
    L: Lexer<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
  {
    Ok(())
  }
}

