/// A parser that repeatedly applies another parser, buffers outputs, and folds them in reverse
/// order while a condition is met.
#[derive(Debug, Clone, Copy)]
pub struct RFoldWhile<P, Condition, Init, Acc, L, O, W, Ctx, Lang: ?Sized = ()> {
  parser: P,
  condition: Condition,
  init: Init,
  acc: Acc,
  _output: PhantomData<O>,
  _window: PhantomData<W>,
  _l: PhantomData<L>,
  _ctx: PhantomData<Ctx>,
  _lang: PhantomData<Lang>,
}

impl<P, Condition, Init, Acc, O, W, L, Ctx, Lang: ?Sized>
  RFoldWhile<P, Condition, Init, Acc, L, O, W, Ctx, Lang>
{
  /// Creates a new `RFoldWhile` parser combinator.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub(crate) fn new(parser: P, condition: Condition, init: Init, acc: Acc) -> Self {
    Self {
      parser,
      condition,
      init,
      acc,
      _output: PhantomData,
      _window: PhantomData,
      _l: PhantomData,
      _ctx: PhantomData,
      _lang: PhantomData,
    }
  }
}

impl<'inp, P, Condition, Init, Acc, O, W, L, Ctx, Lang> ParseInput<'inp, L, O, Ctx, Lang>
  for RFoldWhile<P, Condition, Init, Acc, L, O, W, Ctx, Lang>
where
  P: ParseInput<'inp, L, O, Ctx, Lang>,
  Condition: Decision<'inp, L, Ctx::Emitter, W, Lang>,
  L: Lexer<'inp>,
  Ctx: ParseContext<'inp, L, Lang>,
  Lang: ?Sized,
  Init: FnMut() -> O,
  Acc: FnMut(O, O) -> O,
  W: Window,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn parse_input(
    &mut self,
    inp: &mut InputRef<'inp, '_, L, Ctx, Lang>,
  ) -> Result<O, <<Ctx>::Emitter as Emitter<'inp, L, Lang>>::Error>
  where
    L: Lexer<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
  {
    let mut buf = std::vec::Vec::new();

    loop {
      let (peeked, emitter) = inp.peek_with_emitter::<W>()?;
      match self.condition.decide(peeked, emitter)? {
        Action::Stop => break,
        Action::Continue => {
          buf.push(self.parser.parse_input(inp)?);
        }
      }
    }

    let output = buf.into_iter().rfold((self.init)(), &mut self.acc);
    Ok(output)
  }
}

use crate::{
  error::UnexpectedEot, token::IdentifierToken, try_parse_input::ParseAttempt, types::Ident,
};

use super::*;

impl Ident<(), ()> {
  /// A parser that parses a token and returns an `Ident` instance if it matches.
  ///
  /// If the function returns `Ok(ParseAttempt::Decline)`, it means the next token is not an identifier,
  /// and promises no valid token is consumed.
  pub fn try_parse<'inp, L, Ctx>(
    inp: &mut InputRef<'inp, '_, L, Ctx>,
  ) -> Result<
    ParseAttempt<Ident<<L::Source as Source<L::Offset>>::Slice<'inp>, L::Span>>,
    <Ctx::Emitter as Emitter<'inp, L>>::Error,
  >
  where
    L: Lexer<'inp>,
    L::Token: IdentifierToken<'inp>,
    Ctx: ParseContext<'inp, L>,
    <Ctx::Emitter as Emitter<'inp, L>>::Error: From<UnexpectedEot<L::Offset>>,
  {
    Self::try_parse_of(inp)
  }

  /// A parser that parses a token and returns an `Ident` instance if it matches for a specific language.
  ///
  /// If the function returns `Ok(ParseAttempt::Decline)`, it means the next token is not an identifier,
  /// and promises no valid token is consumed.
  pub fn try_parse_of<'inp, L, Ctx, Lang: ?Sized>(
    inp: &mut InputRef<'inp, '_, L, Ctx, Lang>,
  ) -> Result<
    ParseAttempt<Ident<<L::Source as Source<L::Offset>>::Slice<'inp>, L::Span, Lang>>,
    <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error,
  >
  where
    L: Lexer<'inp>,
    L::Token: IdentifierToken<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
    <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error: From<UnexpectedEot<L::Offset, Lang>>,
  {
    inp.try_expect(|t| t.data.is_identifier()).map(|res| {
      res
        .map(|tok| Ident::new(tok.into_span(), inp.slice()))
        .into()
    })
  }
}

use super::*;

/// A parser that runs another parser but discards its output, returning `()`.
///
/// This combinator executes a parser for its **side effects** (consuming tokens, emitting
/// errors, advancing position) while throwing away the parsed value. It's primarily used
/// via the convenient `.ignore()`, `.then_ignore()`, and `.ignore_then()` methods.
///
/// # Type Parameters
///
/// - `P`: The inner parser whose output will be ignored
/// - `O`: The original output type (discarded)
/// - `L`: Lexer type
/// - `Ctx`: Parse context
/// - `Lang`: Language marker type (default `()`)
///
/// # Examples
///
/// ## Ignore Separators
///
/// ```ignore
/// use tokit::parser::ParseInput;
///
/// // Parse number, comma, number - keep only numbers
/// let parser = parse_number()
///     .then_ignore(parse_comma())  // Uses Ignore internally
///     .then(parse_number());
///
/// // Input: "1, 2"  → Ok((1, 2))
/// // The comma is parsed but discarded
/// ```
///
/// ## Ignore Delimiters
///
/// ```ignore
/// // Parse parenthesized expression: (expr)
/// let parser = parse_lparen()
///     .ignore_then(parse_expression())  // Uses Ignore internally
///     .then_ignore(parse_rparen());
///
/// // Input: "(foo + bar)"  → Ok(Expression)
/// // Parentheses are parsed but discarded
/// ```
///
/// ## Explicit Ignore
///
/// ```ignore
/// // Explicitly ignore a parser's output
/// let parser = parse_comment()
///     .ignore()
///     .then(parse_statement());
///
/// // Equivalent to:
/// let parser = parse_comment()
///     .map(|_| ())
///     .then(parse_statement());
/// ```
///
/// ## Multiple Ignored Parsers
///
/// ```ignore
/// // Parse: fn name(args) { ... }
/// //        ^^ ignore  ^ ignore
/// let parser = parse_fn_keyword()
///     .ignore_then(parse_identifier())
///     .then_ignore(parse_lparen())
///     .then(parse_args())
///     .then_ignore(parse_rparen())
///     .then_ignore(parse_block());
///
/// // Returns just: (name, args)
/// ```
///
/// # When to Use
///
/// - **Separators**: Commas, semicolons between elements
/// - **Delimiters**: Parentheses, brackets, braces around content
/// - **Keywords**: Reserved words that mark structure but aren't data
/// - **Whitespace**: Explicit whitespace handling (though `.padded()` is usually better)
///
/// **Prefer**:
/// - `.then_ignore(p)` over `.then(p).map(|(a, _)| a)`
/// - `.ignore_then(p)` over `.then(p).map(|(_, b)| b)`
/// - `.padded()` over manually ignoring whitespace
///
/// # Comparison with Map
///
/// | Combinator | Transformation | Use Case |
/// |------------|---------------|----------|
/// | **Map** | `T -> U` | Transform value to new type |
/// | **Ignore** | `T -> ()` | Discard value, keep side effects |
///
/// `Ignore` is just `map(|_| ())` with a clearer name.
///
/// # Performance
///
/// - **Memory**: O(1) overhead
/// - **Runtime**: Same as the inner parser (just discards the result)
/// - **Zero-cost**: Optimizer typically eliminates the ignored value entirely
///
/// # See Also
///
/// - [`then_ignore`](crate::parser::ParseInput::then_ignore) - Parse then discard second
/// - [`ignore_then`](crate::parser::ParseInput::ignore_then) - Parse then discard first
/// - [`Map`] - Transform output instead of discarding
#[derive(Clone, Debug, PartialEq, Eq, Hash)]
pub struct Ignore<P, O, L, Ctx, Lang: ?Sized = ()> {
  parser: P,
  _output: PhantomData<O>,
  _l: PhantomData<L>,
  _ctx: PhantomData<Ctx>,
  _lang: PhantomData<Lang>,
}

impl<P, O, L, Ctx, Lang: ?Sized> Ignore<P, O, L, Ctx, Lang> {
  /// Creates a parser that ignores any output.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub(crate) const fn new(parser: P) -> Self {
    Self {
      parser,
      _output: PhantomData,
      _l: PhantomData,
      _ctx: PhantomData,
      _lang: PhantomData,
    }
  }
}

impl<'inp, P, L, O, Ctx, Lang> ParseInput<'inp, L, (), Ctx, Lang> for Ignore<P, O, L, Ctx, Lang>
where
  P: ParseInput<'inp, L, O, Ctx, Lang>,
  L: Lexer<'inp>,
  Ctx: ParseContext<'inp, L, Lang>,
  Lang: ?Sized,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn parse_input(
    &mut self,
    inp: &mut InputRef<'inp, '_, L, Ctx, Lang>,
  ) -> Result<(), <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error>
  where
    L: Lexer<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
  {
    self.parser.parse_input(inp).map(|_| ())
  }
}

use crate::{
  TryParseInput, error::UnexpectedEot, token::KeywordToken, try_parse_input::ParseAttempt,
  types::Keyword, utils::cmp::Equivalent,
};

use super::*;

impl Keyword<(), ()> {
  /// A parser that parses a token and returns a `Keyword` instance if it matches.
  ///
  /// If the function returns `Ok(ParseAttempt::Decline)`, it means the next token is not a keyword,
  /// and promises no valid token is consumed.
  pub fn try_parse<'inp, L, Ctx>(
    inp: &mut InputRef<'inp, '_, L, Ctx>,
  ) -> Result<ParseAttempt<Keyword<L::Token, L::Span>>, <Ctx::Emitter as Emitter<'inp, L>>::Error>
  where
    L: Lexer<'inp>,
    L::Token: KeywordToken<'inp>,
    Ctx: ParseContext<'inp, L>,
    <Ctx::Emitter as Emitter<'inp, L>>::Error: From<UnexpectedEot<L::Offset>>,
  {
    Self::try_parse_of(inp)
  }

  /// A parser that parses a token and returns a `Keyword` instance if it matches for a specific language.
  ///
  /// If the function returns `Ok(ParseAttempt::Decline)`, it means the next token is not a keyword,
  /// and promises no valid token is consumed.
  pub fn try_parse_of<'inp, L, Ctx, Lang: ?Sized>(
    inp: &mut InputRef<'inp, '_, L, Ctx, Lang>,
  ) -> Result<
    ParseAttempt<Keyword<L::Token, L::Span, Lang>>,
    <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error,
  >
  where
    L: Lexer<'inp>,
    L::Token: KeywordToken<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
    <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error: From<UnexpectedEot<L::Offset, Lang>>,
  {
    inp
      .try_expect(|t| t.into_data().is_keyword())
      .map(|opt_tok| {
        opt_tok
          .map(|tok| {
            let (span, t) = tok.into_components();
            Keyword::new(span, t)
          })
          .into()
      })
  }

  /// A parser that parses a token and returns a `Keyword` instance if it matches.
  ///
  /// If the function returns `Ok(ParseAttempt::Decline)`, it means the next token is not a keyword,
  /// and promises no valid token is consumed.
  pub fn try_parse_sliced<'inp, L, Ctx>(
    inp: &mut InputRef<'inp, '_, L, Ctx>,
  ) -> Result<
    ParseAttempt<Keyword<<L::Source as Source<L::Offset>>::Slice<'inp>, L::Span>>,
    <Ctx::Emitter as Emitter<'inp, L>>::Error,
  >
  where
    L: Lexer<'inp>,
    L::Token: KeywordToken<'inp>,
    Ctx: ParseContext<'inp, L>,
    <Ctx::Emitter as Emitter<'inp, L>>::Error: From<UnexpectedEot<L::Offset>>,
  {
    Self::try_parse_sliced_of(inp)
  }

  /// A parser that parses a token and returns a `Keyword` instance if it matches for a specific language.
  ///
  /// If the function returns `Ok(ParseAttempt::Decline)`, it means the next token is not a keyword,
  /// and promises no valid token is consumed.
  pub fn try_parse_sliced_of<'inp, L, Ctx, Lang: ?Sized>(
    inp: &mut InputRef<'inp, '_, L, Ctx, Lang>,
  ) -> Result<
    ParseAttempt<Keyword<<L::Source as Source<L::Offset>>::Slice<'inp>, L::Span, Lang>>,
    <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error,
  >
  where
    L: Lexer<'inp>,
    L::Token: KeywordToken<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
    <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error: From<UnexpectedEot<L::Offset, Lang>>,
  {
    inp
      .try_expect(|t| t.into_data().is_keyword())
      .map(|opt_tok| {
        opt_tok
          .map(|tok| Keyword::new(tok.into_span(), inp.slice()))
          .into()
      })
  }

  /// A parser that parses a specific keyword and returns a `Keyword` instance if it matches.
  ///
  /// If the function returns `Ok(ParseAttempt::Decline)`, it means the next token is not the expected keyword,
  /// and promises no valid token is consumed.
  pub fn try_parse_exact<'inp, L, Ctx, Exp>(
    expected: &Exp,
  ) -> impl TryParseInput<'inp, L, Keyword<L::Token, L::Span>, Ctx>
  where
    L: Lexer<'inp>,
    L::Token: KeywordToken<'inp>,
    Ctx: ParseContext<'inp, L>,
    <Ctx::Emitter as Emitter<'inp, L>>::Error: From<UnexpectedEot<L::Offset>>,
    str: Equivalent<Exp>,
  {
    Self::try_parse_exact_of(expected)
  }

  /// A parser that parses a specific keyword and returns a `Keyword` instance if it matches for a specific language.
  ///
  /// If the function returns `Ok(ParseAttempt::Decline)`, it means the next token is not the expected keyword,
  /// and promises no valid token is consumed.
  pub fn try_parse_exact_of<'inp, L, Ctx, Exp, Lang: ?Sized>(
    expected: &Exp,
  ) -> impl TryParseInput<'inp, L, Keyword<L::Token, L::Span, Lang>, Ctx, Lang>
  where
    L: Lexer<'inp>,
    L::Token: KeywordToken<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
    <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error: From<UnexpectedEot<L::Offset, Lang>>,
    str: Equivalent<Exp>,
  {
    move |inp: &mut InputRef<'inp, '_, L, Ctx, Lang>| {
      inp
        .try_expect(|t| {
          t.into_data()
            .keyword()
            .is_some_and(|k| k.equivalent(expected))
        })
        .map(|opt_tok| {
          opt_tok
            .map(|tok| {
              let (span, t) = tok.into_components();
              Keyword::new(span, t)
            })
            .into()
        })
    }
  }

  /// A parser that parses a specific keyword and returns a `Keyword` instance if it matches.
  ///
  /// If the function returns `Ok(ParseAttempt::Decline)`, it means the next token is not the expected keyword,
  /// and promises no valid token is consumed.
  pub fn try_parse_exact_sliced<'inp, L, Ctx, Exp>(
    expected: &Exp,
  ) -> impl TryParseInput<'inp, L, Keyword<<L::Source as Source<L::Offset>>::Slice<'inp>, L::Span>, Ctx>
  where
    L: Lexer<'inp>,
    L::Token: KeywordToken<'inp>,
    Ctx: ParseContext<'inp, L>,
    <Ctx::Emitter as Emitter<'inp, L>>::Error: From<UnexpectedEot<L::Offset>>,
    str: Equivalent<Exp>,
  {
    Self::try_parse_exact_sliced_of(expected)
  }

  /// A parser that parses a specific keyword and returns a `Keyword` instance if it matches for a specific language.
  ///
  /// If the function returns `Ok(ParseAttempt::Decline)`, it means the next token is not the expected keyword,
  /// and promises no valid token is consumed.
  pub fn try_parse_exact_sliced_of<'inp, L, Ctx, Exp, Lang: ?Sized>(
    expected: &Exp,
  ) -> impl TryParseInput<
    'inp,
    L,
    Keyword<<L::Source as Source<L::Offset>>::Slice<'inp>, L::Span, Lang>,
    Ctx,
    Lang,
  >
  where
    L: Lexer<'inp>,
    L::Token: KeywordToken<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
    <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error: From<UnexpectedEot<L::Offset, Lang>>,
    str: Equivalent<Exp>,
  {
    move |inp: &mut InputRef<'inp, '_, L, Ctx, Lang>| {
      inp
        .try_expect(|t| {
          t.into_data()
            .keyword()
            .is_some_and(|k| k.equivalent(expected))
        })
        .map(|opt_tok| {
          opt_tok
            .map(|tok| Keyword::new(tok.into_span(), inp.slice()))
            .into()
        })
    }
  }
}

