#[cfg(test)]
#[cfg(any(feature = "std", feature = "alloc"))]
mod tests {
  use super::*;
  use std::format;

  // --- Maximum tests ---

  #[test]
  fn maximum_new_and_get() {
    let m = Maximum::new(42);
    assert_eq!(m.get(), 42);
  }

  #[test]
  fn maximum_max_constant() {
    assert_eq!(Maximum::MAX.get(), usize::MAX);
  }

  #[test]
  fn maximum_eq() {
    assert_eq!(Maximum::new(10), Maximum::new(10));
    assert_ne!(Maximum::new(10), Maximum::new(20));
  }

  #[test]
  fn maximum_clone_copy() {
    let m = Maximum::new(5);
    let m2 = m;
    let m3 = m.clone();
    assert_eq!(m, m2);
    assert_eq!(m, m3);
  }

  #[test]
  fn maximum_debug() {
    let m = Maximum::new(7);
    let dbg = format!("{:?}", m);
    assert!(dbg.contains("7"));
  }

  #[test]
  #[cfg(feature = "std")]
  fn maximum_hash() {
    use std::collections::HashSet;
    let mut s = HashSet::new();
    s.insert(Maximum::new(1));
    s.insert(Maximum::new(1));
    assert_eq!(s.len(), 1);
    s.insert(Maximum::new(2));
    assert_eq!(s.len(), 2);
  }

