  _l: PhantomData<L>,
  _lang: PhantomData<Lang>,
  _ctx: PhantomData<Ctx>,
}

impl<F, T, O, U, L, Ctx, Lang: ?Sized> Then<F, T, O, U, L, Ctx, Lang> {
  /// Creates a new `Then` combinator.
  #[cfg_attr(not(tarpaulin), inline(always))]
