  /// Map both the span and data to new values.
  #[inline]
  pub fn map<F, G, U, T>(self, f: F, g: G) -> Spanned<U, T>
  where
    F: FnOnce(S) -> T,
    G: FnOnce(D) -> U,
  {
    Spanned {
      span: f(self.span),
      data: g(self.data),
    }
  }
}

