use derive_more::{IsVariant, TryUnwrap, Unwrap};

use crate::{
  input::InputRef,
  parser::{Accepted, ByRef, Fold, Repeated, Separated, TryFold, TryFoldWith},
  punct::*,
  token::PunctuatorToken,
};

#[cfg(any(feature = "alloc", feature = "std"))]
use crate::parser::RFold;

