pub use ParseAttempt::{Accept, Decline};

/// Result type for tentative parsing attempts.
#[derive(Debug, Clone, PartialEq, Eq, IsVariant, TryUnwrap, Unwrap)]
#[unwrap(ref, ref_mut)]
#[try_unwrap(ref, ref_mut)]
pub enum ParseAttempt<O> {
  /// Parser successfully matched and produced a value.
  Accept(O),
  /// Parser declined to match without consuming any valid tokens.
  #[unwrap(ignore)]
  #[try_unwrap(ignore)]
  Decline,
}

impl<O> From<Option<O>> for ParseAttempt<O> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn from(opt: Option<O>) -> Self {
    match opt {
      Some(value) => Self::Accept(value),
      None => Self::Decline,
    }
  }
}

impl<O> From<ParseAttempt<O>> for Option<O> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn from(result: ParseAttempt<O>) -> Self {
    match result {
      ParseAttempt::Accept(value) => Some(value),
      ParseAttempt::Decline => None,
    }
  }
}

impl<O> ParseAttempt<O> {
  /// Converts to a `ParseAttempt` with a reference to the inner value.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn as_ref(&self) -> ParseAttempt<&O> {
    match self {
      Self::Accept(value) => ParseAttempt::Accept(value),
      Self::Decline => ParseAttempt::Decline,
    }
  }

  /// Converts to a `ParseAttempt` with a mutable reference to the inner value.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn as_mut(&mut self) -> ParseAttempt<&mut O> {
    match self {
      Self::Accept(value) => ParseAttempt::Accept(value),
      Self::Decline => ParseAttempt::Decline,
    }
  }

  /// Maps the inner value using the given function.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn map<U, F>(self, f: F) -> ParseAttempt<U>
  where
    F: FnOnce(O) -> U,
  {
    match self {
      Self::Accept(value) => ParseAttempt::Accept(f(value)),
      Self::Decline => ParseAttempt::Decline,
    }
  }

  /// Maps the inner value using the given fallible function.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn and_then<U, F, E>(self, f: F) -> Result<ParseAttempt<U>, E>
  where
    F: FnOnce(O) -> Result<U, E>,
  {
    match self {
      Self::Accept(value) => Ok(ParseAttempt::Accept(f(value)?)),
      Self::Decline => Ok(ParseAttempt::Decline),
    }
  }
}

macro_rules! define_separated_by {
  ($($name:ident),+$(,)?) => {
    paste::paste! {
      $(
        #[doc = "Creates a `Separated` combinator which separates elements by the `" $name:snake "` separator and applies this parser repeatedly."]
        ///
        /// See [`separated`](crate::TryParseInput::separated) for details.
        #[cfg_attr(not(tarpaulin), inline(always))]
        fn [< separated_by_ $name:snake>](
          self,
        ) -> Separated<Self, $name, O, L, Ctx, Lang>
        where
          Self: Sized,
          L: Lexer<'inp>,
          L::Token: PunctuatorToken<'inp>,
          Ctx: ParseContext<'inp, L, Lang>,
        {
          Separated::new(self)
        }
      )*
    }
  };
}

/// Tentative parsing trait for optional token consumption with automatic backtracking.
///
/// Unlike [`ParseInput`] which must produce a value or error, `TryParseInput` allows parsers
/// to inspect the input and decide whether to consume it based on lookahead. If the parser
/// returns `Ok(ParseAttempt::Decline)`, **no valid tokens are consumed** - the input position only advances
/// past any error tokens that were consumed by the emitter.
///
/// **IMPORTANT:**
/// Implicit backtracking may occur when a parser returns `Ok(ParseAttempt::Decline)`.
pub trait TryParseInput<'inp, L, O, Ctx, Lang: ?Sized = ()> {
  /// Attempts to parse `O` from the input without committing.
  ///
  /// **IMPORTANT:**
  ///
  /// Implementations **must** uphold this contract:
  /// - ✅ `Ok(ParseAttempt::Accept(value))` - Parser succeeded, tokens consumed, value produced
  /// - ✅ `Ok(ParseAttempt::Decline)` - Parser declined, **no valid tokens consumed** (error tokens may be consumed by emitter)
  ///   - Backtracking may occur - input position restored to before parse attempt
  /// - ✅ `Err(error)` - Parser encountered an error (may have consumed tokens)
  fn try_parse_input(
    &mut self,
    input: &mut InputRef<'inp, '_, L, Ctx, Lang>,
  ) -> Result<ParseAttempt<O>, <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error>
  where
    L: Lexer<'inp>,
    Ctx: ParseContext<'inp, L, Lang>;

  /// Applies combinator on [`ParseAttempt::Accept`].
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn accepted(self) -> Accepted<Self, L, O, Ctx, Lang>
  where
    Self: Sized,
    L: Lexer<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
  {
    Accepted::new(self)
  }

  /// Create a parser over a mutable reference to this parser.
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn by_ref(&mut self) -> &mut ByRef<Self> {
    ByRef::from_ref_mut(self)
  }

  /// Creates a `Repeated` combinator that applies this parser repeatedly until it signals completion.
  ///
  /// The parser will be called repeatedly until:
  /// - It returns `Ok(ParseAttempt::Decline)` - parser peeked ahead, didn't match (no tokens consumed)
  /// - It returns `Err(e)` - parse error
  ///
  /// ## Key Behavior
  ///
  /// Since this parser implements [`TryParseInput`], when it returns `Ok(ParseAttempt::Decline)`:
  /// - The parser **peeked ahead** and saw tokens it doesn't match
  /// - **No tokens were consumed** - input position unchanged
  /// - Repetition **stops cleanly**
  ///
  /// ## When to Use This
  ///
  /// Use `.repeated()` when:
  /// - You want to parse zero or more occurrences
  /// - The parser can look ahead and decide if it matches
  /// - You want automatic stopping based on parser's lookahead
  ///
  /// ## See Also
  ///
  /// - [`repeated_while`](crate::ParseInput::repeated_while) - When you want to provide explicit stopping condition
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn repeated(self) -> Repeated<Self, O, L, Ctx, Lang>
  where
    Self: Sized,
    L: Lexer<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
  {
    Repeated::new(self)
  }

  /// Creates a `Fold` combinator that accumulates results using the provided initializer and accumulator.
  ///
  /// See also [`try_fold`](TryParseInput::try_fold), [`fold_while`](crate::ParseInput::fold_while), [try_fold_while](crate::ParseInput::try_fold_while).
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fold<Init, Acc>(self, init: Init, acc: Acc) -> Fold<Self, Init, Acc, L, O, Ctx, Lang>
  where
    Self: Sized,
    L: Lexer<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
    Init: FnMut() -> O,
    Acc: FnMut(O, O) -> O,
  {
    Fold::new(self, init, acc)
  }

  /// Creates a `TryFold` combinator that accumulates results using the provided initializer and fallible accumulator.
  ///
  /// See also [`try_fold_with`](Self::try_fold_with), [`fold_while`](crate::ParseInput::fold_while), [try_fold_while](crate::ParseInput::try_fold_while).
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn try_fold<Init, Acc>(self, init: Init, acc: Acc) -> TryFold<Self, Init, Acc, L, O, Ctx, Lang>
  where
    Self: Sized,
    L: Lexer<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
    Init: FnMut() -> O,
    Acc: FnMut(O, O) -> Result<O, <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error>,
  {
    TryFold::new(self, init, acc)
  }

  /// Creates a `TryFoldWith` combinator that accumulates results using the provided initializer,
  /// fallible accumulator, and parsing state.
  ///
  /// See also [`try_fold`](Self::try_fold), [`fold_while`](crate::ParseInput::fold_while), [try_fold_while](crate::ParseInput::try_fold_while).
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn try_fold_with<Init, Acc>(
    self,
    init: Init,
    acc: Acc,
  ) -> TryFoldWith<Self, Init, Acc, L, O, Ctx, Lang>
  where
    Self: Sized,
    L: Lexer<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
    Init: FnMut() -> O,
    Acc: FnMut(
      O,
      O,
      ParseState<'_, 'inp, '_, L, Ctx, Lang>,
    ) -> Result<O, <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error>,
  {
    TryFoldWith::new(self, init, acc)
  }

  /// Creates a `RFold` combinator that accumulates results in reverse order using the provided
  /// initializer and accumulator.
  ///
  /// This buffers all parsed outputs before folding them from right to left.
  /// Parsing stops when this parser returns `Ok(ParseAttempt::Decline)`.
  ///
  /// See also [`fold`](Self::fold).
  #[cfg(any(feature = "alloc", feature = "std"))]
  #[cfg_attr(docsrs, doc(cfg(any(feature = "alloc", feature = "std"))))]
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn rfold<Init, Acc>(self, init: Init, acc: Acc) -> RFold<Self, Init, Acc, L, O, Ctx, Lang>
  where
    Self: Sized,
    L: Lexer<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
    Init: FnMut() -> O,
    Acc: FnMut(O, O) -> O,
  {
    RFold::new(self, init, acc)
  }

  /// Creates a `Separated` combinator that parses separated elements, where **this parser
  /// handles the lookahead**.
  ///
  /// This parser (the element parser) will be called repeatedly to parse elements separated
  /// by the given separator. Since this parser implements [`TryParseInput`], it can peek ahead
  /// and return `Ok(ParseAttempt::Decline)` when it doesn't match, **without consuming any tokens**.
  ///
  /// ## Key Behavior
  ///
  /// The combinator stops when this element parser returns `Ok(ParseAttempt::Decline)`:
  /// - Parser **peeked ahead** and saw tokens it doesn't match
  /// - **No tokens consumed** - separator or closing delimiter left in input
  /// - Parsing **stops cleanly**
  ///
  /// ## When to Use This
  ///
  /// Use `.separated()` when:
  /// - Your element parser has built-in lookahead (implements `TryParseInput`)
  /// - You want the element parser to decide when to stop
  /// - The parser returns `Ok(ParseAttempt::Decline)` for non-matching tokens
  ///
  /// ## See Also
  ///
  /// - [`separated_while`](crate::ParseInput::separated_while) - When you want to provide the lookahead/stopping logic externally
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn separated<Sep>(self) -> Separated<Self, Sep, O, L, Ctx, Lang>
  where
    Self: Sized,
    L: Lexer<'inp>,
    Ctx: ParseContext<'inp, L, Lang>,
    Sep: Punctuator<'inp, L, Lang>,
  {
    Separated::new(self)
  }

  define_separated_by!(
    Comma,
    Semicolon,
    Dot,
    Colon,
    Pipe,
    Ampersand,
    Hyphen,
    Underscore,
    DoubleColon,
    Arrow,
    FatArrow,
    Tilde,
    Slash,
    Backslash,
    Percent,
    Dollar,
    Hash,
    At,
  );
}

impl<'inp, L, F, O, Ctx, Lang: ?Sized> TryParseInput<'inp, L, O, Ctx, Lang> for F
where
  F: FnMut(
    &mut InputRef<'inp, '_, L, Ctx, Lang>,
  ) -> Result<ParseAttempt<O>, <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error>,
  L: Lexer<'inp>,
  Ctx: ParseContext<'inp, L, Lang>,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn try_parse_input(
    &mut self,
    input: &mut InputRef<'inp, '_, L, Ctx, Lang>,
  ) -> Result<ParseAttempt<O>, <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error> {
    (self)(input)
  }
}

impl<'inp, L, F, O, Ctx, Lang: ?Sized> TryParseInput<'inp, L, O, Ctx, Lang> for &mut ByRef<F>
where
  F: TryParseInput<'inp, L, O, Ctx, Lang>,
  L: Lexer<'inp>,
  Ctx: ParseContext<'inp, L, Lang>,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn try_parse_input(
    &mut self,
    input: &mut InputRef<'inp, '_, L, Ctx, Lang>,
  ) -> Result<ParseAttempt<O>, <Ctx::Emitter as Emitter<'inp, L, Lang>>::Error> {
    (**self).try_parse_input(input)
  }
}

#[cfg(test)]
#[cfg(any(feature = "std", feature = "alloc"))]
mod tests {
  use super::*;

  use std::format;

  // --- ParseAttempt tests ---

  #[test]
  fn accept_is_accepted() {
    let pa = Accept(42);
    assert!(pa.is_accept());
    assert!(!pa.is_decline());
  }

  #[test]
  fn decline_is_declined() {
    let pa: ParseAttempt<i32> = Decline;
    assert!(!pa.is_accept());
    assert!(pa.is_decline());
  }

  #[test]
  fn accept_map() {
    let pa = Accept(10);
    let mapped = pa.map(|v| v + 1);
    assert_eq!(mapped, Accept(11));
  }

  #[test]
  fn decline_map() {
    let pa: ParseAttempt<i32> = Decline;
    let mapped = pa.map(|v: i32| v + 1);
    assert_eq!(mapped, Decline);
  }

  #[test]
  fn accept_as_ref() {
    let pa = Accept(42);
    let r = pa.as_ref();
    assert_eq!(r, Accept(&42));
  }

  #[test]
  fn decline_as_ref() {
    let pa: ParseAttempt<i32> = Decline;
    let r = pa.as_ref();
    assert!(r.is_decline());
  }

  #[test]
  fn accept_as_mut() {
    let mut pa = Accept(42);
    let r = pa.as_mut();
    assert!(r.is_accept());
  }

  #[test]
  fn decline_as_mut() {
    let mut pa: ParseAttempt<i32> = Decline;
    let r = pa.as_mut();
    assert!(r.is_decline());
  }

  #[test]
  fn accept_and_then_ok() {
    let pa = Accept(10);
    let result: Result<ParseAttempt<i32>, &str> = pa.and_then(|v| Ok(v + 1));
    assert_eq!(result, Ok(Accept(11)));
  }

  #[test]
  fn accept_and_then_err() {
    let pa = Accept(10);
    let result: Result<ParseAttempt<i32>, &str> = pa.and_then(|_| Err("fail"));
    assert_eq!(result, Err("fail"));
  }

  #[test]
  fn decline_and_then() {
    let pa: ParseAttempt<i32> = Decline;
    let result: Result<ParseAttempt<i32>, &str> = pa.and_then(|v| Ok(v + 1));
    assert_eq!(result, Ok(Decline));
  }

  // --- From/Into conversions ---

  #[test]
  fn from_some_to_accept() {
    let pa: ParseAttempt<i32> = Some(42).into();
    assert_eq!(pa, Accept(42));
  }

  #[test]
  fn from_none_to_decline() {
    let pa: ParseAttempt<i32> = None.into();
    assert_eq!(pa, Decline);
  }

  #[test]
  fn accept_into_some() {
    let opt: Option<i32> = Accept(42).into();
    assert_eq!(opt, Some(42));
  }

  #[test]
  fn decline_into_none() {
    let opt: Option<i32> = Decline.into();
    assert_eq!(opt, None);
  }

  // --- Derived methods ---

  #[test]
  fn accept_unwrap() {
    let pa = Accept(42);
    assert_eq!(pa.unwrap_accept_ref(), &42);
  }

  #[test]
  fn accept_try_unwrap() {
    let pa = Accept(42);
    assert_eq!(pa.try_unwrap_accept_ref(), Ok(&42));
  }

  #[test]
  fn decline_try_unwrap() {
    let pa: ParseAttempt<i32> = Decline;
    assert!(pa.try_unwrap_accept_ref().is_err());
  }

  #[test]
  fn accept_clone_eq() {
    let pa = Accept(42);
    let cloned = pa.clone();
    assert_eq!(pa, cloned);
  }

  #[test]
  fn decline_clone_eq() {
    let pa: ParseAttempt<i32> = Decline;
    let cloned = pa.clone();
    assert_eq!(pa, cloned);
  }

  #[test]
  fn accept_debug() {
    let pa = Accept(42);
    let dbg = format!("{:?}", pa);
    assert!(dbg.contains("Accept"));
    assert!(dbg.contains("42"));
  }

  #[test]
  fn decline_debug() {
    let pa: ParseAttempt<i32> = Decline;
    let dbg = format!("{:?}", pa);
    assert!(dbg.contains("Decline"));
  }
}

//! Identifier types for language syntax trees.
//!
//! This module provides generic identifier types that can be used across different
//! programming languages and string representations. Identifiers are fundamental
//! building blocks in most languages, representing names for variables, functions,
//! types, and other named entities.
//!
//! # Design Philosophy
//!
//! The [`Ident`] type is generic over both the source string type (`S`) and the
//! language marker (`Lang`). This design provides maximum flexibility:
//!
//! - **String type flexibility**: Use `&str` for zero-copy parsing, `String` for
//!   owned data, or custom interned string types for memory efficiency
//! - **Language safety**: The `Lang` parameter ensures identifiers from different
//!   languages don't mix accidentally
//! - **SimpleSpan tracking**: All identifiers carry their source location for diagnostics
//!
//! # Common Usage Patterns
//!
//! ## Zero-Copy Parsing
//!
//! ```rust,ignore
//! use tokit::{SimpleSpan, types::Ident};
//!
//! // Parse identifiers without allocating
//! type YulIdent<'a> = Ident<&'a str, SimpleSpan, YulLang>;
//!
//! let ident = YulIdent::new(SimpleSpan::new(0, 3), "foo");
//! assert_eq!(ident.source_ref(), &"foo");
//! ```
//!
//! ## Owned Identifiers
//!
//! ```rust,ignore
//! // Store identifiers in AST nodes that outlive the source
//! type OwnedIdent = Ident<String, SimpleSpan, MyLang>;
//!
//! let ident = OwnedIdent::new(span, source_str.to_string());
//! ```
//!
//! ## String Interning
//!
//! ```rust,ignore
//! // Use interned strings for memory efficiency
//! type InternedIdent = Ident<Symbol, SimpleSpan, MyLang>;
//!
//! let ident = InternedIdent::new(span, interner.intern("identifier"));
//! ```
//!
//! # Error Recovery
//!
//! `Ident` implements [`ErrorNode`] when the source type `S` also implements it,
//! allowing creation of placeholder identifiers during error recovery:
//!
//! ```rust,ignore
//! use tokit::error::ErrorNode;
//!
//! // Create placeholder for malformed identifier
//! let bad_ident = Ident::<String, SimpleSpan, YulLang>::error(span);
//!
//! // Create placeholder for missing identifier
//! let missing_ident = Ident::<String, SimpleSpan, YulLang>::missing(span);
//! ```

use core::marker::PhantomData;

use crate::{
  error::ErrorNode,
  span::{AsSpan, SimpleSpan},
  utils::IntoComponents,
};

#[derive(Debug, Copy, Clone, PartialEq, Eq, Hash)]
#[repr(u8)]
#[non_exhaustive]
enum Status {
  Valid,
  Error,
  Missing,
}

/// A language identifier with span tracking.
///
/// Identifiers are names used in source code to refer to variables, functions,
/// types, and other named entities. This type wraps a source string representation
/// with position information and a language marker.
///
/// # Type Parameters
///
/// - `S`: The source string type (`&str`, `String`, interned string, etc.)
/// - `Lang`: Language marker type for type safety (e.g., `YulLang`, `SolidityLang`)
///
/// # Design Notes
///
/// ## Why Generic Over String Type?
///
/// Different use cases require different string representations:
/// - **Parsing**: Use `&str` for zero-copy efficiency
/// - **AST storage**: Use `String` when the AST outlives the source
/// - **Large codebases**: Use interned strings to deduplicate common identifiers
///
/// ## Why Language Marker?
///
/// The `Lang` parameter prevents mixing identifiers from different languages:
/// ```rust,ignore
/// let yul_ident: Ident<&str, SimpleSpan, YulLang> = ...;
/// let sol_ident: Ident<&str, SimpleSpan, SolidityLang> = ...;
///
/// // Compile error: type mismatch
/// // let mixed = vec![yul_ident, sol_ident];
/// ```
///
/// # Examples
///
/// ## Creating Identifiers
///
/// ```rust
/// use tokit::{SimpleSpan, types::Ident};
/// # struct MyLang;
///
/// // Zero-copy identifier
/// let span = SimpleSpan::new(5, 11);
/// let ident = Ident::<&str, SimpleSpan, MyLang>::new(span, "my_var");
///
/// assert_eq!(ident.span(), span);
/// assert_eq!(ident.source_ref(), &"my_var");
/// ```
///
/// ## Extracting Components
///
/// ```rust
/// # use tokit::{SimpleSpan, types::Ident, utils::IntoComponents};
/// # struct MyLang;
/// # let span = SimpleSpan::new(0, 3);
/// let ident = Ident::<&str, SimpleSpan, MyLang>::new(span, "foo");
///
/// // Destructure into span and source
/// let (span, source) = ident.into_components();
/// assert_eq!(source, "foo");
/// ```
///
/// ## Mutable Access
///
/// ```rust
/// # use tokit::{SimpleSpan, types::Ident};
/// # struct MyLang;
/// # let span = SimpleSpan::new(0, 3);
/// let mut ident = Ident::<String, SimpleSpan, MyLang>::new(span, "original".to_string());
///
/// // Update the source string
/// *ident.source_mut() = "modified".to_string();
/// assert_eq!(ident.source_ref(), "modified");
///
/// // Update the span
/// *ident.span_mut() = SimpleSpan::new(10, 18);
/// assert_eq!(ident.span(), SimpleSpan::new(10, 18));
/// ```
#[derive(Debug, Copy, Clone, PartialEq, Eq, Hash)]
pub struct Ident<S, Span = SimpleSpan, Lang: ?Sized = ()> {
  span: Span,
  ident: S,
  status: Status,
  _lang: PhantomData<Lang>,
}

impl<S, Span, Lang: ?Sized> AsSpan<Span> for Ident<S, Span, Lang> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn as_span(&self) -> &Span {
    self.span_ref()
  }
}

impl<S, Span, Lang: ?Sized> IntoComponents for Ident<S, Span, Lang> {
  type Components = (Span, S);

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn into_components(self) -> Self::Components {
    (self.span, self.ident)
  }
}

impl<S, Span, Lang: ?Sized> Ident<S, Span, Lang> {
  /// Creates a new identifier with the given span and source string.
  ///
  /// # Parameters
  ///
  /// - `span`: The source location of this identifier
  /// - `source`: The identifier string (can be `&str`, `String`, or custom type)
  ///
  /// # Examples
  ///
  /// ```rust
  /// use tokit::types::Ident;
  /// use tokit::SimpleSpan;
  /// # struct YulLang;
  ///
  /// let span = SimpleSpan::new(10, 15);
  /// let ident = Ident::<&str, SimpleSpan, YulLang>::new(span, "count");
  ///
  /// assert_eq!(ident.span(), span);
  /// assert_eq!(ident.source_ref(), &"count");
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn new(span: Span, source: S) -> Self {
    Self::with_status(span, source, Status::Valid)
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  const fn with_status(span: Span, source: S, status: Status) -> Self {
    Self {
      span,
      ident: source,
      status,
      _lang: PhantomData,
    }
  }

  /// Returns the span (source location) of this identifier.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Ident;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let ident = Ident::<&str, SimpleSpan, MyLang>::new(SimpleSpan::new(5, 10), "value");
  ///
  /// assert_eq!(ident.span(), SimpleSpan::new(5, 10));
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span(&self) -> Span
  where
    Span: Copy,
  {
    self.span
  }

  /// Returns an immutable reference to the span.
  ///
  /// Use this when you need to borrow the span without copying it.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Ident;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let ident = Ident::<&str, SimpleSpan, MyLang>::new(SimpleSpan::new(0, 3), "foo");
  ///
  /// let span_ref = ident.span_ref();
  /// assert_eq!(*span_ref, SimpleSpan::new(0, 3));
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span_ref(&self) -> &Span {
    &self.span
  }

  /// Returns a mutable reference to the span.
  ///
  /// Use this to update the identifier's source location, for example during
  /// AST transformations or span adjustments.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Ident;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let mut ident = Ident::<&str, SimpleSpan, MyLang>::new(SimpleSpan::new(0, 3), "foo");
  ///
  /// *ident.span_mut() = SimpleSpan::new(10, 13);
  /// assert_eq!(ident.span(), SimpleSpan::new(10, 13));
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span_mut(&mut self) -> &mut Span {
    &mut self.span
  }

  /// Bumps the span of the identifier by the given offset.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn bump(&mut self, by: &Span::Offset) -> &mut Self
  where
    Span: crate::span::Span,
  {
    self.span.bump(by);
    self
  }

  /// Returns a mutable reference to the source string.
  ///
  /// Use this to modify the identifier's text, for example during AST
  /// transformations or name mangling.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Ident;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let mut ident = Ident::<String, SimpleSpan, MyLang>::new(SimpleSpan::new(0, 3), "foo".to_string());
  ///
  /// *ident.source_mut() = "bar".to_string();
  /// assert_eq!(ident.source_ref(), "bar");
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn source_mut(&mut self) -> &mut S {
    &mut self.ident
  }

  /// Returns an immutable reference to the source string.
  ///
  /// This is the most common way to access the identifier's text without
  /// consuming or copying it.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Ident;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let ident = Ident::<&str, SimpleSpan, MyLang>::new(SimpleSpan::new(0, 8), "variable");
  ///
  /// assert_eq!(ident.source_ref(), &"variable");
  /// assert_eq!(ident.source_ref().len(), 8);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn source_ref(&self) -> &S {
    &self.ident
  }

  /// Returns a copy of the source string by value.
  ///
  /// This method is only available when the source type `S` implements [`Copy`].
  /// Useful for types like `&str` or interned string handles.
  ///
  /// For owned types like `String`, use [`source_ref`](Self::source_ref) to
  /// avoid cloning, or consume the identifier with
  /// [`into_components`](crate::utils::IntoComponents::into_components).
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Ident;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let ident = Ident::<&str, SimpleSpan, MyLang>::new(SimpleSpan::new(0, 2), "id");
  ///
  /// let source: &str = ident.source(); // Copy
  /// assert_eq!(source, "id");
  /// // ident is still usable
  /// assert_eq!(ident.source_ref(), &"id");
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn source(&self) -> S
  where
    S: Copy,
  {
    self.ident
  }

  /// Returns `true` is this identifier represents an error identifier.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn is_error(&self) -> bool {
    matches!(self.status, Status::Error)
  }

  /// Returns `true` is this identifier represents a missing identifier.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn is_missing(&self) -> bool {
    matches!(self.status, Status::Missing)
  }

  /// Returns `true` is this identifier is valid (not error or missing).
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn is_valid(&self) -> bool {
    matches!(self.status, Status::Valid)
  }

  /// Maps the source string to a new type, preserving the span and language.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn map<U>(self, f: impl FnOnce(S) -> U) -> Ident<U, Span, Lang> {
    Ident::new(self.span, f(self.ident))
  }
}

impl<S, Span, Lang> ErrorNode<Span> for Ident<S, Span, Lang>
where
  S: ErrorNode<Span>,
  Span: Clone,
{
  /// Creates a placeholder identifier for **malformed content**.
  ///
  /// Used during error recovery when the parser encounters invalid identifier
  /// syntax. The source string `S` will also be created as an error placeholder.
  ///
  /// # Examples
  ///
  /// ```rust,ignore
  /// use tokit::types::Ident;
  /// use tokit::error::ErrorNode;
  ///
  /// // Parser found "123abc" where an identifier was expected
  /// let bad_ident = Ident::<String, SimpleSpan, YulLang>::error(span);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn error(span: Span) -> Self {
    Self::with_status(span.clone(), S::error(span), Status::Error)
  }

  /// Creates a placeholder identifier for **missing required content**.
  ///
  /// Used during error recovery when the parser expects an identifier but
  /// finds nothing at all. The source string `S` will also be created as
  /// a missing placeholder.
  ///
  /// # Examples
  ///
  /// ```rust,ignore
  /// use tokit::types::Ident;
  /// use tokit::error::ErrorNode;
  ///
  /// // Parser expected identifier after "let" but found "="
  /// // Correct: let name = 5;
  /// // Found:   let = 5;
  /// let missing_ident = Ident::<String, SimpleSpan, YulLang>::missing(span);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn missing(span: Span) -> Self {
    Self::with_status(span.clone(), S::missing(span), Status::Missing)
  }
}

use core::marker::PhantomData;

use crate::{span::AsSpan, types::Ident};

/// A list of identifiers.
#[derive(Debug, Copy, Clone, PartialEq, Eq, Hash)]
#[cfg(any(feature = "alloc", feature = "std"))]
pub struct IdentList<
  S,
  Span = crate::span::SimpleSpan,
  Container = std::vec::Vec<Ident<S, Span>>,
  Lang: ?Sized = (),
> {
  span: Span,
  identifiers: Container,
  _m: PhantomData<S>,
  _lang: PhantomData<Lang>,
}

/// A list of identifiers.
#[derive(Debug, Copy, Clone, PartialEq, Eq, Hash)]
#[cfg(not(any(feature = "alloc", feature = "std")))]
pub struct IdentList<S, Span, Container, Lang: ?Sized = ()> {
  span: Span,
  identifiers: Container,
  _m: PhantomData<S>,
  _lang: PhantomData<Lang>,
}

impl<S, Span, Container, Lang> AsSpan<Span> for IdentList<S, Span, Container, Lang> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn as_span(&self) -> &Span {
    self.span_ref()
  }
}

impl<S, Span, Container, Lang> IdentList<S, Span, Container, Lang> {
  /// Returns `true` if all identifiers in the path are valid.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn is_valid(&self) -> bool
  where
    Container: AsRef<[Ident<S, Span, Lang>]>,
  {
    self.identifiers.as_ref().iter().all(|seg| seg.is_valid())
  }

  /// Returns `true` if any segment in the path is an error node.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn is_error(&self) -> bool
  where
    Container: AsRef<[Ident<S, Span, Lang>]>,
  {
    self.identifiers.as_ref().iter().any(|seg| seg.is_error())
  }

  /// Returns `true` if any segment in the path is a missing node.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn is_missing(&self) -> bool
  where
    Container: AsRef<[Ident<S, Span, Lang>]>,
  {
    self.identifiers.as_ref().iter().any(|seg| seg.is_missing())
  }
}

impl<S, Span, Container, Lang> IdentList<S, Span, Container, Lang> {
  /// Create a new path.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn new(span: Span, identifiers: Container) -> Self {
    Self {
      span,
      identifiers,
      _m: PhantomData,
      _lang: PhantomData,
    }
  }

  /// Get the span of the path.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span(&self) -> Span
  where
    Span: Copy,
  {
    self.span
  }

  /// Get the reference to the span of the path.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span_ref(&self) -> &Span {
    &self.span
  }

  /// Get the mutable reference to the span of the path.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span_mut(&mut self) -> &mut Span {
    &mut self.span
  }

  /// Bump the span of the path by the given offset.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn bump(&mut self, by: &Span::Offset) -> &mut Self
  where
    Span: crate::span::Span,
    Container: AsMut<[Ident<S, Span, Lang>]>,
  {
    self.span.bump(by);
    self.identifiers.as_mut().iter_mut().for_each(|seg| {
      seg.bump(by);
    });
    self
  }

  /// Get the identifiers of the path.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn identifiers(&self) -> &Container {
    &self.identifiers
  }

  /// Returns the slice of the path identifiers.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn identifiers_slice(&self) -> &[Ident<S, Span, Lang>]
  where
    Container: AsRef<[Ident<S, Span, Lang>]>,
  {
    self.identifiers.as_ref()
  }

  /// Returns `true` if the path has no identifiers.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn is_empty(&self) -> bool
  where
    Container: AsRef<[Ident<S, Span, Lang>]>,
  {
    self.identifiers.as_ref().is_empty()
  }
}

//! Keywordifier types for language syntax trees.
//!
//! This module provides generic identifier types that can be used across different
//! programming languages and string representations. Keywordifiers are fundamental
//! building blocks in most languages, representing names for variables, functions,
//! types, and other named entities.
//!
//! # Design Philosophy
//!
//! The [`Keyword`] type is generic over both the source string type (`S`) and the
//! language marker (`Lang`). This design provides maximum flexibility:
//!
//! - **String type flexibility**: Use `&str` for zero-copy parsing, `String` for
//!   owned data, or custom interned string types for memory efficiency
//! - **Language safety**: The `Lang` parameter ensures keywords from different
//!   languages don't mix accidentally
//! - **SimpleSpan tracking**: All keywords carry their source location for diagnostics
//!
//! # Common Usage Patterns
//!
//! ## Zero-Copy Parsing
//!
//! ```rust,ignore
//! use tokit::types::Keyword;
//! use tokit::SimpleSpan;
//!
//! // Parse keywords without allocating
//! type YulKeyword<'a> = Keyword<&'a str, SimpleSpan, YulLang>;
//!
//! let ident = YulKeyword::new(SimpleSpan::new(0, 3), "foo");
//! assert_eq!(ident.source_ref(), &"foo");
//! ```
//!
//! ## Owned Keywordifiers
//!
//! ```rust,ignore
//! // Store keywords in AST nodes that outlive the source
//! type OwnedKeyword = Keyword<String, SimpleSpan, MyLang>;
//!
//! let ident = OwnedKeyword::new(span, source_str.to_string());
//! ```
//!
//! ## String Interning
//!
//! ```rust,ignore
//! // Use interned strings for memory efficiency
//! type InternedKeyword = Keyword<Symbol, MyLang>;
//!
//! let ident = InternedKeyword::new(span, interner.intern("identifier"));
//! ```
//!
//! # Error Recovery
//!
//! `Keyword` implements [`ErrorNode`] when the source type `S` also implements it,
//! allowing creation of placeholder keywords during error recovery:
//!
//! ```rust,ignore
//! use tokit::error::ErrorNode;
//!
//! // Create placeholder for malformed identifier
//! let bad_ident = Keyword::<String, SimpleSpan, YulLang>::error(span);
//!
//! // Create placeholder for missing identifier
//! let missing_ident = Keyword::<String, SimpleSpan, YulLang>::missing(span);
//! ```

use core::marker::PhantomData;

use crate::{
  error::ErrorNode,
  span::{AsSpan, SimpleSpan},
  utils::IntoComponents,
};

/// A language identifier with span tracking.
///
/// Keywordifiers are names used in source code to refer to variables, functions,
/// types, and other named entities. This type wraps a source string representation
/// with position information and a language marker.
///
/// # Type Parameters
///
/// - `S`: The source string type (`&str`, `String`, interned string, etc.)
/// - `Lang`: Language marker type for type safety (e.g., `YulLang`, `SolidityLang`)
///
/// # Design Notes
///
/// ## Why Generic Over String Type?
///
/// Different use cases require different string representations:
/// - **Parsing**: Use `&str` for zero-copy efficiency
/// - **AST storage**: Use `String` when the AST outlives the source
/// - **Large codebases**: Use interned strings to deduplicate common keywords
///
/// ## Why Language Marker?
///
/// The `Lang` parameter prevents mixing keywords from different languages:
/// ```rust,ignore
/// let yul_ident: Keyword<&str, SimpleSpan, YulLang> = ...;
/// let sol_ident: Keyword<&str, SimpleSpan, SolidityLang> = ...;
///
/// // Compile error: type mismatch
/// // let mixed = vec![yul_ident, sol_ident];
/// ```
///
/// # Examples
///
/// ## Creating Keywordifiers
///
/// ```rust
/// use tokit::types::Keyword;
/// use tokit::SimpleSpan;
/// # struct MyLang;
///
/// // Zero-copy identifier
/// let span = SimpleSpan::new(5, 11);
/// let ident = Keyword::<&str, SimpleSpan, MyLang>::new(span, "my_var");
///
/// assert_eq!(ident.span(), span);
/// assert_eq!(ident.source_ref(), &"my_var");
/// ```
///
/// ## Extracting Components
///
/// ```rust
/// # use tokit::types::Keyword;
/// # use tokit::SimpleSpan;
/// # use tokit::utils::IntoComponents;
/// # struct MyLang;
/// # let span = SimpleSpan::new(0, 3);
/// let ident = Keyword::<&str, SimpleSpan, MyLang>::new(span, "foo");
///
/// // Destructure into span and source
/// let (span, source) = ident.into_components();
/// assert_eq!(source, "foo");
/// ```
///
/// ## Mutable Access
///
/// ```rust
/// # use tokit::types::Keyword;
/// # use tokit::SimpleSpan;
/// # struct MyLang;
/// # let span = SimpleSpan::new(0, 3);
/// let mut ident = Keyword::<String, SimpleSpan, MyLang>::new(span, "original".to_string());
///
/// // Update the source string
/// *ident.source_mut() = "modified".to_string();
/// assert_eq!(ident.source_ref(), "modified");
///
/// // Update the span
/// *ident.span_mut() = SimpleSpan::new(10, 18);
/// assert_eq!(ident.span(), SimpleSpan::new(10, 18));
/// ```
#[derive(Debug, Copy, Clone, PartialEq, Eq, Hash)]
pub struct Keyword<S, Span = SimpleSpan, Lang: ?Sized = ()> {
  span: Span,
  ident: S,
  _lang: PhantomData<Lang>,
}

impl<S, Span, Lang: ?Sized> From<Keyword<S, Span, Lang>> for super::Ident<S, Span, Lang> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn from(keyword: Keyword<S, Span, Lang>) -> Self {
    Self::new(keyword.span, keyword.ident)
  }
}

impl<S, Span, Lang: ?Sized> AsSpan<Span> for Keyword<S, Span, Lang> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn as_span(&self) -> &Span {
    self.span_ref()
  }
}

impl<S, Span, Lang: ?Sized> IntoComponents for Keyword<S, Span, Lang> {
  type Components = (Span, S);

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn into_components(self) -> Self::Components {
    (self.span, self.ident)
  }
}

impl<S, Span, Lang: ?Sized> Keyword<S, Span, Lang> {
  /// Creates a new identifier with the given span and source string.
  ///
  /// # Parameters
  ///
  /// - `span`: The source location of this identifier
  /// - `source`: The identifier string (can be `&str`, `String`, or custom type)
  ///
  /// # Examples
  ///
  /// ```rust
  /// use tokit::types::Keyword;
  /// use tokit::SimpleSpan;
  /// # struct YulLang;
  ///
  /// let span = SimpleSpan::new(10, 15);
  /// let ident = Keyword::<&str, SimpleSpan, YulLang>::new(span, "count");
  ///
  /// assert_eq!(ident.span(), span);
  /// assert_eq!(ident.source_ref(), &"count");
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn new(span: Span, source: S) -> Self {
    Self {
      span,
      ident: source,
      _lang: PhantomData,
    }
  }

  /// Returns the span (source location) of this identifier.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Keyword;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let ident = Keyword::<&str, SimpleSpan, MyLang>::new(SimpleSpan::new(5, 10), "value");
  ///
  /// assert_eq!(ident.span(), SimpleSpan::new(5, 10));
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span(&self) -> Span
  where
    Span: Copy,
  {
    self.span
  }

  /// Returns an immutable reference to the span.
  ///
  /// Use this when you need to borrow the span without copying it.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Keyword;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let ident = Keyword::<&str, SimpleSpan, MyLang>::new(SimpleSpan::new(0, 3), "foo");
  ///
  /// let span_ref = ident.span_ref();
  /// assert_eq!(*span_ref, SimpleSpan::new(0, 3));
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span_ref(&self) -> &Span {
    &self.span
  }

  /// Returns a mutable reference to the span.
  ///
  /// Use this to update the identifier's source location, for example during
  /// AST transformations or span adjustments.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Keyword;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let mut ident = Keyword::<&str, SimpleSpan, MyLang>::new(SimpleSpan::new(0, 3), "foo");
  ///
  /// *ident.span_mut() = SimpleSpan::new(10, 13);
  /// assert_eq!(ident.span(), SimpleSpan::new(10, 13));
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn span_mut(&mut self) -> &mut Span {
    &mut self.span
  }

  /// Returns a mutable reference to the source string.
  ///
  /// Use this to modify the identifier's text, for example during AST
  /// transformations or name mangling.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Keyword;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let mut ident = Keyword::<String, SimpleSpan, MyLang>::new(SimpleSpan::new(0, 3), "foo".to_string());
  ///
  /// *ident.source_mut() = "bar".to_string();
  /// assert_eq!(ident.source_ref(), "bar");
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn source_mut(&mut self) -> &mut S {
    &mut self.ident
  }

  /// Returns an immutable reference to the source string.
  ///
  /// This is the most common way to access the identifier's text without
  /// consuming or copying it.
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Keyword;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let ident = Keyword::<&str, SimpleSpan, MyLang>::new(SimpleSpan::new(0, 8), "variable");
  ///
  /// assert_eq!(ident.source_ref(), &"variable");
  /// assert_eq!(ident.source_ref().len(), 8);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn source_ref(&self) -> &S {
    &self.ident
  }

  /// Returns a copy of the source string by value.
  ///
  /// This method is only available when the source type `S` implements [`Copy`].
  /// Useful for types like `&str` or interned string handles.
  ///
  /// For owned types like `String`, use [`source_ref`](Self::source_ref) to
  /// avoid cloning, or consume the identifier with
  /// [`into_components`](crate::utils::IntoComponents::into_components).
  ///
  /// # Examples
  ///
  /// ```rust
  /// # use tokit::types::Keyword;
  /// # use tokit::SimpleSpan;
  /// # struct MyLang;
  /// let ident = Keyword::<&str, SimpleSpan, MyLang>::new(SimpleSpan::new(0, 2), "id");
  ///
  /// let source: &str = ident.source(); // Copy
  /// assert_eq!(source, "id");
  /// // ident is still usable
  /// assert_eq!(ident.source_ref(), &"id");
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn source(&self) -> S
  where
    S: Copy,
  {
    self.ident
  }

  /// Consumes the identifier and returns the span and source string.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn into_components(self) -> (Span, S) {
    (self.span, self.ident)
  }

  /// Maps the source string to a new type, preserving the span and language.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn map<U>(self, f: impl FnOnce(S) -> U) -> Keyword<U, Span, Lang> {
    Keyword::new(self.span, f(self.ident))
  }
}

impl<S, Span, Lang: ?Sized> ErrorNode<Span> for Keyword<S, Span, Lang>
where
  S: ErrorNode<Span>,
  Span: Clone,
{
  /// Creates a placeholder identifier for **malformed content**.
  ///
  /// Used during error recovery when the parser encounters invalid identifier
  /// syntax. The source string `S` will also be created as an error placeholder.
  ///
  /// # Examples
  ///
  /// ```rust,ignore
  /// use tokit::types::Keyword;
  /// use tokit::error::ErrorNode;
  ///
  /// // Parser found "123abc" where an identifier was expected
  /// let bad_ident = Keyword::<String, SimpleSpan, YulLang>::error(span);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn error(span: Span) -> Self {
    Self::new(span.clone(), S::error(span))
  }

  /// Creates a placeholder identifier for **missing required content**.
  ///
  /// Used during error recovery when the parser expects an identifier but
  /// finds nothing at all. The source string `S` will also be created as
  /// a missing placeholder.
  ///
  /// # Examples
  ///
  /// ```rust,ignore
  /// use tokit::types::Keyword;
  /// use tokit::error::ErrorNode;
  ///
  /// // Parser expected identifier after "let" but found "="
  /// // Correct: let name = 5;
  /// // Found:   let = 5;
  /// let missing_ident = Keyword::<String, SimpleSpan, YulLang>::missing(span);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn missing(span: Span) -> Self {
    Self::new(span.clone(), S::missing(span))
  }
}

//! Literal token types for language syntax trees.
//!
//! This module provides generic literal types that represent various kinds of
//! literal values found in programming languages: numbers, strings, booleans, etc.
//! Each literal type carries its source representation along with span information.
//!
//! # Design Philosophy
//!
//! All literal types follow the same pattern as [`Ident`](super::Ident):
//!
//! - **Generic string type `S`**: Support `&str`, `String`, or interned strings
//! - **Language marker `Lang`**: Type-safe language distinction
//! - **Span tracking**: All literals carry source location for diagnostics
//! - **Error recovery**: Implement [`ErrorNode`] for placeholder creation
//!
//! # Available Literal Types
//!
//! ## Generic Literal
//!
//! - [`Lit`]: Generic literal (any literal type)
//!
//! ## Numeric Literals
//!
//! - [`LitDecimal`]: Base-10 integer (e.g., `42`, `1_000`)
//! - [`LitHex`]: Hexadecimal integer (e.g., `0xFF`, `0x1A2B`)
//! - [`LitOctal`]: Octal integer (e.g., `0o77`, `0o644`)
//! - [`LitBinary`]: Binary integer (e.g., `0b1010`, `0b1111_0000`)
//! - [`LitFloat`](crate::types::lit::LitFloat): Floating-point (e.g., `3.14`, `1.0e-5`)
//! - [`LitHexFloat`]: Hexadecimal float (e.g., `0x1.8p3`)
//!
//! ## String Literals
//!
//! - [`LitString`]: Single-line string (e.g., `"hello"`)
//! - [`LitMultilineString`]: Multi-line string (e.g., `"""..."""`)
//! - [`LitRawString`]: Raw string without escape processing (e.g., `r"C:\path"`)
//!
//! ## Character/Byte Literals
//!
//! - [`LitChar`]: Character literal (e.g., `'a'`, `'\n'`)
//! - [`LitByte`]: Byte literal (e.g., `b'a'`, `b'\x7F'`)
//! - [`LitByteString`]: Byte string (e.g., `b"bytes"`)
//!
//! ## Boolean and Null
//!
//! - [`LitBool`]: Boolean literal (`true`/`false`)
//! - [`LitNull`]: Null/nil literal
//!
//! # Common Usage Patterns
//!
//! ## Zero-Copy Parsing
//!
//! ```rust,ignore
//! use tokit::types::{Lit, LitDecimal, LitString};
//! use tokit::SimpleSpan;
//!
//! // Parse literals without allocating
//! type YulLit<'a> = Lit<&'a str, SimpleSpan, YulLang>;
//! type YulDecimal<'a> = LitDecimal<&'a str, SimpleSpan, YulLang>;
//! type YulString<'a> = LitString<&'a str, SimpleSpan, YulLang>;
//!
//! let generic = YulLit::new(SimpleSpan::new(0, 2), "42");
//! let num = YulDecimal::new(SimpleSpan::new(0, 2), "42");
//! let str = YulString::new(SimpleSpan::new(5, 12), "\"hello\"");
//! ```
//!
//! ## Owned Literals
//!
//! ```rust,ignore
//! // Store literals in AST nodes
//! type OwnedDecimal = LitDecimal<String, SimpleSpan, MyLang>;
//!
//! let lit = OwnedDecimal::new(span, source.to_string());
//! ```
//!
//! # Error Recovery
//!
//! All literal types implement [`ErrorNode`] when `S: ErrorNode`:
//!
//! ```rust,ignore
//! use tokit::types::LitDecimal;
//! use tokit::error::ErrorNode;
//!
//! // Create placeholder for malformed literal
//! let bad_lit = LitDecimal::<String, SimpleSpan, YulLang>::error(span);
//!
//! // Create placeholder for missing literal
//! let missing_lit = LitDecimal::<String, SimpleSpan, YulLang>::missing(span);
//! ```

use core::marker::PhantomData;

use crate::{error::ErrorNode, span::AsSpan, utils::IntoComponents};

/// A macro to generate literal type structures.
///
/// This reduces boilerplate by generating identical structure and implementations
/// for all literal types.
macro_rules! define_literal {
  (
    $(#[$meta:meta])*
    $name:ident $(= $default:ty)?,
    $doc:expr,
    $example_str:expr,
    $example_desc:expr
  ) => {
    paste::paste! {
      $(#[$meta])*
      #[doc = $doc]
      ///
      /// # Type Parameters
      ///
      /// - `S`: The source string type (`&str`, `String`, interned string, etc.)
      /// - `Lang`: Language marker type for type safety
      ///
      /// # Examples
      ///
      /// ## Creating Literals
      ///
      /// ```rust
      #[doc = "use tokit::types::" $name ";"]
      /// use tokit::SimpleSpan;
      /// # struct MyLang;
      ///
      #[doc = "let lit = " $name "::<&str, SimpleSpan, MyLang>::new("]
      #[doc = "    SimpleSpan::new(0, 4),"]
      #[doc = "    " $example_str ]
      /// );
      ///
      #[doc = "assert_eq!(lit.data_ref(), &" $example_str ");"]
      /// ```
      ///
      /// ## With Error Recovery
      ///
      /// ```rust,ignore
      #[doc = "use tokit::types::" $name ";"]
      /// use tokit::error::ErrorNode;
      ///
      #[doc = "// " $example_desc]
      #[doc = "let bad_lit = " $name "::<String, SimpleSpan, YulLang>::error(span);"]
      /// ```
      #[derive(Debug, Copy, Clone, PartialEq, Eq, Hash)]
      pub struct $name<D $( = $default)?, S = $crate::__private::span::SimpleSpan, Lang = ()> {
        span: S,
        data: D,
        _lang: PhantomData<Lang>,
      }
    }

    impl<D, S, Lang> AsSpan<S> for $name<D, S, Lang> {
      #[cfg_attr(not(tarpaulin), inline(always))]
      fn as_span(&self) -> &S {
        self.span_ref()
      }
    }

    impl<D, S, Lang> IntoComponents for $name<D, S, Lang> {
      type Components = (S, D);

      #[cfg_attr(not(tarpaulin), inline(always))]
      fn into_components(self) -> Self::Components {
        (self.span, self.data)
      }
    }

    impl<D, S, Lang> $name<D, S, Lang> {
      /// Creates a new literal with the given span and source string.
      ///
      /// # Parameters
      ///
      /// - `span`: The source location of this literal
      /// - `data`: The literal's data
      #[cfg_attr(not(tarpaulin), inline(always))]
      pub const fn new(span: S, data: D) -> Self {
        Self {
          span,
          data,
          _lang: PhantomData,
        }
      }

      /// Returns the span (source location) of this literal.
      #[cfg_attr(not(tarpaulin), inline(always))]
      pub const fn span(&self) -> S where S: ::core::marker::Copy {
        self.span
      }

      /// Returns an immutable reference to the span.
      #[cfg_attr(not(tarpaulin), inline(always))]
      pub const fn span_ref(&self) -> &S {
        &self.span
      }

      /// Returns a mutable reference to the span.
      #[cfg_attr(not(tarpaulin), inline(always))]
      pub const fn span_mut(&mut self) -> &mut S {
        &mut self.span
      }

      /// Bumps the span to of this literal by the specified offset.
      #[cfg_attr(not(tarpaulin), inline(always))]
      pub fn bump(&mut self, by: &S::Offset) -> &mut Self
      where
        S: $crate::__private::span::Span,
      {
        self.span.bump(by);
        self
      }

      /// Returns a mutable reference to the source string.
      #[cfg_attr(not(tarpaulin), inline(always))]
      pub const fn data_mut(&mut self) -> &mut D {
        &mut self.data
      }

      /// Returns an immutable reference to the source string.
      ///
      /// This is the most common way to access the literal's text.
      #[cfg_attr(not(tarpaulin), inline(always))]
      pub const fn data_ref(&self) -> &D {
        &self.data
      }

      /// Returns a copy of the source string by value.
      ///
      /// Only available when `S` implements [`Copy`].
      #[cfg_attr(not(tarpaulin), inline(always))]
      pub const fn data(&self) -> D
      where
        D: Copy,
      {
        self.data
      }
    }

    impl<D, S, Lang> ErrorNode<S> for $name<D, S, Lang>
    where
      D: ErrorNode<S>,
      S: Clone,
    {
      /// Creates a placeholder literal for **malformed content**.
      #[cfg_attr(not(tarpaulin), inline(always))]
      fn error(span: S) -> Self {
        Self::new(span.clone(), D::error(span))
      }

      /// Creates a placeholder literal for **missing required content**.
      #[cfg_attr(not(tarpaulin), inline(always))]
      fn missing(span: S) -> Self {
        Self::new(span.clone(), D::missing(span))
      }
    }
  };
}

// Generic literal
define_literal!(
  /// A generic literal.
  ///
  /// Represents any kind of literal value without distinguishing between specific
  /// types (numeric, string, boolean, etc.). Useful when the exact literal type
  /// doesn't matter for your use case.
  Lit,
  "A generic literal (any literal type).",
  "\"value\"",
  "Malformed literal"
);

// Numeric literals
define_literal!(
  /// A decimal (base-10) integer literal.
  ///
  /// Represents numeric literals in standard decimal notation, such as `42`, `1000`,
  /// or `123_456`. The source string may include underscores for readability but
  /// represents a single integer value.
  LitDecimal,
  "A decimal integer literal (e.g., `42`, `1_000`).",
  "\"42\"",
  "Malformed decimal literal like \"12abc\""
);

define_literal!(
  /// A hexadecimal (base-16) integer literal.
  ///
  /// Represents integer literals in hexadecimal notation, typically prefixed with
  /// `0x` or `0X`, such as `0xFF`, `0x1A2B`, or `0xDEAD_BEEF`.
  LitHex,
  "A hexadecimal integer literal (e.g., `0xFF`, `0x1A2B`).",
  "\"0xFF\"",
  "Malformed hex literal like \"0xGG\""
);

define_literal!(
  /// An octal (base-8) integer literal.
  ///
  /// Represents integer literals in octal notation, typically prefixed with `0o`,
  /// such as `0o77`, `0o644`, or `0o755`.
  LitOctal,
  "An octal integer literal (e.g., `0o77`, `0o644`).",
  "\"0o77\"",
  "Malformed octal literal like \"0o89\""
);

define_literal!(
  /// A binary (base-2) integer literal.
  ///
  /// Represents integer literals in binary notation, typically prefixed with `0b`,
  /// such as `0b1010`, `0b11110000`, or `0b1111_0000`.
  LitBinary,
  "A binary integer literal (e.g., `0b1010`, `0b1111_0000`).",
  "\"0b1010\"",
  "Malformed binary literal like \"0b123\""
