define_literal!(
  /// A floating-point literal.
  ///
  /// Represents floating-point literals in standard decimal notation with optional
  /// fractional and exponent parts, such as `3.14`, `1.0`, `2.5e-3`, or `6.022e23`.
  LitFloat,
  "A floating-point literal (e.g., `3.14`, `1.0e-5`).",
  "\"3.14\"",
  "Malformed float literal like \"3.14.15\""
);

define_literal!(
  /// A hexadecimal floating-point literal.
  ///
  /// Represents floating-point literals in hexadecimal notation with binary exponent,
  /// such as `0x1.8p3` (which equals 12.0 in decimal). Used in languages like C and Rust
  /// for precise floating-point representation.
  LitHexFloat,
  "A hexadecimal floating-point literal (e.g., `0x1.8p3`).",
  "\"0x1.8p3\"",
  "Malformed hex float like \"0x1.Gp3\""
);

// String literals
define_literal!(
  /// A single-line string literal.
  ///
  /// Represents string literals enclosed in quotes, typically on a single line,
  /// such as `"hello"`, `"world\n"`, or `"escaped \"quotes\""`. May contain
  /// escape sequences.
  LitString,
  "A single-line string literal (e.g., `\"hello\"`, `\"world\\n\"`).",
  "\"\\\"hello\\\"\"",
  "Malformed string like unterminated \"hello"
);

define_literal!(
  /// A multi-line string literal.
  ///
  /// Represents string literals that span multiple lines, often with special delimiters
  /// like triple quotes (`"""..."""` or `'''...'''`). Common in languages like Python,
  /// Kotlin, and Swift.
  LitMultilineString,
  "A multi-line string literal (e.g., `\"\"\"...\"\"\"`).",
  "\"\\\"\\\"\\\"multi\\nline\\\"\\\"\\\"\"",
  "Malformed multiline string"
);

define_literal!(
  /// A raw string literal.
  ///
  /// Represents string literals where escape sequences are not processed, often
  /// prefixed with `r` (e.g., Rust's `r"C:\path"`, Python's `r"\n stays literal"`).
  /// Useful for regular expressions and file paths.
  LitRawString,
  "A raw string literal without escape processing (e.g., `r\"C:\\path\"`).",
  "\"r\\\"C:\\\\path\\\"\"",
  "Malformed raw string"
);

// Character and byte literals
define_literal!(
  /// A character literal.
  ///
  /// Represents a single character enclosed in single quotes, such as `'a'`, `'\\n'`,
  /// or `'\\u{1F600}'`. May contain escape sequences for special characters.
  LitChar = char,
  "A character literal (e.g., `'a'`, `'\\n'`, `'\\u{1F600}'`).",
  "\"'a'\"",
  "Malformed char like unclosed 'a"
);

define_literal!(
  /// A byte literal.
  ///
  /// Represents a single byte value enclosed in single quotes with a `b` prefix,
  /// such as `b'a'`, `b'\\x7F'`, or `b'\\n'`. Used in languages like Rust for
  /// ASCII/byte manipulation.
  LitByte = u8,
  "A byte literal (e.g., `b'a'`, `b'\\x7F'`).",
  "\"b'a'\"",
  "Malformed byte literal"
);

define_literal!(
  /// A byte string literal.
  ///
  /// Represents a sequence of bytes enclosed in quotes with a `b` prefix, such as
  /// `b"bytes"`, `b"\\x48\\x65\\x6C\\x6C\\x6F"`. Used for binary data or ASCII strings.
  LitByteString,
  "A byte string literal (e.g., `b\"bytes\"`, `b\"\\x48\\x65\\x6C\\x6C\\x6F\"`).",
  "\"b\\\"bytes\\\"\"",
  "Malformed byte string"
);

// Boolean and null
define_literal!(
  /// A boolean literal.
  ///
  /// Represents boolean values `true` or `false`. The source string contains the
  /// actual keyword as it appears in source code.
  LitBool = bool,
  "A boolean literal (`true` or `false`).",
  "\"true\"",
  "Malformed boolean like \"tru\" or \"fals\""
);

define_literal!(
  /// A `true` literal.
  ///
  /// Represents boolean value `true`. The source string contains the
  /// actual keyword as it appears in source code.
  LitTrue = (),
  "A `true` literal.",
  "\"true\"",
  "Malformed `true` literal like \"tru\""
);

define_literal!(
  /// A `true` literal.
  ///
  /// Represents boolean value `true`. The source string contains the
  /// actual keyword as it appears in source code.
  LitFalse = (),
  "A `false` literal.",
  "\"false\"",
  "Malformed `false` literal like \"fals\""
);

define_literal!(
  /// A null/nil literal.
  ///
  /// Represents the null, nil, or None value in various programming languages.
  /// The source string contains the keyword as it appears (e.g., `null`, `nil`,
  /// `None`, `nullptr`).
  LitNull = (),
  "A null/nil literal (e.g., `null`, `nil`, `None`).",
  "\"null\"",
  "Malformed null literal"
);

//! Common types for building language-specific ASTs.
//!
//! This module provides generic, reusable building blocks for creating Abstract
//! Syntax Trees (ASTs) across different programming languages. These types are
//! designed to be language-agnostic while maintaining type safety through generic
//! parameters.
//!
//! # Available Types
//!
//! ## Identifiers
//!
//! - `Ident`: Generic identifier with span tracking and language marker
//!
//! ## Generic Literal
//!
//! - `Lit`: Generic literal (any literal type)
//!
//! ## Numeric Literals
//!
//! - `LitDecimal`: Decimal integer (e.g., `42`, `1_000`)
//! - `LitHex`: Hexadecimal integer (e.g., `0xFF`, `0x1A2B`)
//! - `LitOctal`: Octal integer (e.g., `0o77`, `0o644`)
//! - `LitBinary`: Binary integer (e.g., `0b1010`)
//! - `LitFloat`: Floating-point (e.g., `3.14`, `1.0e-5`)
//! - `LitHexFloat`: Hexadecimal float (e.g., `0x1.8p3`)
//!
//! ## String Literals
//!
//! - `LitString`: Single-line string (e.g., `"hello"`)
//! - `LitMultilineString`: Multi-line string (e.g., `"""..."""`)
//! - `LitRawString`: Raw string (e.g., `r"C:\path"`)
//!
//! ## Character/Byte Literals
//!
//! - `LitChar`: Character literal (e.g., `'a'`)
//! - `LitByte`: Byte literal (e.g., `b'a'`)
//! - `LitByteString`: Byte string (e.g., `b"bytes"`)
//!
//! ## Boolean and Null
//!
//! - `LitBool`: Boolean literal (`true`/`false`)
//! - `LitNull`: Null/nil literal
//!
//! # Design Principles
//!
//! All types in this module follow these principles:
//!
//! 1. **Generic over string representation**: Support zero-copy (`&str`), owned
//!    (`String`), and interned strings
//! 2. **Span tracking**: Every node carries its source location for diagnostics
//! 3. **Language safety**: Generic `Lang` parameter prevents mixing ASTs from
//!    different languages
//! 4. **Error recovery**: Implement [`ErrorNode`](crate::error::ErrorNode) when
//!    appropriate for creating placeholders during parsing errors
//!
//! # Example: Building a Simple Expression AST
//!
//! ```rust,ignore
//! use tokit::types::Ident;
//! use tokit::utils::SimpleSpan;
//!
//! // Define your language marker
//! struct MyLang;
//!
//! // Define expression type using Ident
//! enum Expr<'a> {
//!     Variable(Ident<&'a str, MyLang>),
//!     Number(i64, SimpleSpan),
//!     Add(Box<Expr<'a>>, Box<Expr<'a>>, SimpleSpan),
//! }
//!
//! // Create an expression
//! let var = Ident::new(SimpleSpan::new(0, 1), "x");
//! let expr = Expr::Variable(var);
//! ```

use derive_more::{IsVariant, TryUnwrap, Unwrap};

use crate::{
  error::ErrorNode,
  span::{AsSpan, SimpleSpan},
  syntax::{Language, Syntax},
};

pub use ident::*;
pub use ident_list::*;
pub use keyword::*;
pub use lit::*;

mod ident;
mod ident_list;
mod keyword;
mod lit;

/// A type representing a recoverable parse node, which can be a valid node,
/// an error node with span, or a missing node with span.
#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash, IsVariant, TryUnwrap, Unwrap)]
#[unwrap(ref, ref_mut)]
#[try_unwrap(ref, ref_mut)]
pub enum Recoverable<T, S = SimpleSpan> {
  /// A valid parse node.
  Node(T),
  /// An error node with associated span.
  Error(S),
  /// A missing node with associated span.
  Missing(S),
}

impl<T, S> AsSpan<S> for Recoverable<T, S>
where
  T: AsSpan<S>,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn as_span(&self) -> &S {
    match self {
      Self::Node(node) => node.as_span(),
      Self::Error(span) | Self::Missing(span) => span,
    }
  }
}

impl<T, S> Syntax for Recoverable<T, S>
where
  T: Syntax,
{
  type Lang = T::Lang;
  const KIND: <Self::Lang as Language>::SyntaxKind = T::KIND;

  type Component = T::Component;

  type COMPONENTS = T::COMPONENTS;

  type REQUIRED = T::REQUIRED;

  fn possible_components()
  -> &'static generic_arraydeque::GenericArrayDeque<Self::Component, Self::COMPONENTS> {
    T::possible_components()
  }

  fn required_components()
  -> &'static generic_arraydeque::GenericArrayDeque<Self::Component, Self::REQUIRED> {
    T::required_components()
  }
}

impl<T> ErrorNode for Recoverable<T> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn error(span: SimpleSpan) -> Self {
    Self::Error(span)
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn missing(span: SimpleSpan) -> Self {
    Self::Missing(span)
  }
}

impl<T> From<T> for Recoverable<T> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn from(node: T) -> Self {
    Self::Node(node)
  }
}

