  #[test]
  fn recoverable_node() {
    let r = Recoverable::<i32>::Node(42);
    assert!(r.is_node());
    assert!(!r.is_error());
    assert!(!r.is_missing());
  }

  #[test]
  fn recoverable_error() {
    let r = Recoverable::<i32>::Error(SimpleSpan::new(0, 5));
    assert!(!r.is_node());
    assert!(r.is_error());
