  }

  #[test]
  fn recoverable_missing() {
    let r = Recoverable::<i32>::Missing(SimpleSpan::new(0, 5));
    assert!(!r.is_node());
    assert!(!r.is_error());
    assert!(r.is_missing());
  }

  #[test]
  fn recoverable_from_value() {
    let r: Recoverable<i32> = 42.into();
    assert!(r.is_node());
    assert_eq!(r.try_unwrap_node(), Ok(42));
  }

