  #[cfg_attr(not(tarpaulin), inline(always))]
  fn into_span(self) -> S {
    self.span
  }
}

impl<Open, Close, Data, S> core::ops::Deref for Delimited<Open, Close, Data, S> {
  type Target = Data;

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn deref(&self) -> &Self::Target {
