  /// let borrowed: Delimited<&char, &char, &String, &SimpleSpan> = delimited.as_ref();
  /// assert_eq!(borrowed.data(), &"hello");
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn as_ref(&self) -> Delimited<&Open, &Close, &Data, &S> {
    Delimited {
      open: &self.open,
