const _: () = {
  impl<'a, T: Clone> OneOf<'a, T> {
    #[cfg_attr(not(tarpaulin), inline(always))]
    const fn borrow_const(value: &'a [T]) -> Inner<'a, T> {
      Cow::Borrowed(value)
    }

    #[cfg_attr(not(tarpaulin), inline(always))]
    const fn as_inner_helper<'b>(inner: &'b Inner<'a, T>) -> &'b [T] {
      match inner {
        Cow::Borrowed(value) => value,
        Cow::Owned(value) => value.as_slice(),
      }
    }

    /// Creates a message by taking ownership of a vector.
    ///
    /// ## Examples
    ///
    /// ```
    /// use tokit::utils::OneOf;
    ///
    /// let values = OneOf::from_vec(vec!["owned", "slice"]);
    /// assert_eq!(values.as_slice(), &["owned", "slice"]);
    /// ```
    #[cfg_attr(not(tarpaulin), inline(always))]
    pub fn from_vec(value: Vec<T>) -> Self {
      Self {
        inner: Cow::Owned(value),
      }
    }

    /// Ensures the message is owned and returns a mutable reference.
    ///
    /// ## Examples
    ///
    /// ```
    /// use tokit::utils::OneOf;
    ///
    /// let mut values = OneOf::from_vec(vec![1, 2, 3]);
    /// values.to_mut()[1] = 42;
    /// assert_eq!(values.as_slice(), &[1, 42, 3]);
    /// ```
    #[cfg_attr(not(tarpaulin), inline(always))]
    pub fn to_mut(&mut self) -> &mut [T] {
      self.inner.to_mut()
    }
  }

  impl<T: Clone> From<Vec<T>> for OneOf<'_, T> {
    #[cfg_attr(not(tarpaulin), inline(always))]
    fn from(value: Vec<T>) -> Self {
      OneOf::from_vec(value)
    }
  }

  impl<'a, T: Clone> From<Cow<'a, [T]>> for OneOf<'a, T> {
    #[cfg_attr(not(tarpaulin), inline(always))]
    fn from(value: Cow<'a, [T]>) -> Self {
      Self { inner: value }
    }
  }

  impl<'a, T: Clone> From<OneOf<'a, T>> for Cow<'a, [T]> {
    #[cfg_attr(not(tarpaulin), inline(always))]
    fn from(value: OneOf<'a, T>) -> Self {
      value.inner
    }
  }

  impl<'a, T: Clone> From<&OneOf<'a, T>> for Cow<'a, [T]> {
    #[cfg_attr(not(tarpaulin), inline(always))]
    fn from(value: &OneOf<'a, T>) -> Self {
      value.inner.clone()
    }
  }
};

use core::ops::Add;

use super::CharLen;

use crate::span::SimpleSpan;

/// A character paired with its byte position in the source input.
///
/// `PositionedChar` combines a character (or character-like value) with the byte offset
/// where it appears in the source. This is particularly useful for:
///
/// - **Error reporting**: Show exactly where an unexpected character occurred
/// - **Lexer state**: Track position while processing character-by-character
/// - **Diagnostics**: Build precise error messages with column/line information
/// - **Character-level parsing**: When token-level parsing is too coarse
///
/// # Type Parameter
///
/// - `Char`: The character type, typically `char` for UTF-8 text or `u8` for bytes
///
/// # Design
///
/// This type is designed to be lightweight and efficient:
/// - **Copy**: Can be freely copied (when `Char` is `Copy`)
/// - **Small**: Just the character plus one `usize` for position
/// - **Comparable**: Supports comparison operations based on both character and position
///
/// # Examples
///
/// ## Basic Usage
///
/// ```rust
/// use tokit::utils::PositionedChar;
///
/// let ch = PositionedChar::with_position('x', 42);
///
/// assert_eq!(ch.char(), 'x');
/// assert_eq!(ch.position(), 42);
/// ```
///
/// ## Character-by-Character Processing
///
/// ```rust,ignore
/// use tokit::utils::PositionedChar;
///
/// fn process_input(input: &str) -> Vec<PositionedChar<char>> {
///     input.char_indices()
///         .map(|(pos, ch)| PositionedChar::with_position(ch, pos))
///         .collect()
/// }
///
/// let positioned = process_input("hello");
/// assert_eq!(positioned[0].char(), 'h');
/// assert_eq!(positioned[0].position(), 0);
/// ```
///
/// ## Error Reporting
///
/// ```rust,ignore
/// use tokit::utils::PositionedChar;
///
/// fn report_unexpected(pc: PositionedChar<char>, input: &str) {
///     let line_start = input[..pc.position()]
///         .rfind('\n')
///         .map(|p| p + 1)
///         .unwrap_or(0);
///
///     let column = pc.position() - line_start;
///
///     eprintln!("Unexpected character '{}' at position {} (column {})",
///         pc.char(), pc.position(), column);
/// }
/// ```
///
/// ## Mapping Characters
///
/// ```rust
/// use tokit::utils::PositionedChar;
///
/// let lowercase = PositionedChar::with_position('a', 10);
/// let uppercase = lowercase.map(|c| c.to_ascii_uppercase());
///
/// assert_eq!(uppercase.char(), 'A');
/// assert_eq!(uppercase.position(), 10); // Position preserved
/// ```
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct PositionedChar<Char, Offset = usize> {
  char: Char,
  pub(crate) position: Offset,
}

impl<Char, Offset> PositionedChar<Char, Offset> {
  /// Create a new positioned character with the given position.
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn with_position(char: Char, position: Offset) -> Self {
    Self { char, position }
  }

  /// Get the character.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::PositionedChar;
  ///
  /// let pc = PositionedChar::with_position('x', 10);
  /// assert_eq!(pc.char(), 'x');
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn char(&self) -> Char
  where
    Char: Copy,
  {
    self.char
  }

  /// Get the reference to the character.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::PositionedChar;
  ///
  /// let pc = PositionedChar::with_position('x', 10);
  /// assert_eq!(pc.char_ref(), &'x');
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn char_ref(&self) -> &Char {
    &self.char
  }

  /// Get a mutable reference to the character.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::PositionedChar;
  ///
  /// let mut pc = PositionedChar::with_position('a', 10);
  /// *pc.char_mut() = 'b';
  /// assert_eq!(pc.char(), 'b');
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn char_mut(&mut self) -> &mut Char {
    &mut self.char
  }

  /// Get the reference of the position.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::PositionedChar;
  ///
  /// let pc = PositionedChar::with_position('x', 42);
  /// assert_eq!(pc.position(), 42);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn position_ref(&self) -> &Offset {
    &self.position
  }

  /// Get the position.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::PositionedChar;
  ///
  /// let pc = PositionedChar::with_position('x', 42);
  /// assert_eq!(pc.position(), 42);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn position(&self) -> Offset
  where
    Offset: Copy,
  {
    self.position
  }

  /// Returns the span covers this positioned character.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::{Span, utils::PositionedChar};
  ///
  ///
  /// let pc = PositionedChar::with_position('x', 42);
  /// assert_eq!(pc.span(), Span::new(42, 43));
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn span(&self) -> SimpleSpan<Offset>
  where
    Char: CharLen,
    Offset: Clone + Ord,
    for<'a> &'a Offset: Add<usize, Output = Offset>,
  {
    let start = self.position_ref();
    let end = start + self.char_ref().char_len();
    SimpleSpan::new(start.clone(), end)
  }

  /// Set the position, returning a mutable reference of the positioned character.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::PositionedChar;
  ///
  /// let mut pc = PositionedChar::with_position('x', 10);
  /// pc.set_position(20);
  /// assert_eq!(pc.position(), 20);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn set_position(&mut self, position: Offset) -> &mut Self {
    self.position = position;
    self
  }

  /// Bump the position by `n`,  returning a mutable reference of the positioned character.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::PositionedChar;
  ///
  /// let mut pc = PositionedChar::with_position('x', 10);
  /// pc.bump_position(&5);
  /// assert_eq!(pc.position(), 15);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn bump_position<'a>(&'a mut self, n: &'a Offset) -> &'a mut Self
  where
    Offset: core::ops::AddAssign<&'a Offset>,
  {
    self.position += n;
    self
  }

  /// Converts the positioned character to a reference.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::PositionedChar;
  ///
  /// let pc = PositionedChar::with_position('x', 10);
  /// let pc_ref = pc.as_ref();
  /// assert_eq!(**pc_ref.char_ref(), 'x');
  /// assert_eq!(pc_ref.position(), &10);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn as_ref(&self) -> PositionedChar<&Char, &Offset> {
    PositionedChar {
      char: &self.char,
      position: &self.position,
    }
  }

  /// Converts the positioned character to a mutable reference.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::PositionedChar;
  ///
  /// let mut pc = PositionedChar::with_position('a', 10);
  /// {
  ///     let mut pc_mut = pc.as_mut();
  ///     **pc_mut.char_mut() = 'b';
  /// }
  /// assert_eq!(pc.char(), 'b');
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub const fn as_mut(&mut self) -> PositionedChar<&mut Char, &mut Offset> {
    PositionedChar {
      char: &mut self.char,
      position: &mut self.position,
    }
  }

  /// Maps the character to another character, returning a new positioned character.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::PositionedChar;
  ///
  /// let pc = PositionedChar::with_position('a', 10);
  /// let upper = pc.map(|c| c.to_ascii_uppercase());
  /// assert_eq!(upper.char(), 'A');
  /// assert_eq!(upper.position(), 10);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn map<NewChar, F>(self, f: F) -> PositionedChar<NewChar, Offset>
  where
    F: FnOnce(Char) -> NewChar,
  {
    PositionedChar {
      char: f(self.char),
      position: self.position,
    }
  }

  /// Consumes the positioned character, returning the character and its position.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::PositionedChar;
  ///
  /// let pc = PositionedChar::with_position('x', 42);
  /// let (ch, pos) = pc.into_components();
  /// assert_eq!(ch, 'x');
  /// assert_eq!(pos, 42);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  pub fn into_components(self) -> (Char, Offset) {
    (self.char, self.position)
  }
}

impl<Char: core::fmt::Display, Offset> core::fmt::Display for PositionedChar<Char, Offset> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
    write!(f, "{}", self.char)
  }
}

mod sealed {
  pub trait Sealed {}

  impl<T: ?Sized + Sealed> Sealed for &T {}
}

/// A trait for displaying values with configurable formatting options.
///
/// `DisplaySDL` (Structured Display Language) provides a flexible way to format values
/// with user-supplied options that control the output format. This is the base trait
/// that both [`DisplayCompact`] and [`DisplayPretty`] build upon.
///
/// # Design Philosophy
///
/// Unlike `Display` which has no configuration, `DisplaySDL` accepts an `Options` type
/// parameter that controls formatting behavior. This allows the same type to be formatted
/// in multiple ways (compact, pretty, custom) without needing multiple `Display` implementations.
///
/// # Implementation Note
///
/// **This trait is sealed and cannot be implemented directly.** Instead:
/// 1. Implement [`DisplayCompact`] and/or [`DisplayPretty`]
/// 2. Use [`CompactDisplay`] or [`PrettyDisplay`] wrappers
/// 3. Those wrappers automatically implement `DisplaySDL`
///
/// This design prevents direct implementation while providing the flexibility to
/// define custom formatting behaviors.
///
/// # Examples
///
/// ## Using DisplaySDL via CompactDisplay
///
/// ```rust
/// use tokit::utils::sdl_display::{DisplayCompact, DisplaySDL};
///
/// struct AST {
///     nodes: Vec<String>,
/// }
///
/// impl DisplayCompact for AST {
///     type Options = ();
///
///     fn fmt(&self, f: &mut core::fmt::Formatter<'_>, _options: &()) -> core::fmt::Result {
///         write!(f, "AST({})", self.nodes.join(","))
///     }
/// }
///
/// let ast = AST { nodes: vec!["a".into(), "b".into()] };
/// let compact = ast.display(&());
/// println!("{}", compact); // Uses DisplaySDL through CompactDisplay
/// ```
pub trait DisplaySDL: sealed::Sealed {
  /// The options type that controls formatting behavior.
  ///
  /// This can be any type that carries configuration for formatting.
  /// Common choices include:
  /// - `()`: No options needed
  /// - `usize`: For indentation level
  /// - Custom struct: For complex formatting options
  type Options: ?Sized;

  /// Formats the value with the given options.
  ///
  /// This is the core formatting method that receives both a formatter
  /// and user-supplied options.
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>, options: &Self::Options) -> core::fmt::Result;

  /// Returns a wrapper that implements `Display` with the given options.
  ///
  /// This allows you to use the formatted value with standard formatting macros.
  fn display<'a>(&'a self, options: &'a Self::Options) -> impl core::fmt::Display + 'a;
}

impl<T: DisplaySDL + ?Sized> DisplaySDL for &T {
  type Options = T::Options;

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>, options: &Self::Options) -> core::fmt::Result {
    <T as DisplaySDL>::fmt(*self, f, options)
  }

  fn display<'a>(&'a self, options: &'a Self::Options) -> impl core::fmt::Display + 'a {
    <T as DisplaySDL>::display(*self, options)
  }
}

/// A trait for formatting values in a compact, space-efficient representation.
///
/// `DisplayCompact` is used when you want to minimize whitespace and produce
/// the most concise possible output. This is ideal for logging, inline display,
/// or when space is at a premium.
///
/// # Use Cases
///
/// - **Logging**: Compact output for log files where space matters
/// - **Inline display**: Single-line representations for debugging
/// - **Network protocols**: Minimized data transfer
/// - **Terminal output**: Fitting more information on screen
///
/// # Options Type
///
/// The associated `Options` type can be used to pass configuration to the
/// formatter. Common patterns include:
/// - `()`: No configuration needed
/// - `usize`: For recursion depth or other simple parameters
/// - Custom struct: For complex formatting options
///
/// # Examples
///
/// ## Simple Compact Display
///
/// ```rust
/// use tokit::utils::sdl_display::DisplayCompact;
///
/// struct Point { x: i32, y: i32 }
///
/// impl DisplayCompact for Point {
///     type Options = ();
///
///     fn fmt(&self, f: &mut core::fmt::Formatter<'_>, _: &()) -> core::fmt::Result {
///         write!(f, "({},{})", self.x, self.y)
///     }
/// }
///
/// let p = Point { x: 10, y: 20 };
/// println!("{}", p.display(&())); // (10,20)
/// ```
///
/// ## With Options
///
/// ```rust
/// use tokit::utils::sdl_display::DisplayCompact;
///
/// struct Tree {
///     value: i32,
///     children: Vec<Tree>,
/// }
///
/// impl DisplayCompact for Tree {
///     type Options = usize; // max depth
///
///     fn fmt(&self, f: &mut core::fmt::Formatter<'_>, depth: &usize) -> core::fmt::Result {
///         if *depth == 0 {
///             return write!(f, "...");
///         }
///         write!(f, "{}", self.value)?;
///         if !self.children.is_empty() {
///             write!(f, "(")?;
///             for (i, child) in self.children.iter().enumerate() {
///                 if i > 0 { write!(f, ",")?; }
///                 child.fmt(f, &(depth - 1))?;
///             }
///             write!(f, ")")?;
///         }
///         Ok(())
///     }
/// }
/// ```
pub trait DisplayCompact {
  /// The options type for controlling compact formatting.
  type Options: ?Sized;

  /// Formats the value in a compact, space-efficient way.
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>, options: &Self::Options) -> core::fmt::Result;

  /// Returns a wrapper that implements `Display` for compact formatting.
  ///
  /// # Example
  ///
  /// ```rust,ignore
  /// let compact = value.display(&options);
  /// println!("{}", compact);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn display<'a>(&'a self, options: &'a Self::Options) -> CompactDisplay<'a, Self> {
    CompactDisplay { t: self, options }
  }
}

impl<T: DisplayCompact + ?Sized> DisplayCompact for &T {
  type Options = T::Options;

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>, options: &Self::Options) -> core::fmt::Result {
    (*self).fmt(f, options)
  }
}

/// A trait for formatting values in a human-friendly, readable representation.
///
/// `DisplayPretty` is used when you want to maximize readability with indentation,
/// whitespace, and multi-line output. This is ideal for debugging, documentation,
/// or when human comprehension is more important than space efficiency.
///
/// # Use Cases
///
/// - **Debugging**: Easily readable output for complex data structures
/// - **Pretty-printing ASTs**: Multi-line formatted abstract syntax trees
/// - **Configuration files**: Human-editable output formats
/// - **Error messages**: Clear, well-formatted diagnostic information
///
/// # Options Type
///
/// The associated `Options` type typically carries indentation information.
/// Common patterns include:
/// - `usize`: Current indentation level
/// - Custom struct: With indent size, style preferences, etc.
///
/// # Examples
///
/// ## Simple Pretty Display
///
/// ```rust
/// use tokit::utils::sdl_display::DisplayPretty;
///
/// struct Point { x: i32, y: i32 }
///
/// impl DisplayPretty for Point {
///     type Options = ();
///
///     fn fmt(&self, f: &mut core::fmt::Formatter<'_>, _: &()) -> core::fmt::Result {
///         writeln!(f, "Point {{")?;
///         writeln!(f, "  x: {},", self.x)?;
///         writeln!(f, "  y: {}", self.y)?;
///         write!(f, "}}")
///     }
/// }
///
/// let p = Point { x: 10, y: 20 };
/// println!("{}", p.display(&()));
/// // Output:
/// // Point {
/// //   x: 10,
/// //   y: 20
/// // }
/// ```
///
/// ## With Indentation
///
/// ```rust
/// use tokit::utils::sdl_display::DisplayPretty;
///
/// struct Tree {
///     value: i32,
///     children: Vec<Tree>,
/// }
///
/// impl DisplayPretty for Tree {
///     type Options = usize; // indentation level
///
///     fn fmt(&self, f: &mut core::fmt::Formatter<'_>, indent: &usize) -> core::fmt::Result {
///         let spaces = "  ".repeat(*indent);
///         writeln!(f, "{}Tree {{", spaces)?;
///         writeln!(f, "{}  value: {}", spaces, self.value)?;
///         if !self.children.is_empty() {
///             writeln!(f, "{}  children: [", spaces)?;
///             for child in &self.children {
///                 child.fmt(f, &(indent + 2))?;
///             }
///             writeln!(f, "{}  ]", spaces)?;
///         }
///         write!(f, "{}}}", spaces)
///     }
/// }
///
/// let tree = Tree {
///     value: 1,
///     children: vec![
///         Tree { value: 2, children: vec![] },
///         Tree { value: 3, children: vec![] },
///     ],
/// };
/// println!("{}", tree.display(&0));
/// ```
pub trait DisplayPretty {
  /// The options type for controlling pretty formatting.
  type Options: ?Sized;

  /// Formats the value in a human-friendly, readable way.
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>, options: &Self::Options) -> core::fmt::Result;

  /// Returns a wrapper that implements `Display` for pretty formatting.
  ///
  /// # Example
  ///
  /// ```rust,ignore
  /// let pretty = value.display(&0); // 0 indentation
  /// println!("{}", pretty);
  /// ```
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn display<'a>(&'a self, options: &'a Self::Options) -> PrettyDisplay<'a, Self> {
    PrettyDisplay { t: self, options }
  }
}

impl<T: DisplayPretty + ?Sized> DisplayPretty for &T {
  type Options = T::Options;

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>, options: &Self::Options) -> core::fmt::Result {
    (*self).fmt(f, options)
  }
}

/// A wrapper that implements `Display` for compact formatting.
///
/// This type is returned by [`DisplayCompact::display`] and bridges the gap
/// between the `DisplayCompact` trait (which requires options) and Rust's
/// standard `Display` trait (which does not).
///
/// # Examples
///
/// ```rust
/// use tokit::utils::sdl_display::DisplayCompact;
///
/// struct Data { value: i32 }
///
/// impl DisplayCompact for Data {
///     type Options = ();
///     fn fmt(&self, f: &mut core::fmt::Formatter<'_>, _: &()) -> core::fmt::Result {
///         write!(f, "Data({})", self.value)
///     }
/// }
///
/// let data = Data { value: 42 };
/// let display_wrapper = data.display(&());
///
/// // Now you can use it with format! and println!
/// assert_eq!(format!("{}", display_wrapper), "Data(42)");
/// ```
pub struct CompactDisplay<'a, T: ?Sized + DisplayCompact> {
  t: &'a T,
  options: &'a T::Options,
}

impl<T> core::fmt::Display for CompactDisplay<'_, T>
where
  T: DisplayCompact + ?Sized,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
    self.t.fmt(f, self.options)
  }
}

impl<T> sealed::Sealed for CompactDisplay<'_, T> where T: DisplayCompact + ?Sized {}

impl<T> DisplaySDL for CompactDisplay<'_, T>
where
  T: DisplayCompact + ?Sized,
{
  type Options = T::Options;

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>, options: &Self::Options) -> core::fmt::Result {
    self.t.fmt(f, options)
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn display<'a>(&'a self, options: &'a Self::Options) -> impl core::fmt::Display + 'a {
    self.t.display(options)
  }
}

/// A wrapper that implements `Display` for pretty formatting.
///
/// This type is returned by [`DisplayPretty::display`] and bridges the gap
/// between the `DisplayPretty` trait (which requires options) and Rust's
/// standard `Display` trait (which does not).
///
/// # Examples
///
/// ```rust
/// use tokit::utils::sdl_display::DisplayPretty;
///
/// struct Data { value: i32 }
///
/// impl DisplayPretty for Data {
///     type Options = usize; // indentation level
///     fn fmt(&self, f: &mut core::fmt::Formatter<'_>, indent: &usize) -> core::fmt::Result {
///         let spaces = "  ".repeat(*indent);
///         writeln!(f, "{}Data {{", spaces)?;
///         writeln!(f, "{}  value: {}", spaces, self.value)?;
///         write!(f, "{}}}", spaces)
///     }
/// }
///
/// let data = Data { value: 42 };
/// let display_wrapper = data.display(&0);
///
/// // Now you can use it with format! and println!
/// println!("{}", display_wrapper);
/// // Output:
/// // Data {
/// //   value: 42
/// // }
/// ```
pub struct PrettyDisplay<'a, T: ?Sized + DisplayPretty> {
  t: &'a T,
  options: &'a T::Options,
}

impl<T> core::fmt::Display for PrettyDisplay<'_, T>
where
  T: DisplayPretty + ?Sized,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
    self.t.fmt(f, self.options)
  }
}

impl<T> sealed::Sealed for PrettyDisplay<'_, T> where T: DisplayPretty + ?Sized {}

impl<T> DisplaySDL for PrettyDisplay<'_, T>
where
  T: DisplayPretty + ?Sized,
{
  type Options = T::Options;

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>, options: &Self::Options) -> core::fmt::Result {
    self.t.fmt(f, options)
  }

  #[cfg_attr(not(tarpaulin), inline(always))]
  fn display<'a>(&'a self, options: &'a Self::Options) -> impl core::fmt::Display + 'a {
    self.t.display(options)
  }
}

#[cfg(test)]
#[allow(warnings)]
#[cfg(any(feature = "std", feature = "alloc"))]
mod tests {
  use super::*;
  use std::format;

  struct TestCompact {
    value: i32,
  }

  impl DisplayCompact for TestCompact {
    type Options = ();

    fn fmt(&self, f: &mut core::fmt::Formatter<'_>, _: &()) -> core::fmt::Result {
      write!(f, "compact({})", self.value)
    }
  }

  struct TestPretty {
    value: i32,
  }

  impl DisplayPretty for TestPretty {
    type Options = usize;

    fn fmt(&self, f: &mut core::fmt::Formatter<'_>, indent: &usize) -> core::fmt::Result {
      write!(f, "{}pretty({})", " ".repeat(*indent), self.value)
    }
  }

  // --- DisplayCompact tests ---

  #[test]
  fn compact_display_fmt() {
    let t = TestCompact { value: 42 };
    let d = t.display(&());
    assert_eq!(format!("{}", d), "compact(42)");
  }

  #[test]
  fn compact_display_ref() {
    let t = TestCompact { value: 7 };
    let r = &t;
    let d = DisplayCompact::display(r, &());
    assert_eq!(format!("{}", d), "compact(7)");
  }

  #[test]
  fn compact_display_sdl_fmt() {
    let t = TestCompact { value: 10 };
    let compact = t.display(&());
    let sdl_display = DisplaySDL::display(&compact, &());
    assert_eq!(format!("{}", sdl_display), "compact(10)");
  }

  #[test]
  fn compact_display_sdl_direct_fmt() {
    let t = TestCompact { value: 5 };
    let compact = t.display(&());
    let mut buf = std::string::String::new();
    use core::fmt::Write;
    write!(buf, "{}", compact).unwrap();
    assert_eq!(buf, "compact(5)");
  }

  // --- DisplayPretty tests ---

  #[test]
  fn pretty_display_fmt() {
    let t = TestPretty { value: 42 };
    let d = t.display(&2);
    assert_eq!(format!("{}", d), "  pretty(42)");
  }

  #[test]
  fn pretty_display_ref() {
    let t = TestPretty { value: 7 };
    let r = &t;
    let d = DisplayPretty::display(r, &0);
    assert_eq!(format!("{}", d), "pretty(7)");
  }

  #[test]
  fn pretty_display_sdl_fmt() {
    let t = TestPretty { value: 10 };
    let pretty = t.display(&1);
    let sdl_display = DisplaySDL::display(&pretty, &0);
    assert_eq!(format!("{}", sdl_display), "pretty(10)");
  }

  // --- DisplaySDL for &T ---

  #[test]
  fn display_sdl_ref_delegation() {
    let t = TestCompact { value: 99 };
    let compact = t.display(&());
    let r = &compact;
    let d = DisplaySDL::display(r, &());
    assert_eq!(format!("{}", d), "compact(99)");
  }
}

/// A trait for displaying in a SyntaxTree style.
pub trait DisplaySyntaxTree {
  /// Formats the value in a SyntaxTree style.
  ///
  /// - `level` is the current indentation level.
  /// - `indent` is the number of spaces to indent per level.
  fn fmt(&self, level: usize, indent: usize, f: &mut core::fmt::Formatter<'_>)
  -> core::fmt::Result;

  /// Returns a wrapper which implement `Display`.
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn display(&self, level: usize, indent: usize) -> SyntaxTreeDisplay<'_, Self> {
    SyntaxTreeDisplay {
      t: self,
      indent,
      level,
    }
  }
}

impl<T: DisplaySyntaxTree + ?Sized> DisplaySyntaxTree for &T {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(
    &self,
    level: usize,
    indent: usize,
    f: &mut core::fmt::Formatter<'_>,
  ) -> core::fmt::Result {
    (*self).fmt(level, indent, f)
  }
}

/// A helper struct for displaying in a SyntaxTree.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct SyntaxTreeDisplay<'a, T: ?Sized> {
  t: &'a T,
  indent: usize,
  level: usize,
}

impl<T: DisplaySyntaxTree + ?Sized> core::fmt::Display for SyntaxTreeDisplay<'_, T> {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
    self.t.fmt(self.level, self.indent, f)
  }
}

#[cfg(test)]
#[allow(warnings)]
#[cfg(any(feature = "std", feature = "alloc"))]
mod tests {
  use super::*;
  use std::format;

  struct TestNode(&'static str);

  impl DisplaySyntaxTree for TestNode {
    fn fmt(
      &self,
      level: usize,
      indent: usize,
      f: &mut core::fmt::Formatter<'_>,
    ) -> core::fmt::Result {
      for _ in 0..level * indent {
        write!(f, " ")?;
      }
      write!(f, "{}", self.0)
    }
  }

  #[test]
  fn display_syntax_tree_basic() {
    let node = TestNode("hello");
    let d = node.display(0, 2);
    assert_eq!(format!("{}", d), "hello");
  }

  #[test]
  fn display_syntax_tree_indented() {
    let node = TestNode("child");
    let d = node.display(2, 4);
    assert_eq!(format!("{}", d), "        child");
  }

  #[test]
  fn display_syntax_tree_ref() {
    let node = TestNode("ref");
    let r: &TestNode = &node;
    let d = r.display(1, 2);
    assert_eq!(format!("{}", d), "  ref");
  }
}

#![allow(single_use_lifetimes)]

mod sealed {
  pub trait Sealed<T: ?Sized> {}

  impl<T, O> Sealed<O> for &T where T: Sealed<O> + ?Sized {}
}

/// A trait for converting to an equivalent type.
///
/// e.g. `&[u8]` is equivalent to [`bytes::Bytes`](https://docs.rs/bytes/latest/bytes/struct.Bytes.html)
pub trait ToEquivalent<T>: sealed::Sealed<T> {
  /// Converts this element to an equivalent type `T`.
  fn to_equivalent(&self) -> T;
}

impl<T, O> ToEquivalent<O> for &T
where
  T: ToEquivalent<O> + ?Sized,
{
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn to_equivalent(&self) -> O {
    T::to_equivalent(self)
  }
}

impl sealed::Sealed<str> for str {}
impl<'de: 'a, 'a> sealed::Sealed<&'a str> for &'de str {}

impl sealed::Sealed<[u8]> for [u8] {}
impl<'de: 'a, 'a> sealed::Sealed<&'a [u8]> for &'de [u8] {}

impl<'de: 'a, 'a> ToEquivalent<&'a str> for &'de str {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn to_equivalent(&self) -> &'a str {
    self
  }
}

impl<'de: 'a, 'a> ToEquivalent<&'a [u8]> for &'de [u8] {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn to_equivalent(&self) -> &'a [u8] {
    self
  }
}

/// A trait for converting into an equivalent type.
///
/// e.g. `&[u8]` is equivalent to [`bytes::Bytes`](https://docs.rs/bytes/latest/bytes/struct.Bytes.html)
///
/// ## Example
///
/// ```rust
/// use tokit::utils::IntoEquivalent;
///
/// let bytes: &[u8] = b"hello";
/// let str_ref: &str = "world";
///
/// // Identity conversions (consuming)
/// let _: &[u8] = bytes.into_equivalent();
/// let _: &str = str_ref.into_equivalent();
/// ```
pub trait IntoEquivalent<T>: sealed::Sealed<T> {
  /// Consumes this element and converts it into an equivalent type `T`.
  ///
  /// ## Example
  ///
  /// ```rust
  /// use tokit::utils::IntoEquivalent;
  ///
  /// let data: &[u8] = b"test";
  /// let result: &[u8] = data.into_equivalent();
  /// assert_eq!(result, b"test");
  /// ```
  fn into_equivalent(self) -> T;
}

impl<'de: 'a, 'a> IntoEquivalent<&'a str> for &'de str {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn into_equivalent(self) -> &'a str {
    self
  }
}

impl<'de: 'a, 'a> IntoEquivalent<&'a [u8]> for &'de [u8] {
  #[cfg_attr(not(tarpaulin), inline(always))]
  fn into_equivalent(self) -> &'a [u8] {
    self
  }
}

#[cfg(test)]
#[allow(warnings)]
mod tests {
  use super::*;

  #[test]
  fn to_equivalent_str_ref() {
    let s: &str = "hello";
    let result: &str = ToEquivalent::<&str>::to_equivalent(&s);
    assert_eq!(result, "hello");
  }

  #[test]
  fn to_equivalent_bytes_ref() {
    let b: &[u8] = b"hello";
    let result: &[u8] = ToEquivalent::<&[u8]>::to_equivalent(&b);
    assert_eq!(result, b"hello");
  }

  #[test]
  fn to_equivalent_via_double_ref() {
    let s: &str = "world";
    let r: &&str = &s;
    let result: &str = ToEquivalent::<&str>::to_equivalent(r);
    assert_eq!(result, "world");
  }

  #[test]
  fn into_equivalent_str() {
    let s: &str = "test";
    let result: &str = IntoEquivalent::<&str>::into_equivalent(s);
    assert_eq!(result, "test");
  }

  #[test]
  fn into_equivalent_bytes() {
    let b: &[u8] = b"test";
    let result: &[u8] = IntoEquivalent::<&[u8]>::into_equivalent(b);
    assert_eq!(result, b"test");
  }
}

